-- Poems batch 130
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6a15170a-79a7-47c5-9171-5d72ea51594e','二月十四日梅花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','樹勁春猶瘦，花寒暮更明。',24,'全唐诗/poet.song.139000.json','["樹勁春猶瘦，花寒暮更明。", "平生豈無句，此外不須清。"]'),
('f7932cf8-8933-42dd-bb30-942376214102','晚飲','楊萬里','宋','宋诗','song-poetry','','[]','旋旋哦詩旋旋抄，一尊野蔌更山肴。',32,'全唐诗/poet.song.139000.json','["旋旋哦詩旋旋抄，一尊野蔌更山肴。", "春風略不扶人醉，月到梅花最末梢。"]'),
('619cff5c-0197-4161-8e20-df81081616b7','二月望日勸農既歸散策郡圃二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','荆溪老守勸農歸，吏散還從郡圃嬉。',32,'全唐诗/poet.song.139000.json','["荆溪老守勸農歸，吏散還從郡圃嬉。", "拾得落英纔一掬，春風苦向掌中吹。"]'),
('9cd6a186-53db-4e79-aa7c-abb43ca32e4b','二月望日勸農既歸散策郡圃二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今年花事許遲遲，九十春光已半歸。',32,'全唐诗/poet.song.139000.json','["今年花事許遲遲，九十春光已半歸。", "風急杏花吹不脫，落梅無數掠人飛。"]'),
('81be556c-4678-4be9-b156-5d7fc2b53ab3','水仙花四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','江妃虛却蕊珠宮，銀漢仙人謫此中。',32,'全唐诗/poet.song.139000.json','["江妃虛却蕊珠宮，銀漢仙人謫此中。", "偶趁月明波上戲，一身冰雪舞春風。"]'),
('470e9448-42fa-45c2-8779-a92d66b2deec','水仙花四首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','額間拂殺御袍黄，衣上偷將月姊香。',32,'全唐诗/poet.song.139000.json','["額間拂殺御袍黄，衣上偷將月姊香。", "待倩春風作媒却，西湖嫁與水仙王。"]'),
('defccafb-f926-44cc-81ad-2f2244861064','水仙花四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','韻絕香仍絕，花清月未清。',24,'全唐诗/poet.song.139000.json','["韻絕香仍絕，花清月未清。", "天仙不行地，且借水爲名。"]'),
('81971035-4852-4ade-8405-9ed7854b6374','水仙花四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','開處誰爲伴，蕭然不可親。',24,'全唐诗/poet.song.139000.json','["開處誰爲伴，蕭然不可親。", "雪宮孤弄影，水殿四無人。"]'),
('0b3e0d73-51c0-4b8b-b83a-b03588880f6e','夜坐','楊萬里','宋','宋诗','song-poetry','','[]','背壁青燈勸讀書，窺窗素月喚看渠。',64,'全唐诗/poet.song.139000.json','["背壁青燈勸讀書，窺窗素月喚看渠。", "向來諸老端何似，未必千年便不如。", "春後春前雙雪鬢，江南江北一茅廬。", "只愁夜飲無供給，小雨新肥半圃蔬。"]'),
('b59f1845-66dd-44a3-b95d-03f262a6ad8d','新柳','楊萬里','宋','宋诗','song-poetry','','["\u67f3\u6811"]','柳條百尺拂銀塘，且莫深青只淺黄。',32,'全唐诗/poet.song.139000.json','["柳條百尺拂銀塘，且莫深青只淺黄。", "未必柳條能蘸水，水中柳影引它長。"]'),
('34087973-8d97-45b5-b59d-3dcdeff7f52d','禱雨報恩因到翟園四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','霧氣初迎日脚開，春光偏傍柳邊回。',32,'全唐诗/poet.song.139000.json','["霧氣初迎日脚開，春光偏傍柳邊回。", "寒暄消息何人會，十指今朝出袖來。"]'),
('a10b3a9f-188d-4aab-bdc2-4ab50faf43a8','禱雨報恩因到翟園四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','草路無泥未有塵，城南城北總遊人。',32,'全唐诗/poet.song.139000.json','["草路無泥未有塵，城南城北總遊人。", "不緣香火來山墅，孤負今年半段春。"]'),
('4f0b1d9b-48d8-4dd8-8e29-ba01cfc8c026','禱雨報恩因到翟園四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','遶亭怪石小山幽，夾徑低枝壓客頭。',32,'全唐诗/poet.song.139000.json','["遶亭怪石小山幽，夾徑低枝壓客頭。", "幸自一來惟不早，梅花滿地訴春愁。"]'),
('a848d21d-6c11-4d59-afbb-2b6f57094cf8','禱雨報恩因到翟園四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','未必錢園似翟園，翟園窠木最宜看。',32,'全唐诗/poet.song.139000.json','["未必錢園似翟園，翟園窠木最宜看。", "茂松亭下偏明眼，矮檜平鋪翡翠盤。"]'),
('cca1ed0b-75c5-4d16-a8c1-0a7fa9a8afac','垂絲海棠二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','無波可照底須窺，與柳爭嬌也學垂。',32,'全唐诗/poet.song.139000.json','["無波可照底須窺，與柳爭嬌也學垂。", "破曉驟晴天有意，生紅新曬一絇絲。"]'),
('0d1ed67b-aa0d-4b51-83d9-39f1af437d22','垂絲海棠二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不關殘醉未醒鬆，不爲春愁懶散中。',32,'全唐诗/poet.song.139000.json','["不關殘醉未醒鬆，不爲春愁懶散中。", "自是新晴生睡思，起來無力對東風。"]'),
('5f3a1a8c-5936-401b-8567-26436b38938c','送羅永年西歸','楊萬里','宋','宋诗','song-poetry','','[]','梅莟香邊踏雪來，杏花雨裏带春回。',64,'全唐诗/poet.song.139000.json','["梅莟香邊踏雪來，杏花雨裏带春回。", "明朝解纜還千里，今日看花更一杯。", "誰遣文章太驚俗，何緣場屋不遺才。", "南溪鷗鷺如相問，爲報春吟費麝煤。"]'),
('c2821f69-8815-43c8-927e-235a3fbcf542','社雨','楊萬里','宋','宋诗','song-poetry','','[]','時節從來好雨知，今朝社日頓霏微。',32,'全唐诗/poet.song.139000.json','["時節從來好雨知，今朝社日頓霏微。", "落花只得春風舞，濕却殘香不得飛。"]'),
('12ace59a-d006-43db-bd76-87235cb7b8f4','讀唐人及半山詩','楊萬里','宋','宋诗','song-poetry','','[]','不分唐人與半山，無端橫欲割詩壇。',32,'全唐诗/poet.song.139000.json','["不分唐人與半山，無端橫欲割詩壇。", "半山便遣能參透，猶有唐人是一關。"]'),
('65d3a11d-362b-422f-86f9-1066d8b7f0a3','落梅再著晚花','楊萬里','宋','宋诗','song-poetry','','[]','數日春風不奈暄，梅花落盡浄無痕。',32,'全唐诗/poet.song.139000.json','["數日春風不奈暄，梅花落盡浄無痕。", "却將晚莟重收拾，更放南枝第二番。"]'),
('6cced826-0353-480c-abbe-63cb495919b7','鑷白','楊萬里','宋','宋诗','song-poetry','','[]','五十如何是後生，呼兒拔白未忘情。',32,'全唐诗/poet.song.139000.json','["五十如何是後生，呼兒拔白未忘情。", "新年只道無功業，也有霜髭六十莖。"]'),
('269f7e78-fd76-4127-b4bd-58844231729a','春興','楊萬里','宋','宋诗','song-poetry','','[]','著盡工夫是化工，不關春雨更春風。',32,'全唐诗/poet.song.139000.json','["著盡工夫是化工，不關春雨更春風。", "已拚膩粉塗雙蝶，更費雌黄滴一蜂。"]'),
('172f8e1d-b841-404f-9cab-c14e50563b8a','夜窗二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','口角哦詩細有聲，不妨半醉不妨行。',32,'全唐诗/poet.song.139000.json','["口角哦詩細有聲，不妨半醉不妨行。", "青燈一點纔如黍，解作書窗徹夜明。"]'),
('5e288b6e-c30a-47d5-af7c-6025061cd2c7','夜窗二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','詩人心緒幾時休，逢著三春似九秋。',32,'全唐诗/poet.song.139000.json','["詩人心緒幾時休，逢著三春似九秋。", "數到五更仍五點，明朝還更有新愁。"]'),
('71b31d0d-20e3-4e96-88a7-91a592f697e1','春曉三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','拂花紅露濺春衣，柳外春禽睡未知。',32,'全唐诗/poet.song.139000.json','["拂花紅露濺春衣，柳外春禽睡未知。", "天借晴光與桃李，更將剩彩弄游絲。"]'),
('b5199089-f560-4f00-9c36-9940ce05e992','春曉三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風光明淑奈渠何，非暖非寒直是和。',32,'全唐诗/poet.song.139000.json','["風光明淑奈渠何，非暖非寒直是和。", "春到千花俱有分，海棠獨自得春多。"]'),
('b138e77d-1d43-43cf-8e67-b1a07792169e','春曉三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一年生活是三春，二月春光儘十分。',32,'全唐诗/poet.song.139000.json','["一年生活是三春，二月春光儘十分。", "不必開窗索花笑，隔窗花影也欣欣。"]'),
('5e911d09-add1-4721-9934-fa353aa8f0e4','米囊花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','鉛膏細細點花梢，道是春深雪未銷。',32,'全唐诗/poet.song.139000.json','["鉛膏細細點花梢，道是春深雪未銷。", "一斛千囊蒼玉粟，東風吹作米長腰。"]'),
('42a874d0-924a-414c-8ef1-26d045211c8a','米囊花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','鳥語蜂喧蝶亦忙，爭傳天詔詔花王。',32,'全唐诗/poet.song.139000.json','["鳥語蜂喧蝶亦忙，爭傳天詔詔花王。", "東皇羽衛無供給，探借春風十日糧。"]'),
('2f348b31-e9f5-4883-be3f-844f11a49f13','曉寒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','黯黯輕寒淡淡陰，遊人便覺減行春。',32,'全唐诗/poet.song.139000.json','["黯黯輕寒淡淡陰，遊人便覺減行春。", "春風也解嫌蕭索，自送鞦韆不要人。"]'),
('c0304036-3be0-4ab8-9455-7e1d3697a15b','曉寒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','春光喚入百花叢，寒力平欺兩鬢蓬。',32,'全唐诗/poet.song.139000.json','["春光喚入百花叢，寒力平欺兩鬢蓬。", "吹亂衆紅還復整，海棠却不怕東風。"]'),
('9bc5d201-2d72-47d7-b9b0-f89a15801810','上巳三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','上巳春陰政未開，寒窗愁坐冷於灰。',32,'全唐诗/poet.song.139000.json','["上巳春陰政未開，寒窗愁坐冷於灰。", "凍蠅觸紙飛還落，仰面翻身起不來。"]'),
('187cae78-d766-4757-8fa8-e61ad91babfa','上巳三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨冷風酸數日强，老懷不可更禁當。',32,'全唐诗/poet.song.139000.json','["雨冷風酸數日强，老懷不可更禁當。", "春寒幸自歸將去，喚取重來是海棠。"]'),
('a0d0b6e3-f605-489d-a66f-4522e43f6e27','上巳三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','正是春光最盛時，桃花枝映李花枝。',32,'全唐诗/poet.song.139000.json','["正是春光最盛時，桃花枝映李花枝。", "鞦韆日暮人歸盡，只有春風弄彩旗。"]'),
('f75cdccd-3442-43e3-a916-1f1386f8d3b8','寒食雨作','楊萬里','宋','宋诗','song-poetry','','[]','雙燕衝簾報禁煙，喚驚晝夢聳詩肩。',64,'全唐诗/poet.song.139000.json','["雙燕衝簾報禁煙，喚驚晝夢聳詩肩。", "晚寒政與花爲地，曉雨能令水作天。", "桃李海棠聊病眼，清明寒食又來年。", "老來不辦琱新句，報答風光且一篇。"]'),
('ef22f971-90d9-47b8-b6f0-b433e8de922c','垂絲海棠半落','楊萬里','宋','宋诗','song-poetry','','[]','雨後精神退九分，病香愁態不勝春。',32,'全唐诗/poet.song.139000.json','["雨後精神退九分，病香愁態不勝春。", "落階一寸輕紅雪，卷地風來政惱人。"]'),
('f1419c40-a5b3-49a6-bb58-b68598fb1851','寒食相將諸子遊翟園得十詩  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨罷饒晴色，松陰轉午時。',48,'全唐诗/poet.song.139000.json','["雨罷饒晴色，松陰轉午時。", "堆成李花雪，開遍海棠枝。", "旋酌新篘酒，留題細字詩。", "不來真是枉，欲去更云遲。"]'),
('4884c405-650d-4e8d-9f4f-cc7cb2df6af8','寒食相將諸子遊翟園得十詩  其二','楊萬里','宋','宋诗','song-poetry','','[]','鹿葱舊種菊新栽，幽徑深行忘却回。',32,'全唐诗/poet.song.139000.json','["鹿葱舊種菊新栽，幽徑深行忘却回。", "忽有野香尋不得，蘭於石背一花開。"]'),
('3f633912-fc2c-4490-a802-3e21777ff520','寒食相將諸子遊翟園得十詩  其三','楊萬里','宋','宋诗','song-poetry','','[]','柳條老去尚青鮮，下有清渠遶野田。',32,'全唐诗/poet.song.139000.json','["柳條老去尚青鮮，下有清渠遶野田。", "波面落花相趁走，避風爭泊岸傍邊。"]'),
('349742f8-b669-41d4-b51b-c0e3391d7bbe','寒食相將諸子遊翟園得十詩  其四','楊萬里','宋','宋诗','song-poetry','','[]','儘忙也到翟園休，只見春光不見愁。',32,'全唐诗/poet.song.139000.json','["儘忙也到翟園休，只見春光不見愁。", "屈折海棠團更密，日光下照繡燈毬。"]'),
('99d93055-14d7-4608-a448-e7c38147fc04','寒食相將諸子遊翟園得十詩  其五','楊萬里','宋','宋诗','song-poetry','','[]','小小茅亭短短窗，海棠圍裏柳中央。',32,'全唐诗/poet.song.139000.json','["小小茅亭短短窗，海棠圍裏柳中央。", "乍晴萱草渾無力，落盡梅花尚有香。"]'),
('285ade03-cf7a-4650-afa9-21fc825e26ae','寒食相將諸子遊翟園得十詩  其六','楊萬里','宋','宋诗','song-poetry','','[]','兒曹健走儘從渠，老脚微酸半要扶。',32,'全唐诗/poet.song.139000.json','["兒曹健走儘從渠，老脚微酸半要扶。", "未委前頭花好否，且令蜂蝶作前驅。"]'),
('8089fb60-61a0-4203-b101-aff41a9b2f6a','寒食相將諸子遊翟園得十詩  其七','楊萬里','宋','宋诗','song-poetry','','[]','三月風光一歲無，杏花欲過李花初。',32,'全唐诗/poet.song.139000.json','["三月風光一歲無，杏花欲過李花初。", "柳絲自爲春風舞，竹尾如何也學渠。"]'),
('42aa23c5-0fb1-4169-87c8-91c1d3ad557b','寒食相將諸子遊翟園得十詩  其八','楊萬里','宋','宋诗','song-poetry','','[]','驅使花枝苦未休，平章詩句政冥搜。',32,'全唐诗/poet.song.139000.json','["驅使花枝苦未休，平章詩句政冥搜。", "無端一竇西窗日，不遣吾人略小留。"]'),
('c36bb027-54c5-4cfa-a371-2f5c50cbd5cb','寒食相將諸子遊翟園得十詩  其九','楊萬里','宋','宋诗','song-poetry','','[]','花木從渠取次栽，青山那肯入城隈。',32,'全唐诗/poet.song.139000.json','["花木從渠取次栽，青山那肯入城隈。", "翟公不有驅山手，城裏松林底處來。"]'),
('eb414b08-3c70-4a7e-beb3-82bd5a39511b','寒食相將諸子遊翟園得十詩  其一○','楊萬里','宋','宋诗','song-poetry','','[]','荆溪老守底風流，哦就千詩一笑休。',32,'全唐诗/poet.song.139000.json','["荆溪老守底風流，哦就千詩一笑休。", "天欲做春無去處，只堆濃綠柳梢頭。"]'),
('81300fc5-6c8c-4cdd-9981-bbd83adb321a','三月十日','楊萬里','宋','宋诗','song-poetry','','[]','纔看桃李錦成圍，忽便園林綠作堆。',64,'全唐诗/poet.song.139000.json','["纔看桃李錦成圍，忽便園林綠作堆。", "遠草將人雙眼去，飛花引蝶過牆來。", "簿書節裏無多著，懷抱朝來得好開。", "已是七分春去了，何須鳥語苦相催。"]'),
('09ab8be0-1529-48e4-99a4-06f547b6e637','清明雨寒八首  其一','楊萬里','宋','宋诗','song-poetry','','[]','整冠忽見鏡中霜，挽樹渾無蔕上香。',32,'全唐诗/poet.song.139000.json','["整冠忽見鏡中霜，挽樹渾無蔕上香。", "已貯春愁過萬斛，更令細細著升量。"]'),
('fe60cf9a-ae37-4fcb-9440-38f1d20023a1','清明雨寒八首  其二','楊萬里','宋','宋诗','song-poetry','','[]','脫却單衣著裌衣，禁煙無有不寒時。',32,'全唐诗/poet.song.139000.json','["脫却單衣著裌衣，禁煙無有不寒時。", "一年好處君知麽，寒食千門插柳枝。"]'),
('8feff763-8aab-44e4-8242-82b98732d864','清明雨寒八首  其三','楊萬里','宋','宋诗','song-poetry','','[]','今年寒食與清明，各自陰晴作麽生。',32,'全唐诗/poet.song.139000.json','["今年寒食與清明，各自陰晴作麽生。", "細雨千絲不成點，如何也解滴簷聲。"]'),
('4da42a64-7031-4e9f-9eba-4709bc22ad7c','清明雨寒八首  其四','楊萬里','宋','宋诗','song-poetry','','[]','桃李一空春已歸，不須更待絮飛時。',32,'全唐诗/poet.song.139000.json','["桃李一空春已歸，不須更待絮飛時。", "閉門獨琢春寒句，只有輕風細雨知。"]'),
('c5aaea50-7607-45b1-b9d4-88b04951c6d5','清明雨寒八首  其五','楊萬里','宋','宋诗','song-poetry','','[]','苔階滴雨翠方濃，須把寒珠濺鹿葱。',32,'全唐诗/poet.song.139000.json','["苔階滴雨翠方濃，須把寒珠濺鹿葱。", "梅子猶粘雪前蕊，海棠生恨夜來風。"]'),
('f354adc6-26f8-416a-bef8-959f9c27f8a5','清明雨寒八首  其六','楊萬里','宋','宋诗','song-poetry','','[]','莫嫌細雨苦飄蕭，政要寒聲伴寂寥。',32,'全唐诗/poet.song.139000.json','["莫嫌細雨苦飄蕭，政要寒聲伴寂寥。", "杏葉猶疎不成響，且將紙瓦當芭蕉。"]'),
('97ad5a89-c546-4be0-b50e-99d014f0f1d0','清明雨寒八首  其七','楊萬里','宋','宋诗','song-poetry','','[]','閉戶何緣得句來，開窗更倩雨相催。',32,'全唐诗/poet.song.139000.json','["閉戶何緣得句來，開窗更倩雨相催。", "只言春色都歸去，小樹桃花政晚開。"]'),
('2e78a62c-4659-4ac4-98f7-f6de3af11033','清明雨寒八首  其八','楊萬里','宋','宋诗','song-poetry','','[]','風欹衆柳自成妍，雨泣殘花不忍看。',32,'全唐诗/poet.song.139000.json','["風欹衆柳自成妍，雨泣殘花不忍看。", "急喚麴生嘗杏子，及渠小苦未生酸。"]'),
('58cc5534-3feb-4926-9587-6964ba90808c','題山莊草蟲扇','楊萬里','宋','宋诗','song-poetry','','[]','風生蚱蜢怒鬚頭，紈扇團圓璧月流。',32,'全唐诗/poet.song.139000.json','["風生蚱蜢怒鬚頭，紈扇團圓璧月流。", "三蝶商量探花去，不知若箇是莊周。"]'),
('c3173c12-5da3-4a94-a4a3-1ee28b79073b','清明果飲二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','南溪春酒碧於江，北地鵝梨白似霜。',64,'全唐诗/poet.song.139000.json','["南溪春酒碧於江，北地鵝梨白似霜。", "頹却老人山作玉，更加食邑醉爲鄉。", "春光如許天何負，雨點殊疎燕不妨。", "絕愛杞萌如紫蕨，爲烹茗椀洗詩腸。"]'),
('92577be5-8b6e-4b9e-92d0-2f3079c5f2eb','清明果飲二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','深著爐香淺著杯，杯行儘緩莫教催。',64,'全唐诗/poet.song.139000.json','["深著爐香淺著杯，杯行儘緩莫教催。", "可憐花樹渾無頼，下却簾鉤也入來。", "雪藕新將削冰水，蔗霜只好點青梅。", "明年寒食還家去，却憶荆溪花政開。"]'),
('fbc935a5-30a5-49ae-b930-c9fbf6bafd4e','和張倅子儀送鞓紅魏紫崇寧紅醉西施四種牡丹二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','朱墨勾添眼底塵，今年春盡不知春。',32,'全唐诗/poet.song.139000.json','["朱墨勾添眼底塵，今年春盡不知春。", "鞓紅魏紫能相訪，西子崇寧更可人。"]'),
('b63a8e44-404e-46b1-ba86-2e986142303e','和張倅子儀送鞓紅魏紫崇寧紅醉西施四種牡丹二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','洛花移種到松江，國色天香內樣粧。',32,'全唐诗/poet.song.139000.json','["洛花移種到松江，國色天香內樣粧。", "老裏懶邊無好思，爲渠覓句却窮忙。"]'),
('a3489468-7ea8-4a3b-9e20-7495eb19d4bc','次李倅子壽郡集詩韻','楊萬里','宋','宋诗','song-poetry','','[]','蒼璧新煎第二泉，博山深炷古龍涎。',64,'全唐诗/poet.song.139000.json','["蒼璧新煎第二泉，博山深炷古龍涎。", "草玄顧我非楊子，能賦如公是仲宣。", "詩社自甘編下戶，醉鄉何苦不開邊。", "窮州地主慚司業，不解時時與酒錢。"]'),
('394f890b-bdfb-4622-a458-0cd94ddca1d5','薛舍人母方氏太恭人挽章二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','熊膽平生苦，魚軒晚歲榮。',48,'全唐诗/poet.song.139000.json','["熊膽平生苦，魚軒晚歲榮。", "芝蘭今柱史，苗裔古玄英。", "寒食花爭泣，元宵燭半明。", "從今好時節，萱砌罷君羹。"]'),
('2f087480-353b-4339-a96f-fb9cbd797f61','薛舍人母方氏太恭人挽章二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','賦感東征句，詩愁陟屺篇。',48,'全唐诗/poet.song.139000.json','["賦感東征句，詩愁陟屺篇。", "生前九齡夢，眼底五朝天。", "錦告渾無恙，雲車忽杳然。", "不堪青竹笋，歸路不迎船。"]'),
('5884cd97-8660-4568-80e4-930744505d1f','櫻桃','楊萬里','宋','宋诗','song-poetry','','[]','櫻桃一雨半彫零，更與黄鸝翠羽爭。',64,'全唐诗/poet.song.139000.json','["櫻桃一雨半彫零，更與黄鸝翠羽爭。", "計會小風留紫脆，殷勤落日弄紅明。", "摘來珠顆光如濕，走下金盤不待傾。", "天上薦新舊分賜，兒童猶解憶寅清。"]'),
('ab7b3c49-bfe0-4a07-ac63-f660a9308a7d','雨後行郡圃','楊萬里','宋','宋诗','song-poetry','','[]','雨餘行脚古城隈，爲愛危亭首屢回。',32,'全唐诗/poet.song.139000.json','["雨餘行脚古城隈，爲愛危亭首屢回。", "無數菊苗齊老去，多時花徑不曾來。"]'),
('bac16f49-f19f-433d-a2c4-fe98b939c3eb','多稼亭前兩檻芍藥紅白對開二百朵','楊萬里','宋','宋诗','song-poetry','','[]','紅紅白白定誰先，嫋嫋娉娉各自妍。',64,'全唐诗/poet.song.139000.json','["紅紅白白定誰先，嫋嫋娉娉各自妍。", "最是倚欄嬌分外，却緣經雨意醒然。", "晚春早夏渾無伴，暖豔晴香政可憐。", "好爲花王作花相，不應只遣侍甘泉。"]'),
('42bf6a45-3e16-4e80-b391-c4559a252e6f','小雨','楊萬里','宋','宋诗','song-poetry','','[]','雨纔放脚又還無，葉上蕭蕭半霎餘。',32,'全唐诗/poet.song.139000.json','["雨纔放脚又還無，葉上蕭蕭半霎餘。", "貯得千珠無點漏，絲窠元自不勝疎。"]'),
('628a9220-1ab0-4908-aef6-7839843cba7d','六月喜雨三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','守臣兩月禱山川，詔旨纔頒便沛然。',32,'全唐诗/poet.song.139000.json','["守臣兩月禱山川，詔旨纔頒便沛然。", "不是格天緣詔旨，憂民天子本如天。"]'),
('8fded573-0386-4c3f-9638-c8092190eac7','六月喜雨三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','玄雲直下素光開，雨到前山只恐回。',32,'全唐诗/poet.song.139000.json','["玄雲直下素光開，雨到前山只恐回。", "霹靂一聲風一陣，爲儂催上半天來。"]'),
('f24cd706-5b69-4c24-bc3d-f5fc565f0e1a','六月喜雨三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','今年不是雨來慳，不後秧時亦不前。',32,'全唐诗/poet.song.139000.json','["今年不是雨來慳，不後秧時亦不前。", "自古浙西長苦澇，近來無澇恰三年。"]'),
('4f014d60-6e93-4632-a5e8-6c1d7cc2acf9','和李子壽通判曾慶祖判院投贈喜雨口號八首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雷起嘉山半點蒼，乖龍無地著身藏。',32,'全唐诗/poet.song.139000.json','["雷起嘉山半點蒼，乖龍無地著身藏。", "莫嫌白雨來差晚，但遣黄雲作大穰。"]'),
('96d959a8-04ad-46a0-b5de-29a53fbc3b08','和李子壽通判曾慶祖判院投贈喜雨口號八首  其二','楊萬里','宋','宋诗','song-poetry','','[]','塵漲街頭不識泥，朝來也解滑霜蹄。',32,'全唐诗/poet.song.139000.json','["塵漲街頭不識泥，朝來也解滑霜蹄。", "兩公玉句驚風雨，把翫都忘日脚西。"]'),
('f671532c-64ce-430e-aec1-f5a616d68cd6','和李子壽通判曾慶祖判院投贈喜雨口號八首  其三','楊萬里','宋','宋诗','song-poetry','','[]','雨早些時打麥殘，雨遲許日即秧乾。',32,'全唐诗/poet.song.139000.json','["雨早些時打麥殘，雨遲許日即秧乾。", "阿誰會得天公意，只道今年乞雨難。"]'),
('2c5d2498-602a-46cc-a495-826403c988d1','和李子壽通判曾慶祖判院投贈喜雨口號八首  其四','楊萬里','宋','宋诗','song-poetry','','[]','夢中簷溜作灘聲，幼竹新荷總解鳴。',32,'全唐诗/poet.song.139000.json','["夢中簷溜作灘聲，幼竹新荷總解鳴。", "曉色滿城渾是喜，更無一寸旱時情。"]'),
('7aa22aa4-430a-465b-8f17-98fba4b0d2e9','和李子壽通判曾慶祖判院投贈喜雨口號八首  其五','楊萬里','宋','宋诗','song-poetry','','[]','蘇湖元以水爲鄉，春早偏欺潤與常。',32,'全唐诗/poet.song.139000.json','["蘇湖元以水爲鄉，春早偏欺潤與常。", "一雨忽來三晝夜，兩公卷入八詩章。"]'),
('1d0a5f4d-4755-4a3e-970b-b88578ff5716','和李子壽通判曾慶祖判院投贈喜雨口號八首  其六','楊萬里','宋','宋诗','song-poetry','','[]','守臣閔雨幾曾欣，兩月天高叫不聞。',32,'全唐诗/poet.song.139000.json','["守臣閔雨幾曾欣，兩月天高叫不聞。", "黄紙带將今雨至，分明端爲聖明君。"]'),
('4ad8814b-5634-439e-9944-da8d9b42c720','和李子壽通判曾慶祖判院投贈喜雨口號八首  其七','楊萬里','宋','宋诗','song-poetry','','[]','謫仙下筆不曾休，句似金盤柘彈流。',32,'全唐诗/poet.song.139000.json','["謫仙下筆不曾休，句似金盤柘彈流。", "我欲將渠卜鄰著，對披簑笠刺漁舟。"]'),
('0c873cb4-9ab3-4c8f-b17f-ee21a39ecaa2','和李子壽通判曾慶祖判院投贈喜雨口號八首  其八','楊萬里','宋','宋诗','song-poetry','','[]','南豐每見每津津，繭紙松煤幻好春。',32,'全唐诗/poet.song.139000.json','["南豐每見每津津，繭紙松煤幻好春。", "幸與李侯成二妙，更添楊子作三人。"]'),
('3b02f7f6-7d1d-4f2d-add1-fac913d2ac3c','曉登多稼亭三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','過雨梅無半箇黄，冬青枝上雪花香。',32,'全唐诗/poet.song.139000.json','["過雨梅無半箇黄，冬青枝上雪花香。", "不須更要風吹面，看著青林意自涼。"]'),
('bea78a97-87c8-4ece-9831-9dd38772f647','曉登多稼亭三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨前田畝不勝荒，雨後農家特地忙。',32,'全唐诗/poet.song.139000.json','["雨前田畝不勝荒，雨後農家特地忙。", "一眼平疇三十里，際天白水立青秧。"]'),
('92427464-df03-4234-8921-1b6aff1a2ade','曉登多稼亭三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','尚無池水泛荷香，幸有園英照竹窗。',32,'全唐诗/poet.song.139000.json','["尚無池水泛荷香，幸有園英照竹窗。", "雪白葵花持玉節，柿紅萱草立金幢。"]'),
('026e7734-3770-495a-b52c-feaab7eb2c85','六月六日小集二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','青李來禽已眼明，新瓜入夏見何曾。',32,'全唐诗/poet.song.139000.json','["青李來禽已眼明，新瓜入夏見何曾。", "酒邊忘却人間暑，消盡金盆一丈冰。"]'),
('18aa329e-7ae9-43d3-9ceb-028c3310251c','六月六日小集二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','新蟬聲澀亦無多，强與嬌鶑和好歌。',32,'全唐诗/poet.song.139000.json','["新蟬聲澀亦無多，强與嬌鶑和好歌。", "盡日舞風渾不倦，無人奈得柳條何。"]'),
('39c6aa32-6f84-427f-8191-34e16d3df27d','雨足曉立郡圃荷橋','楊萬里','宋','宋诗','song-poetry','','[]','郡池六月水方生，便有新荷貼水輕。',32,'全唐诗/poet.song.139000.json','["郡池六月水方生，便有新荷貼水輕。", "雨後獨來無箇事，閑聽啼鳥話昇平。"]'),
('15c5022b-b116-4b87-b8d0-9b90b9c14e8a','登多稼亭曉望','楊萬里','宋','宋诗','song-poetry','','[]','風不能銷曉霧痕，天猶未放宿雲根。',32,'全唐诗/poet.song.139000.json','["風不能銷曉霧痕，天猶未放宿雲根。", "城腰折處纔三徑，山觜前頭別一村。"]'),
('8e5779bb-3169-4615-bfb1-845160bd0fc6','午熱登多稼亭五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','矮屋炎天不可居，高亭爽氣亦元無。',32,'全唐诗/poet.song.139000.json','["矮屋炎天不可居，高亭爽氣亦元無。", "小風不被蟬餐却，合有些凉到老夫。"]'),
('22864ace-09ce-4e00-bc50-d913b5688041','午熱登多稼亭五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','芒鞋葵扇頗蕭然，倦倚胡床不是眠。',32,'全唐诗/poet.song.139000.json','["芒鞋葵扇頗蕭然，倦倚胡床不是眠。", "避暑無藏身去處，追涼行盡竹旁邊。"]'),
('9b79c68b-a4f8-4a6a-83cc-4213bfa0b70b','午熱登多稼亭五首  其三','楊萬里','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不是城中是甑中，雨餘日色更明紅。',32,'全唐诗/poet.song.139000.json','["不是城中是甑中，雨餘日色更明紅。", "若爲飛上金山頂，獨立長江萬里風。"]'),
('fca3ac79-d1ea-4b9b-8b0d-c0820cdd03a5','午熱登多稼亭五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','柳外花邊忽颯然，好風一點破愁顔。',32,'全唐诗/poet.song.139000.json','["柳外花邊忽颯然，好風一點破愁顔。", "岸巾獨倚千尋樹，閑看南雲度北山。"]'),
('3ef8dca0-9bef-4889-9444-be2ecc93b580','午熱登多稼亭五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','御風不必問雌雄，只有炎風最不中。',32,'全唐诗/poet.song.139000.json','["御風不必問雌雄，只有炎風最不中。", "却是竹君殊解事，炎風篩過作清風。"]'),
('ecbb747e-e74a-4551-877e-1d978fd914c2','張尉惠詩和韻謝之三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','下筆生波便百川，字間句裏總超然。',32,'全唐诗/poet.song.139000.json','["下筆生波便百川，字間句裏總超然。", "讀來清氣涼人骨，六月真成九月天。"]'),
('e3cc8361-21e6-441d-b4b8-fecbfc0639d1','張尉惠詩和韻謝之三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','軟紅塵裏眼曾開，苦被新詩猛喚回。',32,'全唐诗/poet.song.139000.json','["軟紅塵裏眼曾開，苦被新詩猛喚回。", "借問錦心能底巧，更從月脇摘將來。"]'),
('f80909e9-b292-4e7f-981e-0ac429b6498b','張尉惠詩和韻謝之三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','老去才情半掬慳，不愁不退豈愁前。',32,'全唐诗/poet.song.139000.json','["老去才情半掬慳，不愁不退豈愁前。", "清風明月無拘管，與子分張更一年。"]'),
('c5a2c112-667b-48d6-93f7-d928c6202681','卧治齋晚坐','楊萬里','宋','宋诗','song-poetry','','[]','閉戶坐不得，開窗竚微涼。',96,'全唐诗/poet.song.139000.json','["閉戶坐不得，開窗竚微涼。", "樹林蔭白日，几研生碧光。", "信手取詩卷，細哦三數章。", "初披頗欣愜，再攬忽感傷。", "廢卷不能讀，起行繞胡床。", "古人恨如山，吾心澹於江。", "本不與彼謀，云何斷我腸。", "感罷翻自笑，一蟬催夕陽。"]'),
('902f7244-ebe0-4927-86a5-0b2130774a7e','憩懷古堂','楊萬里','宋','宋诗','song-poetry','','[]','新葺懷古堂，舊臨郭璞池。',144,'全唐诗/poet.song.139000.json','["新葺懷古堂，舊臨郭璞池。", "去歲夏徂秋，無日不此嬉。", "茨菰無暑性，芙蕖有涼姿。", "今年池水乾，老子來遂稀。", "豈惟來不留，亦復去靡思。", "朝來偶一到，又覺景特奇。", "水含霽後光，荷於風處欹。", "便有白鷗下，驚起翠羽飛。", "方池灧窗東，長池橫簷西。", "紅綠向背看，觴詠朝夕宜。", "此堂初無情，此池諒何知。", "如何涉斯世，乖逢亦有時。"]'),
('2442d6f6-a181-4cda-8b14-dae48d402999','望雨','楊萬里','宋','宋诗','song-poetry','','["\u592a\u6e56"]','雲興惠山頂，雨放太湖脚。',132,'全唐诗/poet.song.139000.json','["雲興惠山頂，雨放太湖脚。", "初愁望中遠，忽在頭上落。", "白羽障烏巾，衣袖已沾渥。", "歸來看簷溜，如瀉萬仞壑。", "霆裂大瑶甕，電縈濕銀索。", "須臾水平階，花塢失半角。", "定知秧疇滿，想見田父樂。", "向來春夏交，旱氣亦太虐。", "山川已徧走，雲物竟索寞。", "雙鬢愁得白，兩膝拜將剝。", "早知有今雨，老懷枉作惡。"]'),
('eec679f8-5bd0-4592-9aab-4017fc610760','聞一二故人相繼而逝感歎書懷','楊萬里','宋','宋诗','song-poetry','','[]','故人昔同朝，與游每甚歡。',276,'全唐诗/poet.song.139000.json','["故人昔同朝，與游每甚歡。", "豈緣勢利合，相得文字間。", "有頃各補外，不見今六年。", "我來荆溪上，敲榜索租錢。", "故人復雙入，飛上青雲端。", "我雖世味澹，羨心能恝然。", "忽傳故人去，得書墨未乾。", "又傳故人亡，驚悼摧肺肝。", "鼎貴良獨佳，安貧未遽賢。", "向以我易彼，安知不作難。", "今以彼易我，試問誰當慳。", "如何捐此軀，必要博好官。", "顧謂妻與子，官滿當歸田。", "我賤汝勿羞，我貧汝勿歎。", "從汝丐我身，百年庶團欒。", "妻子笑答我，脩短未易言。", "富貴必速殞，郭令當夭殘。", "貧賤果永算，顔子壽必延。", "我復答渠道，薄命我自憐。", "我福肯如郭，我德敢望顔。", "造物本嗇與，我乃多取旃。", "借令彼不怒，退省我獨安。", "汝言自有理，我意不可還。"]'),
('9d8a25f4-b960-4350-9d7f-b2e6bb6e9729','晚步追凉二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老眼偏明遠岫孤，夕陽故遣樹陰疎。',32,'全唐诗/poet.song.139000.json','["老眼偏明遠岫孤，夕陽故遣樹陰疎。", "蟬鳴葉底無尋處，隨意閑行偶見渠。"]'),
('c1cdcea9-bb14-4e8f-8b2a-6d56451f4f56','晚步追凉二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風不須多只是涼，穿花度柳到人傍。',32,'全唐诗/poet.song.139000.json','["風不須多只是涼，穿花度柳到人傍。", "細吹病耳颼颼響，徐弄輕衫拂拂長。"]'),
('c444763f-61b0-49a9-af9e-4b1eb20b261c','荷橋暮坐三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','橋剪荷花兩段開，荷花留我不容回。',32,'全唐诗/poet.song.139000.json','["橋剪荷花兩段開，荷花留我不容回。", "不勝好處荷橋坐，政是涼時蚊子來。"]'),
('4607c34e-6991-43f5-b6d1-16a560eefd11','荷橋暮坐三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','池似平鋪綠錦橫，荷花爲緯藻爲經。',32,'全唐诗/poet.song.139000.json','["池似平鋪綠錦橫，荷花爲緯藻爲經。", "無端織出詩人像，獨立飛橋摘斗星。"]'),
('21165b88-5327-41e2-97b7-009b1260c06c','荷橋暮坐三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','水到荷花蔕，風生菰葉梢。',24,'全唐诗/poet.song.139000.json','["水到荷花蔕，風生菰葉梢。", "鷗鳬晚聲散，天水夕光交。"]'),
('ea0cc95d-9099-429e-a012-d7b5ac566cae','休日清曉讀書多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','携家守荆溪，忽忽已一朞。',144,'全唐诗/poet.song.139000.json','["携家守荆溪，忽忽已一朞。", "官舍非不佳，懷抱長鮮怡。", "若非僮僕病，定復兒女啼。", "昔貧歎不飽，今愁豈緣饑。", "晨起袖書冊，急登亭上嬉。", "露痕尚星月，風氣無窗扉。", "頓覺老病身，不禁絺綌衣。", "昨暑何可度，朝涼乃爾奇。", "白鳥遠如蝶，玄蟬哦似詩。", "松色雪我神，荷香冰我脾。", "憂樂忽安在，形骸亦俱遺。", "穉子不解事，朝餐呼我歸。"]'),
('e7fb93a8-1257-4d47-be94-e0caee513540','多稼亭上望三山中峰獨秀而低','楊萬里','宋','宋诗','song-poetry','','[]','三山道是遠連天，亭上看來只近簷。',32,'全唐诗/poet.song.139000.json','["三山道是遠連天，亭上看來只近簷。", "可惜當初低少許，三山幸有一峰尖。"]'),
('57799eea-aa3c-493d-a276-29578aae8f38','雨後晚步郡圃二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','畫舫鳴鉦野寺鐘，暮聲驚破翠煙重。',32,'全唐诗/poet.song.139000.json','["畫舫鳴鉦野寺鐘，暮聲驚破翠煙重。", "好風不解藏天巧，彫碎孤雲作數峰。"]'),
('f15faf60-8836-4ef8-b510-787deec6c2db','雨後晚步郡圃二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','風勒歸雲带雨回，不容老子小徘徊。',32,'全唐诗/poet.song.139000.json','["風勒歸雲带雨回，不容老子小徘徊。", "撥忙也到池亭上，昨日卷荷今盡開。"]'),
('d6197b54-1827-4cc0-a248-41f7912e6e51','曉坐荷橋四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雨後晨前絕爽時，胡床四面是荷池。',32,'全唐诗/poet.song.139000.json','["雨後晨前絕爽時，胡床四面是荷池。", "荷珠細走惟愁落，爲報薰風莫急吹。"]'),
('7d1b7c69-a503-45b7-b479-21c8d161ecc7','曉坐荷橋四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','四葉青蘋點綠池，千重翠蓋護紅衣。',32,'全唐诗/poet.song.139000.json','["四葉青蘋點綠池，千重翠蓋護紅衣。", "蜻蜓空裏元無見，只見波間仰面飛。"]'),
('088fdc07-0400-4708-b5cf-e45393d63b95','曉坐荷橋四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','碧玉山邊白鳥鳴，綠楊風裏翠荷聲。',32,'全唐诗/poet.song.139000.json','["碧玉山邊白鳥鳴，綠楊風裏翠荷聲。", "草花踏碎教人惜，爲勒芒鞋款款行。"]'),
('efdc820d-9f37-4f5e-aaf3-95c0f842a136','曉坐荷橋四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','簾影窺池到藕根，水光爲我弄朝暾。',32,'全唐诗/poet.song.139000.json','["簾影窺池到藕根，水光爲我弄朝暾。", "魚兒解作晴天雨，波面吹成落點痕。"]'),
('143b4ed1-a8f7-45a7-b218-cda7854eb74f','池亭','楊萬里','宋','宋诗','song-poetry','','[]','小沼纔階下，孤亭恰水邊。',48,'全唐诗/poet.song.139000.json','["小沼纔階下，孤亭恰水邊。", "揩磨一玉鏡，上下兩青天。", "可惜無多水，難堪著釣船。", "今年非不暑，每到每醒然。"]'),
('79ff6b53-15ba-41d0-a498-1675d396692d','卧治齋盆池','楊萬里','宋','宋诗','song-poetry','','[]','舊來菰葉已全衰，旋買新荷带藕栽。',32,'全唐诗/poet.song.139000.json','["舊來菰葉已全衰，旋買新荷带藕栽。", "看得荷花作蓮子，可憐時節被花催。"]'),
('51ec22fa-5079-427e-a50a-c7e978863dd8','凝露堂前紫薇花兩株每自五月盛開九月乃衰二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','晴霞豔豔覆簷牙，絳雪霏霏點砌沙。',32,'全唐诗/poet.song.139000.json','["晴霞豔豔覆簷牙，絳雪霏霏點砌沙。", "莫管身非香案吏，也移床對紫薇花。"]'),
('3b0a4e3e-960f-4e46-9bcd-ded69d2c1f4f','凝露堂前紫薇花兩株每自五月盛開九月乃衰二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','似癡如醉弱還佳，露壓風欺分外斜。',32,'全唐诗/poet.song.139000.json','["似癡如醉弱還佳，露壓風欺分外斜。", "誰道花無紅十日，紫薇長放半年花。"]'),
('40840a84-dc56-4aa4-95ec-08c3e18349d9','暮坐中庭','楊萬里','宋','宋诗','song-poetry','','[]','蚊子因涼減，蟬聲入暮多。',24,'全唐诗/poet.song.139000.json','["蚊子因涼減，蟬聲入暮多。", "有愁無處著，不飲欲如何。"]'),
('0baebf9d-1ffc-424a-823f-8897d3bfcbf4','食蓮子','楊萬里','宋','宋诗','song-poetry','','[]','蜂不禁人採蜜忙，荷花蕊裏作蜂房。',32,'全唐诗/poet.song.139000.json','["蜂不禁人採蜜忙，荷花蕊裏作蜂房。", "不知玉蛹甜於蜜，又被詩人嚼作霜。"]'),
('20a29620-6312-474c-b381-dd5eb6428560','食雞頭','楊萬里','宋','宋诗','song-poetry','','[]','龍宮失曉惱江妃，也養鳴雞報早暉。',32,'全唐诗/poet.song.139000.json','["龍宮失曉惱江妃，也養鳴雞報早暉。", "要啄稻粱無半粒，只教滿頷飽珠璣。"]'),
('91e91bb1-48d4-465e-94a3-8d76d79a745c','暮雨既霽將兒輩登多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','一霎滂沱一霎晴，簷間點滴尚殘聲。',64,'全唐诗/poet.song.139000.json','["一霎滂沱一霎晴，簷間點滴尚殘聲。", "水將樹影亂揉碎，月與日光相對明。", "試數六宵還五雨，坐令夏熱作秋清。", "兒曹小住休歸去，更聽風蟬子細鳴。"]'),
('02614a1d-5f41-4b7a-a0db-8e593234a4c5','苦熱登多稼亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','日脚斜紅欲暮天，倚欄垂手弄雲煙。',64,'全唐诗/poet.song.139000.json','["日脚斜紅欲暮天，倚欄垂手弄雲煙。", "兩行相對樹如許，一葉不摇風寂然。", "剩欲啜茶還罷去，却愁通夕不成眠。", "黑絲半把垂天外，白雨初生遠嶺邊。"]'),
('df3a2041-938f-48e4-b8fb-4054e5649ee9','苦熱登多稼亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','吏散庭空便悄然，不須休日始偷閑。',64,'全唐诗/poet.song.139000.json','["吏散庭空便悄然，不須休日始偷閑。", "鷗邊野水水邊屋，城外平林林外山。", "偶見行人回首却，亦看老子立亭間。", "暮蟬何苦催歸急，只待涼生月半環。"]'),
('ef3bb046-1b9b-40a6-b3aa-8561f0971c76','暮熱游荷池上五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','玉礫金沙一逕長，暑中無處可追涼。',32,'全唐诗/poet.song.139000.json','["玉礫金沙一逕長，暑中無處可追涼。", "獨行行到荷池上，荷不生風水不香。"]'),
('a577b2e1-38ee-4363-bdf5-5e0e27e5605b','暮熱游荷池上五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','寒甃千尋汲井花，病身一浴不勝佳。',32,'全唐诗/poet.song.139000.json','["寒甃千尋汲井花，病身一浴不勝佳。", "追涼不得渾閑事，燒眼生憎半幅霞。"]'),
('f4fa762f-2954-49fb-8429-ebea0c533627','暮熱游荷池上五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','細草摇頭忽報儂，披襟攔得一西風。',32,'全唐诗/poet.song.139000.json','["細草摇頭忽報儂，披襟攔得一西風。", "荷花入暮猶愁熱，低面深藏碧傘中。"]'),
('e24bf24f-211d-470f-8e8c-53951ae8f865','暮熱游荷池上五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','也不多時便立秋，寄聲殘暑速拘收。',32,'全唐诗/poet.song.139000.json','["也不多時便立秋，寄聲殘暑速拘收。", "瘦蟬有得許多氣，吟落斜陽未肯休。"]'),
('30551456-976c-45b7-9a8c-aabc11b3be3d','暮熱游荷池上五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','空中斗起朵雲頭，旋旋開來旋旋收。',32,'全唐诗/poet.song.139000.json','["空中斗起朵雲頭，旋旋開來旋旋收。", "初作䰒鬆松樹子，忽成髣髴柳花毬。"]'),
('71db8662-899f-4a5e-a329-f3ca545f49b8','月下果飲七首  其一','楊萬里','宋','宋诗','song-poetry','','[]','恰則天方暮，如何月正中。',48,'全唐诗/poet.song.139000.json','["恰則天方暮，如何月正中。", "一年無此熱，今夕絕無風。", "早藕凝鬆雪，新菱剝釅紅。", "醉鄉堪避暑，只合著衰翁。"]'),
('54cda6ce-b8b0-4f24-aa73-39100493f829','月下果飲七首  其二','楊萬里','宋','宋诗','song-poetry','','[]','酒邊無物伴長瓶，一顆新蓮一段冰。',32,'全唐诗/poet.song.139000.json','["酒邊無物伴長瓶，一顆新蓮一段冰。", "月下不風終是爽，燭光何罪也堪憎。"]'),
('58282f4e-c5b3-4417-bc8f-c25e77bbe3b3','月下果飲七首  其三','楊萬里','宋','宋诗','song-poetry','','[]','一年遇暑一番愁，六月梢時七月頭。',32,'全唐诗/poet.song.139000.json','["一年遇暑一番愁，六月梢時七月頭。", "今夕追涼還得熱，何時遇夏却逢秋。"]'),
('5cb23f5f-2712-485b-9119-f336d018b69f','月下果飲七首  其四','楊萬里','宋','宋诗','song-poetry','','[]','月初生處薄雲生，到得雲銷月政明。',32,'全唐诗/poet.song.139000.json','["月初生處薄雲生，到得雲銷月政明。", "兩處打更如一處，二更還作四更聲。"]'),
('2ad9821c-36fe-46b3-836b-eb436491f28d','月下果飲七首  其五','楊萬里','宋','宋诗','song-poetry','','[]','坐久輕雲次第開，月光飛入酒杯來。',32,'全唐诗/poet.song.139000.json','["坐久輕雲次第開，月光飛入酒杯來。", "今宵只有半邊月，一半桂枝何處栽。"]'),
('447fbf75-1317-4a1b-877b-7d94f1b4c107','月下果飲七首  其六','楊萬里','宋','宋诗','song-poetry','','[]','斜斜花影欲愁予，唧唧蟲聲亦愛渠。',32,'全唐诗/poet.song.139000.json','["斜斜花影欲愁予，唧唧蟲聲亦愛渠。", "月與詩人元不薄，儂於歡伯未應疎。"]'),
('a2e87ff9-0d08-4cc6-8cdc-07642ffe8b09','月下果飲七首  其七','楊萬里','宋','宋诗','song-poetry','','[]','人靜更深丈室虛，欲眠聊復小踟躕。',32,'全唐诗/poet.song.139000.json','["人靜更深丈室虛，欲眠聊復小踟躕。", "竹床最冷也成熱，羽扇不涼差勝無。"]'),
('ef147e3d-f86a-4576-a64f-29dd98f14e16','曉坐多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','日光烘碎一天雲，散作濛濛霧滿村。',32,'全唐诗/poet.song.139000.json','["日光烘碎一天雲，散作濛濛霧滿村。", "我亦知渠別無事，不教遠岫翠當門。"]'),
('3ddd3694-4104-4b88-88a3-7a1340c22b33','梳頭有感二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','身在荷香水影中，曉涼不與夜來同。',32,'全唐诗/poet.song.139000.json','["身在荷香水影中，曉涼不與夜來同。", "且拋書冊梳蓬鬢，移轉胡床受小風。"]'),
('059db4fc-d4e5-481b-8b3d-23e705b40801','梳頭有感二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','同郡同年總八人，七人零落一人存。',32,'全唐诗/poet.song.139000.json','["同郡同年總八人，七人零落一人存。", "如何獨立薰風裏，猶怨霜花點鬢根。"]'),
('03570a82-d834-4668-9f64-acc014db562b','晚凉散策二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','飯餘浴罷趁涼行，偶憩池頭最小亭。',32,'全唐诗/poet.song.139000.json','["飯餘浴罷趁涼行，偶憩池頭最小亭。", "醉倚胡床便成睡，夢聞荷氣忽然醒。"]'),
('9655ccc3-3d7f-49c5-9a50-6a0e776f494e','晚凉散策二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','半點輕風泛柳絲，忽吹荷葉一時欹。',32,'全唐诗/poet.song.139000.json','["半點輕風泛柳絲，忽吹荷葉一時欹。", "芙蕖好處無人會，最是將開半落時。"]'),
('547c3e9f-d6a3-432e-b9f2-8a20a67484f2','閏六月立秋後暮熱追凉郡圃二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','上得城來眼頓明，暮山爭獻數尖青。',32,'全唐诗/poet.song.139000.json','["上得城來眼頓明，暮山爭獻數尖青。", "垂楊舞罷西風葉，一葉多時獨未停。"]'),
('46339180-1222-4889-941b-2363d467f601','閏六月立秋後暮熱追凉郡圃二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夏欲盡頭秋欲初，小涼未苦爽肌膚。',32,'全唐诗/poet.song.139000.json','["夏欲盡頭秋欲初，小涼未苦爽肌膚。", "夕陽幸自西山外，一抹斜紅不肯無。"]'),
('7f0013db-772f-4a81-981e-1c310f23d808','靜坐池亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','胡床倦坐起憑欄，人正忙時我正閑。',32,'全唐诗/poet.song.139000.json','["胡床倦坐起憑欄，人正忙時我正閑。", "却是閑中有忙處，看書纔了又看山。"]'),
('d7f473cd-fd45-4b0a-a9ad-6ed34343fcf1','靜坐池亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','荷邊弄水一身香，竹裏招風滿扇涼。',32,'全唐诗/poet.song.139000.json','["荷邊弄水一身香，竹裏招風滿扇涼。", "道是秋來還日短，秋來閑裏日偏長。"]'),
('a6c06644-a733-45fd-ab73-70e50407caba','秋暑三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','不教老子略眉開，夏熱未除秋熱來。',32,'全唐诗/poet.song.139000.json','["不教老子略眉開，夏熱未除秋熱來。", "一夜涼風吹欲盡，半輪曉日喚將回。"]'),
('813fd616-e1d0-4d71-a1ca-c3a17a710047','秋暑三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','汗如雨點湧人膚，一一鬚根一一珠。',32,'全唐诗/poet.song.139000.json','["汗如雨點湧人膚，一一鬚根一一珠。", "不道去年秋不熱，今年秋熱去年無。"]'),
('1db896a7-b37e-443d-a881-85a7fdfafbee','秋暑三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','半柳斜陽半柳陰，一蟬飛去一蟬吟。',32,'全唐诗/poet.song.139000.json','["半柳斜陽半柳陰，一蟬飛去一蟬吟。", "岸巾亭子鈎欄角，送眼江村松樹林。"]'),
('52ee252e-75a5-4de9-bbdf-47aa7ff1e2c1','戲題','楊萬里','宋','宋诗','song-poetry','','[]','蜂居筆管沒人知，誰遣啾啾不住時。',32,'全唐诗/poet.song.139000.json','["蜂居筆管沒人知，誰遣啾啾不住時。", "最是蝸牛太多事，長將宅子自相隨。"]'),
('268a6e0e-18f2-4435-a72d-56ffafe6ceb8','曉登水亭','楊萬里','宋','宋诗','song-poetry','','[]','露氣仍荷氣，秋風更曉風。',24,'全唐诗/poet.song.139000.json','["露氣仍荷氣，秋風更曉風。", "身兼水亭子，雙墮玉壺中。"]'),
('4eff9e09-c1a1-4436-a458-442079433921','讀元白長慶二集詩','楊萬里','宋','宋诗','song-poetry','','[]','讀遍元詩與白詩，一生少傅重微之。',32,'全唐诗/poet.song.139000.json','["讀遍元詩與白詩，一生少傅重微之。", "再三不曉渠何意，半是交情半是私。"]'),
('f9ad1cf2-3b56-49e3-abf3-054967598eec','白蓮','楊萬里','宋','宋诗','song-poetry','','[]','花頭素片剪成冰，葉背青瓊刻作稜。',32,'全唐诗/poet.song.139000.json','["花頭素片剪成冰，葉背青瓊刻作稜。", "珍重兒童輕手折，綠針刺手却渠憎。"]'),
('364a0ef9-6a73-4d31-a939-f84e3550a0b3','瓶中紅白二蓮五首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紅白蓮花共玉瓶，紅蓮韻絕白蓮清。',32,'全唐诗/poet.song.139000.json','["紅白蓮花共玉瓶，紅蓮韻絕白蓮清。", "空齋不是無秋暑，暑被花銷斷不生。"]'),
('a1560d21-157b-4823-90d7-4c5f3b228821','瓶中紅白二蓮五首  其二','楊萬里','宋','宋诗','song-poetry','','[]','揀得新開便折將，忽然到晚斂花房。',32,'全唐诗/poet.song.139000.json','["揀得新開便折將，忽然到晚斂花房。", "只愁花斂香還減，來早重開別是香。"]'),
('dfb1e7df-aa3e-49e8-92fb-e49dbd60010f','瓶中紅白二蓮五首  其三','楊萬里','宋','宋诗','song-poetry','','[]','晚花特地斂新粧，莫道無情總不妨。',32,'全唐诗/poet.song.139000.json','["晚花特地斂新粧，莫道無情總不妨。", "中有黄金蓮子盞，被人瞥見即深藏。"]'),
('44fe7e70-694b-4921-b377-38f2753f9570','瓶中紅白二蓮五首  其四','楊萬里','宋','宋诗','song-poetry','','[]','白蓮半莟未開時，看作紅蓮更不疑。',32,'全唐诗/poet.song.139000.json','["白蓮半莟未開時，看作紅蓮更不疑。", "到得欲開渾別了，玉膚洗退淡臙脂。"]'),
('f74524cd-b563-45a3-927b-83bec094cdef','瓶中紅白二蓮五首  其五','楊萬里','宋','宋诗','song-poetry','','[]','折得荷花伴我幽，更搴荷葉伴花愁。',32,'全唐诗/poet.song.139000.json','["折得荷花伴我幽，更搴荷葉伴花愁。", "孤芳欲落偏多思，一片先垂半不收。"]'),
('0d195ff0-600f-4d8a-9d80-78a4336637a5','早起','楊萬里','宋','宋诗','song-poetry','','[]','不分老鈴下，苦來驚我眠。',48,'全唐诗/poet.song.139000.json','["不分老鈴下，苦來驚我眠。", "要知甘寢處，最是欲明天。", "未了公家事，難銷月俸錢。", "坐曹臨訟罷，殘燭正熒然。"]'),
('492dd18d-7cb6-4b4f-a899-31a2a13eabaf','曉登懷古堂','楊萬里','宋','宋诗','song-poetry','','[]','度暑過於歲，初涼別是天。',48,'全唐诗/poet.song.139000.json','["度暑過於歲，初涼別是天。", "獨穿秋露草，來看曉風蓮。", "病骨殊輕甚，幽襟一灑然。", "不妨聊吏隠，何必更林泉。"]'),
('9e5ab130-ee28-46e0-b1bd-6bd1a9f81ed6','荷橋','楊萬里','宋','宋诗','song-poetry','','[]','橋壓荷梢過，花圍橋外饒。',24,'全唐诗/poet.song.139000.json','["橋壓荷梢過，花圍橋外饒。", "荆溪無勝處，勝處是荷橋。"]'),
('b8369c00-84ba-4005-97d4-085cbc2838f2','感秋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','今歲五十二，豈爲年少人。',48,'全唐诗/poet.song.139000.json','["今歲五十二，豈爲年少人。", "荷涼欣暑退，蟬苦怨秋新。", "澹慮翻成感，彫詩不著塵。", "小兒知得句，頻掉小烏巾。"]'),
('4c619acf-df0d-42f3-854e-013dd1839840','感秋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南國初涼日，東吳欲盡頭。',48,'全唐诗/poet.song.139000.json','["南國初涼日，東吳欲盡頭。", "露荷幽馥曉，雲日澹光秋。", "也愛西風爽，其如半老休。", "蟬聲與蛩響，計會兩催愁。"]'),
('bd203546-dc82-4c04-b64b-ab1a1b250a39','雨後清曉梳頭讀書懷古堂二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','宿雨猶涼在，晨陰欲霽初。',48,'全唐诗/poet.song.139000.json','["宿雨猶涼在，晨陰欲霽初。", "移床近秋水，正面對芙蕖。", "團扇淒無彩，生衣凜覺疎。", "欲歸仍小住，更讀數行書。"]'),
('bbfe5c7d-0d54-4e42-ab77-018aa3ba6585','雨後清曉梳頭讀書懷古堂二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','蟲響餘宵寂，荷粧赴曉鮮。',48,'全唐诗/poet.song.139000.json','["蟲響餘宵寂，荷粧赴曉鮮。", "梳頭花霧裏，照水柳風前。", "舊雨仍今雨，新年勝故年。", "登城有佳眺，秋稼正連天。"]'),
('de9c5f96-fa9e-4eab-938b-95b8d218a232','午坐卧治齋','楊萬里','宋','宋诗','song-poetry','','[]','雨後朝陰到午晴，空齋孤坐納秋清。',32,'全唐诗/poet.song.139000.json','["雨後朝陰到午晴，空齋孤坐納秋清。", "一蟬也解憐幽寂，柳外飛來葉底鳴。"]'),
('bde6a2dc-d488-429e-a0d9-04e97f3646e3','謝丁端叔直閣惠永嘉髹研句容香鬲','楊萬里','宋','宋诗','song-poetry','','[]','元珍先生茁雲孫，雪竹有節豹有文。',192,'全唐诗/poet.song.139000.json','["元珍先生茁雲孫，雪竹有節豹有文。", "染雲作句本天巧，鏤冰生花無手痕。", "鵷鷺行邊舊聯翼，天祿閣中今獨直。", "半竿淮水將渠歸，一笑荆溪豈人力。", "贈我阿泓非姓陶，木家居士漆園曹。", "急呼陳玄導黑水，花暈千層吹海濤。", "句容銅山擣金屑，幻出羽淵三足鼈。", "兩耳踰肩一腹皤，解吐黄雲香刮骨。", "雙珍投贈感故人，秃翁有筆今無神。", "杯水博詩元不直，醤瓿覆却那作嗔。", "阿泓處分蛛絲裹，延置銅君居上坐。", "煮茶剝芡對爐薰，遮莫白駒隙中過。"]'),
('31057086-b7cf-4203-881d-aef95093ddaf','檜逕曉步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','老檜陰陰夾古城，露叢迎貫日華明。',32,'全唐诗/poet.song.139000.json','["老檜陰陰夾古城，露叢迎貫日華明。", "曉涼無箇人分却，一逕深長獨自行。"]'),
('e92e18b6-8572-447e-953a-bf6cd99cace3','檜逕曉步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','雨歇林間涼自生，風穿逕裏曉逾清。',32,'全唐诗/poet.song.139000.json','["雨歇林間涼自生，風穿逕裏曉逾清。", "意行偶到無人處，驚起山禽我亦驚。"]'),
('ffa60fd9-888e-4622-8aa7-91c217d218d7','謝尤延之提舉郎中自山間惠訪長句','楊萬里','宋','宋诗','song-poetry','','[]','淮南使者郎官星，瑞光夜燭荆溪清。',192,'全唐诗/poet.song.139000.json','["淮南使者郎官星，瑞光夜燭荆溪清。", "平生龐公不入城，令我折却屐齒迎。", "交遊雲散別如雨，同舍諸郎半爲土。", "二老還將兩鬢霜，三更重對孤燈語。", "向來南宮綾錦堆，南窗北窗桃李開。", "先生誦詩舌起雷，一字不似人間來。", "剡藤染出梅花賦，句似梅花花似句。", "幾年金鑰秘銀鉤，玉𥫽不施恐飛去。", "秋風呼酒荷邊亭，主人自醉客自醒。", "儂能痛飲渠不飲，飲與不飲俱忘形。", "鬢今如霜心如水，功名一念扶不起。", "儂歸螺山渠惠山，來歲相思二千里。"]'),
('ab378e51-8ed0-4a50-a303-c44c84bfe502','小集食藕極嫩','楊萬里','宋','宋诗','song-poetry','','[]','比雪猶鬆在，無絲可得飄。',24,'全唐诗/poet.song.139000.json','["比雪猶鬆在，無絲可得飄。", "輕拈愁欲碎，未嚼已先銷。"]'),
('73a88d11-2e20-47a7-98b5-2033a67a4b0f','秋懷','楊萬里','宋','宋诗','song-poetry','','[]','隨分哦詩足散愁，老懷何用更冥搜。',64,'全唐诗/poet.song.139000.json','["隨分哦詩足散愁，老懷何用更冥搜。", "聿來胥宇蟻移穴，無以爲家燕入秋。", "蓋世功名吹劍首，平生憂患淅矛頭。", "從今歸去便歸去，未到無顔見白鷗。"]'),
('e097ad9e-eef1-423f-bd89-e15e833413f8','七月既望晚觀菱壕','楊萬里','宋','宋诗','song-poetry','','[]','官壕水落兩三痕，正是秋初雨後天。',32,'全唐诗/poet.song.139000.json','["官壕水落兩三痕，正是秋初雨後天。", "菱荇中間開一路，曉來誰過採菱船。"]'),
('f9ae17aa-d729-403d-8524-68c1af673070','新凉感興','楊萬里','宋','宋诗','song-poetry','','[]','初退生衣進熟衣，新涼只與睡相宜。',64,'全唐诗/poet.song.139000.json','["初退生衣進熟衣，新涼只與睡相宜。", "草爭人迹微疎處，荷怯秋風欲動時。", "又是一年將過眼，如何兩鬢不成絲。", "中元節後新來懶，草冊纔抄第二詩。"]'),
('db6f5fdf-2c2b-4924-b1f0-33501dd31582','七月二十五日曉登多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','風將煙雨入亭寒，城引山林拓眼寬。',32,'全唐诗/poet.song.139000.json','["風將煙雨入亭寒，城引山林拓眼寬。", "六月登臨渾覺熱，朝來不敢傍危欄。"]'),
('a0b85b0a-77b2-4faa-b913-352f8cd483c1','凝露堂木犀二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪花四出剪鵝黄，金屑千麩糝露囊。',32,'全唐诗/poet.song.139000.json','["雪花四出剪鵝黄，金屑千麩糝露囊。", "看去看來能幾大，如何著得許多香。"]'),
('8f0e7b27-c05d-4cd3-869e-2f2b0a261440','凝露堂木犀二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','夢騎白鳳上青空，徑度銀河入月宮。',32,'全唐诗/poet.song.139000.json','["夢騎白鳳上青空，徑度銀河入月宮。", "身在廣寒香世界，覺來簾外木犀風。"]'),
('5457c309-9cd8-4297-bd93-919ae0bc59dd','中秋前一夕携酒與子仁姪登多稼亭','楊萬里','宋','宋诗','song-poetry','','[]','月忽飛來墮我傍，我還飛入月中央。',64,'全唐诗/poet.song.139000.json','["月忽飛來墮我傍，我還飛入月中央。", "如何桂樹許多影，不隔冰輪些子光。", "自古中秋多苦事，非風即雨斷人腸。", "醉來不信寒欺酒，露濕杯盤凍作霜。"]'),
('9eaf1570-9c33-4ce6-9d11-fed12aa4ad15','觀蟻二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','偶爾相逢細問途，不知何事數遷居。',32,'全唐诗/poet.song.139000.json','["偶爾相逢細問途，不知何事數遷居。", "微軀所饌能多少，一獵歸來滿後車。"]'),
('a0eb6a7f-936b-4139-bd91-bef585c0606d','觀蟻二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','一騎初來隻又雙，全軍突出陣成行。',32,'全唐诗/poet.song.139000.json','["一騎初來隻又雙，全軍突出陣成行。", "策勳急報千夫長，渡水還爭一葦杭。"]'),
('fa561a1f-d4b0-4df8-b02f-51297098f704','中秋無月至十七日曉晴','楊萬里','宋','宋诗','song-poetry','','[]','劣到中秋雲便興，中秋過了却成晴。',64,'全唐诗/poet.song.139000.json','["劣到中秋雲便興，中秋過了却成晴。", "霧橫平野村村白，日上疎林葉葉明。", "歲事不應如許早，朝來已覺嫩寒生。", "春吟不似秋吟好，覓句新來分外清。"]'),
('7d4a2b4f-c147-4b18-b034-8432169ac64e','重九前五日再游翟園','楊萬里','宋','宋诗','song-poetry','','[]','翟園不到纔幾日，寒梢冷葉秋蕭瑟。',96,'全唐诗/poet.song.139000.json','["翟園不到纔幾日，寒梢冷葉秋蕭瑟。", "只有黄花數點明，上照青松下蒼石。", "記得春頭來此嬉，梅花太瘦杏花肥。", "巷南巷北皆春色，恰似吾人年少時。", "忽怪翟園如許老，園應笑我衰容早。", "來歲春光更一來，我衰依舊園還少。"]'),
('7bac962c-961e-4f8a-a821-cff98e78ea02','送子仁姪南歸二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','酒爲吾人綠，花知九日黄。',48,'全唐诗/poet.song.139000.json','["酒爲吾人綠，花知九日黄。", "風燈秋焰冷，霜雁夜聲忙。", "愛子文無對，嗟予老更狂。", "相分即相見，不待半年强。"]'),
('d055795b-25cb-4ba8-b8f8-d0983abef6cb','送子仁姪南歸二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','再歲來相款，三杯忽語離。',48,'全唐诗/poet.song.139000.json','["再歲來相款，三杯忽語離。", "忍將垂老淚，滴作送行詩。", "子去儂猶住，身留夢亦隨。", "南溪舊風月，千萬寄相思。"]'),
('f8124acd-bd22-43a4-8146-92ad96cdfc78','食老菱有感','楊萬里','宋','宋诗','song-poetry','','[]','幸自江湖可避人，懷珠韞玉冷無塵。',32,'全唐诗/poet.song.139000.json','["幸自江湖可避人，懷珠韞玉冷無塵。", "何須抵死露頭角，荇葉荷花老此身。"]'),
('79f1121c-58aa-4cba-96f2-a11a4cba365e','醉吟','楊萬里','宋','宋诗','song-poetry','','[]','古人亡，古人在，古人不在天應改。',128,'全唐诗/poet.song.139000.json','["古人亡，古人在，古人不在天應改。", "不留三句五句詩，安得千人萬人愛。", "今人只笑古人癡，古人笑君君不知。", "朝來暮去能幾許，葉落花開無盡時。", "人生須要印如斗，不道金槌控渠口。", "身前只解皺兩眉，身後還能更杯酒。", "李太白，阮嗣宗，當年誰不笑兩翁。", "萬古賢愚俱白骨，兩翁天地一清風。"]'),
('b4c19170-e451-4475-a32d-25b9698e0b42','和丁端叔菊花','楊萬里','宋','宋诗','song-poetry','','[]','忽忽還重九，匆匆又歲華。',24,'全唐诗/poet.song.139000.json','["忽忽還重九，匆匆又歲華。", "不妨將白髮，剩與插黄花。"]'),
('0e62e000-d204-493b-a130-cb90f8c246b6','懷山莊子仁姪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','危亭獨上忽徬徨，欠箇山莊墮我傍。',32,'全唐诗/poet.song.139000.json','["危亭獨上忽徬徨，欠箇山莊墮我傍。", "却是向來相聚日，老懷未解憶山莊。"]'),
('fbec8dcc-469d-49b8-b5b9-62fb88684f7a','懷山莊子仁姪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','吾家小阮未西歸，日日相從郡圃嬉。',32,'全唐诗/poet.song.139000.json','["吾家小阮未西歸，日日相從郡圃嬉。", "黄菊拒霜今笑我，先生也有獨來時。"]'),
('f2189086-eee4-4bfc-bcd9-c2e3a9587566','張子儀太社折送秋日海棠二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','新樣西風較劣些，重陽還放海棠花。',32,'全唐诗/poet.song.139000.json','["新樣西風較劣些，重陽還放海棠花。", "春紅更把秋霜洗，且道精神佳不佳。"]'),
('694deae5-5b1b-4d1f-be8d-59866d93ae8b','張子儀太社折送秋日海棠二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','木蕖籬菊總無光，秋色今年付海棠。',32,'全唐诗/poet.song.139000.json','["木蕖籬菊總無光，秋色今年付海棠。", "爲底夜深花不睡，翠紗袖上月和霜。"]'),
('b5b0d18f-e1ec-4864-b4a2-7896c1e026d6','晚登浄遠亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','重陽纔過便新寒，去歲如今暑尚殘。',32,'全唐诗/poet.song.139000.json','["重陽纔過便新寒，去歲如今暑尚殘。", "雲外雁來元不覺，一聲喚我舉頭看。"]'),
('5902cb0e-916c-4ab6-b0b1-de3f4094e9ad','晚登浄遠亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','簿書纔了晚衙催，且上高亭眼暫開。',32,'全唐诗/poet.song.139000.json','["簿書纔了晚衙催，且上高亭眼暫開。", "野鴨成羣忽驚起，定知城背有船來。"]'),
('1bdabe8e-2c10-4e66-97b8-c4db00c2aeee','黄菊','楊萬里','宋','宋诗','song-poetry','','[]','鶑樣衣裳錢樣裁，冷霜涼露濺秋埃。',32,'全唐诗/poet.song.139000.json','["鶑樣衣裳錢樣裁，冷霜涼露濺秋埃。", "比他紅紫開差晚，時節來時畢竟開。"]'),
('87f17da7-90c1-494c-a522-bae7f8f35c4d','曉登子城','楊萬里','宋','宋诗','song-poetry','','[]','鞋響新霜後，襟暄野日初。',48,'全唐诗/poet.song.139000.json','["鞋響新霜後，襟暄野日初。", "寒溪半灣落，遠樹一行疎。", "老矣端何苦，歸哉不願餘。", "終更猶半歲，作麽度居諸。"]'),
('e7d0135e-77aa-4030-96a2-9ddaca13defe','多稼亭前黄菊','楊萬里','宋','宋诗','song-poetry','','[]','危亭俯涼囿，落葉日夜深。',120,'全唐诗/poet.song.139000.json','["危亭俯涼囿，落葉日夜深。", "佳菊獨何爲，開花得我心。", "韻孤自無伴，香浄暗滿襟。", "根器受正色，非緣學黄金。", "獨違春光早，而俟秋寒侵。", "豈不愛凋年，坐令淹寸陰。", "奈此清苦操，媿入妍華林。", "向來朱碧叢，亦復悴斯今。", "清霜慘萬象，幽芳耿森森。", "持以壽君子，聊爾慰孤斟。"]'),
('86eead58-48e4-41e0-bc3b-6ea1ed86d9dc','促織','楊萬里','宋','宋诗','song-poetry','','[]','一聲能遣一人愁，終夕聲聲曉未休。',32,'全唐诗/poet.song.139000.json','["一聲能遣一人愁，終夕聲聲曉未休。", "不解繅絲替人織，强來出口促衣裘。"]'),
('5cf29b49-aeae-47a6-b2e7-d655cfd77da2','迓使客夜歸四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','去時岸樹日猶明，歸到州橋月已昇。',64,'全唐诗/poet.song.139000.json','["去時岸樹日猶明，歸到州橋月已昇。", "水與天爭一輪玉，市聲人語兩街燈。", "迎來送往鬚成雪，索筆題詩硯欲冰。", "浄洗紅塵煩碧酒，倦來不覺睡騰騰。"]'),
('d1a04a0b-799a-4cdd-ba40-8219e3be3b0a','迓使客夜歸四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','病後霜威不見饒，吟邊月色苦相撩。',64,'全唐诗/poet.song.139000.json','["病後霜威不見饒，吟邊月色苦相撩。", "重簾垂地寒猶入，畫燭無風影自摇。", "誰遣塵埃空老去，何曾鷗鷺不吾招。", "坐來已是愁無奈，草露蟲聲政寂寥。"]'),
('39572e33-1a86-4448-bf56-16e3f68528dd','迓使客夜歸四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','起視青天分外青，滿天一點更無星。',64,'全唐诗/poet.song.139000.json','["起視青天分外青，滿天一點更無星。", "忽驚平地化成水，乃是月華光滿庭。", "筆下何知有前輩，醉中未肯赦空瓶。", "兒曹夜誦何書冊，也遣先生細細聽。"]'),
('9588f025-7096-4431-92a3-f911cdb83f75','迓使客夜歸四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','病身已怯九秋涼，也復移樽下砌傍。',64,'全唐诗/poet.song.139000.json','["病身已怯九秋涼，也復移樽下砌傍。", "只愛杯中都是月，不知身上寸深霜。", "清愁舊覺天來遠，寒夜新添歲樣長。", "不是傍人俱欲睡，老人無睡亦何妨。"]'),
('d0496166-cea9-48b1-b3b0-461780b400ff','城頭秋望  其一','楊萬里','宋','宋诗','song-poetry','','[]','秋光好處頓胡床，旋喚茶甌淺著湯。',32,'全唐诗/poet.song.139000.json','["秋光好處頓胡床，旋喚茶甌淺著湯。", "隔樹漏天青破碎，驚風度竹碧匆忙。"]'),
('0d85bed7-7aa2-4aa9-8c77-14eb5b6b3db4','城頭秋望  其二','楊萬里','宋','宋诗','song-poetry','','[]','未得霜晴未是晴，霜晴無復點雲生。',32,'全唐诗/poet.song.139000.json','["未得霜晴未是晴，霜晴無復點雲生。", "鷺鷥不遣魚驚散，移却惟愁水作聲。"]'),
('e91827a9-a3f7-4812-91e3-3e1747d53207','生酒歌','楊萬里','宋','宋诗','song-poetry','','[]','生酒清於雪，煮酒赤如血，煮酒不如生酒烈。',84,'全唐诗/poet.song.139000.json','["生酒清於雪，煮酒赤如血，煮酒不如生酒烈。", "煮酒只带煙火氣，生酒不離泉石味。", "石根泉眼新汲將，麯米釀出春風香。", "坐上豬紅間熊白，甕頭鴨綠變鵝黄。", "先生一醉萬事已，那知身在塵埃裏。"]'),
('bb5a1945-4720-431a-9189-90332843c83b','夜雨','楊萬里','宋','宋诗','song-poetry','','[]','幽人睡正熟，不知江雨來。',144,'全唐诗/poet.song.139000.json','["幽人睡正熟，不知江雨來。", "驚風颯然起，聲若山嶽摧。", "起坐不復寐，萬感集老懷。", "憶年十四五，讀書松下齋。", "寒夜耿難曉，孤吟悄無儕。", "蟲語一燈寂，鬼啼萬山哀。", "雨聲正如此，壯心滴不灰。", "即今踰知命，已先十年衰。", "不知後此者，壯心肯更回。", "舊學日疏蕪，書冊久塵埃。", "聖處與天似，而我老相催。", "坐念慨未已，東窗晨光開。"]'),
('59949224-56df-4f20-8b3d-e3f5ff860360','芭蕉雨','楊萬里','宋','宋诗','song-poetry','','[]','芭蕉得雨便欣然，終夜作聲清更妍。',66,'全唐诗/poet.song.139000.json','["芭蕉得雨便欣然，終夜作聲清更妍。", "細聲巧學蠅觸紙，大聲鏘若山落泉。", "三點五點俱可聽，萬籟不生秋夕靜。", "芭蕉自喜人自愁，不如西風收却雨即休。"]'),
('d5cf3491-1037-4577-a617-1f3fa6175679','雨中懶困','楊萬里','宋','宋诗','song-poetry','','[]','城頭欲上苦新泥，暖氣薰人軟欲癡。',32,'全唐诗/poet.song.139000.json','["城頭欲上苦新泥，暖氣薰人軟欲癡。", "睡又不成行不是，强來看打洛神碑。"]'),
('aa692253-56b8-4676-894b-9563b576d262','胡達孝水墨妙絕一世爲余作枯松孫枝石間老柏謝以長句','楊萬里','宋','宋诗','song-poetry','','[]','東齋歸自浣花里，訪我弄泉惠山趾。',150,'全唐诗/poet.song.139000.json','["東齋歸自浣花里，訪我弄泉惠山趾。", "隨身萬里只孤舟，一簪不曾著行李。", "忽拈遠物出袖中，乃是孔明廟前古柏閬州松。", "徑從平地便起立，上穿屋瓦到青穹。", "老蛟脫鱗乾見骨，厥孫碧絲作鬚髮。", "石間霜皮二千尺，石似孤根根似石。", "硬根瘦榦未要論，葉間猶带漢唐春。", "歲久亦無苔蘚痕，只有雪山之雪玉壘雲。", "却收松柏半天裏，几上捲來一張紙。"]'),
('a413761b-1d14-4d03-ba78-a82767f01610','苦吟','楊萬里','宋','宋诗','song-poetry','','[]','蟻無秋衣雁有裘，霜天謀食各自愁。',64,'全唐诗/poet.song.139000.json','["蟻無秋衣雁有裘，霜天謀食各自愁。", "雁聲寒死叫不歇，蟻膝凍僵行復休。", "先生苦吟日色晚，老鈴來催喫朝飯。", "小兒誦書呼不來，案頭冷却黄虀麵。"]'),
('4815d75b-5766-40b3-8698-583703160bc9','晚衙野望','楊萬里','宋','宋诗','song-poetry','','[]','上却城來忘却歸，迎它來雁送它飛。',32,'全唐诗/poet.song.139000.json','["上却城來忘却歸，迎它來雁送它飛。", "可憐烏臼能緇素，却被清霜染作緋。"]'),
('83a8866d-1c87-4202-89d0-ea039015d761','毗陵郡齋追憶鄉味','楊萬里','宋','宋诗','song-poetry','','[]','坐無黄雀牛尾狸，荆溪日日思江西。',96,'全唐诗/poet.song.139000.json','["坐無黄雀牛尾狸，荆溪日日思江西。", "若無鵝梨與海錯，江西却恐思荆溪。", "舊居江西不自惜，到得荆溪却追憶。", "明年官滿歸江西，却憶荆溪難再得。", "江珍海錯各自奇，冬裘何曾羨夏絺。", "鵝梨黄雀無不可，荆溪江西不關我。"]'),
('b1076279-e890-4e62-88dd-7d33709205a6','和章漢直','楊萬里','宋','宋诗','song-poetry','','[]','宛水吹波解舫齋，南徐吊古上高臺。',64,'全唐诗/poet.song.139000.json','["宛水吹波解舫齋，南徐吊古上高臺。", "岸巾過我燈前語，贈句清於月底梅。", "對著酒船手持蟹，管渠秋井骨生苔。", "壁間挂舌那能許，一斗百篇真快哉。"]'),
('cc709839-a6eb-46c5-9798-6f93157bc2b8','曉坐卧治齋','楊萬里','宋','宋诗','song-poetry','','[]','夜風甚細不勝酸，霜落無聲只是寒。',32,'全唐诗/poet.song.139000.json','["夜風甚細不勝酸，霜落無聲只是寒。", "日上東窗無箇事，送將梅影索人看。"]'),
('d5832312-71e0-4418-8fe3-4e022de15654','行圃','楊萬里','宋','宋诗','song-poetry','','[]','飯罷來窺園，晴路忽流水。',96,'全唐诗/poet.song.139000.json','["飯罷來窺園，晴路忽流水。", "石子浄無塵，一一濕如洗。", "夜來元無雨，霜消痕尚爾。", "穉子有素約，杖屨從我戲。", "老夫偶獨先，穉子久不至。", "初心一何樂，中路慘不喜。", "悵望行復歇，回顧亦三四。", "行逢木蕖開，攀翻嗅霜蕊。"]'),
('87dbee47-d1a8-4aa2-8f20-e42481c42745','壕上','楊萬里','宋','宋诗','song-poetry','','[]','壕上朝來眼頓明，小風淺水寫秋清。',32,'全唐诗/poet.song.139000.json','["壕上朝來眼頓明，小風淺水寫秋清。", "新霜殺盡浮萍草，放出靴紋水面生。"]'),
('a9bdcb46-c979-40a5-8803-f83ed941b98a','白髮歎','楊萬里','宋','宋诗','song-poetry','','[]','素絲久即黑，黑鬢久即絲。',80,'全唐诗/poet.song.139000.json','["素絲久即黑，黑鬢久即絲。", "絲黑有浣法，鬢絲無染期。", "日月有底忙，晝夜馳向西。", "江漢與之反，却向東方馳。", "江漢西流日東落，鬢絲漆黑還如昨。", "夜長何不秉燭游，自是人生不行樂。"]'),
('71064fd1-8cbf-4196-ad69-493d137cfb3f','紅葉','楊萬里','宋','宋诗','song-poetry','','[]','詩人滿腹著清愁，吐作千詩未肯休。',32,'全唐诗/poet.song.139000.json','["詩人滿腹著清愁，吐作千詩未肯休。", "寫徧壁間無去處，却將紅葉强題秋。"]'),
('bde3247a-5b05-43a0-93dc-a637e8cbd254','送蔡定夫提舉正字使廣東','楊萬里','宋','宋诗','song-poetry','','[]','國朝以來妙人物，近世獨數乾道年。',296,'全唐诗/poet.song.139000.json','["國朝以來妙人物，近世獨數乾道年。", "后皇乃武再開闢，欲傾東海洗乾坤。", "九淵探珠巖採璞，天地爲綱罝羣賢。", "玉堂金鉉貯稷契，蓬山璧水俱崔班。", "追還慶曆元祐初，突過貞觀開元前。", "麟臺正字蔡夫子，乃祖元是四諫官。", "風流文采已碧梧，忠義慷慨仍青氈。", "折檻舊痕故無恙，后皇是日動龍顔。", "嚴霜烈日照鵷鷺，一身似葉飄淮堧。", "柴門僵卧三臘雪，魚釜僅續一線煙。", "后皇九重念五嶺，生愁雨露南方乾。", "詔謂正字當居中，肯爲朕行綏百蠻。", "梅花迎笑錦囊古，南斗退避文星寒。", "動摇山嶽細事耳，約束海若收波瀾。", "坐令百姓萬里外，墮在二陝三輔間。", "檳榔紅時芝泥紫，歸來徑著侍臣冠。", "我家江西更西處，白鷺洲對青原山。", "公歸肯訪老翁否，酤酒滿眼未必然，青芻白飯聊隨緣。"]'),
('755172ce-fe2c-4f5f-9a09-0eebad256a12','齋房戲題','楊萬里','宋','宋诗','song-poetry','','[]','長瓶舉我充自代，短檠留人爲莫逆。',80,'全唐诗/poet.song.139000.json','["長瓶舉我充自代，短檠留人爲莫逆。", "醉鄉無日不瓜時，書囿何朝無菜色。", "欲從舉者便彈冠，回顧石交難割席。", "子墨客卿善運籌，更問渠儂決去留。", "墨卿轉問子虛子，欲說還忘一笑休。"]'),
('a7c3c13e-3315-4266-9212-b2cedb3cc597','太平寺水郡人徐友畫清濟貫河','楊萬里','宋','宋诗','song-poetry','','[]','太平古寺劫灰餘，夕陽惟照一塔孤。',234,'全唐诗/poet.song.139000.json','["太平古寺劫灰餘，夕陽惟照一塔孤。", "得得來看還不樂，竹莖荒處破殿虛。", "偶逢老僧聽僧話，道是壁間留古畫。", "徐生絕筆今百年，祖師相傳妙天下。", "壁如雪色一丈許，徐生畫水纔盈堵。", "橫看側看只麽是，分明是畫不是水。", "中有清濟一線波，橫貫萬里濁浪之黄河。", "雷奔電卷儘渠猛，獨清元自不隨它。", "波痕盡處忽掀怒，攪動一河秋色暮。", "分明是水不是畫，老眼向來元自誤。", "佛廬化作金柁樓，銀山雪堆風打頭。", "是身飄然在中流，奪得太一蓮葉舟。", "僧言此畫難再覓，官歸江西却相憶。", "并州剪刀剪不得，鵝溪疋絹官莫惜，貌取秋濤懸坐側。"]'),
('8a3e661f-a1c5-444b-80e3-6962e8811335','水紋二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','池面尖風起，煙痕一拂微。',24,'全唐诗/poet.song.139000.json','["池面尖風起，煙痕一拂微。", "無形還有影，掠水去如飛。"]'),
('965f942c-63ef-4408-9e10-ca8773c664f9','水紋二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','初作眉頭皺，還成簟面斑。',24,'全唐诗/poet.song.139000.json','["初作眉頭皺，還成簟面斑。", "小風來不住，織遍一池間。"]'),
('b70ce70f-7d0b-4395-96aa-b83c858fa335','一鷺先立池中有雙鷺自外來先立者逐之雙鷺亟去莫敢敵者','楊萬里','宋','宋诗','song-poetry','','[]','鷺鷥各自有食邑，長恐諸侯客子來。',32,'全唐诗/poet.song.139000.json','["鷺鷥各自有食邑，長恐諸侯客子來。", "一鷺忽追雙鷺去，窮追盡處始飛回。"]'),
('49f3ea23-5bef-465d-9c10-8f12b38d0796','晚風寒林二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','已是霜林葉爛紅，那禁動地晚來風。',32,'全唐诗/poet.song.139000.json','["已是霜林葉爛紅，那禁動地晚來風。", "寒鴉可是矜渠黠，踏折枯梢不墮空。"]'),
('d858a3c2-963d-45b5-bead-d2d706182acd','晚風寒林二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','樹無一葉萬梢枯，活底秋江水墨圖。',32,'全唐诗/poet.song.139000.json','["樹無一葉萬梢枯，活底秋江水墨圖。", "幸自寒林俱淡筆，却將濃墨點栖烏。"]'),
('3bd56aa3-79a1-4b84-88a9-a33a52f6a3fd','霜夜無睡聞畫角孤雁二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','畫角聲從枕底鳴，愁霜怨月不堪聽。',32,'全唐诗/poet.song.139000.json','["畫角聲從枕底鳴，愁霜怨月不堪聽。", "擁紬起坐何人伴，只有殘燈半暈青。"]'),
('bd0c25e3-c650-4d74-9f25-6db010604f78','霜夜無睡聞畫角孤雁二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅邊玉琯月邊橫，吹落銀河與曉星。',32,'全唐诗/poet.song.139000.json','["梅邊玉琯月邊橫，吹落銀河與曉星。", "城裏萬家都睡著，孤鴻叫我起來聽。"]'),
('982a669f-421d-49b3-bc47-c368c463cfbd','飯罷登浄遠亭','楊萬里','宋','宋诗','song-poetry','','[]','今歲寒應少，冬深氣轉和。',48,'全唐诗/poet.song.139000.json','["今歲寒應少，冬深氣轉和。", "都緣徑差曲，添得步行多。", "柳色猶青在，霜威奈爾何。", "忽然雙野鴨，飛下一池波。"]'),
('ac11afd2-079e-4f32-b452-0295c87bb3ec','晴望','楊萬里','宋','宋诗','song-poetry','','[]','愁於望處一時銷，山亦霜前分外高。',32,'全唐诗/poet.song.139000.json','["愁於望處一時銷，山亦霜前分外高。", "枸杞一叢渾落盡，只殘紅乳似櫻桃。"]'),
('6266d7f0-97ad-4d69-9167-7001b8c39921','豫章王集大成惠我思古人實獲我心八詩謝以五字','楊萬里','宋','宋诗','song-poetry','','[]','孤嗜難衆悅，今聽非昔絃。',156,'全唐诗/poet.song.139000.json','["孤嗜難衆悅，今聽非昔絃。", "美人西山秀，蕨茹飲澗泉。", "雪蓑韞明月，冰棹刺野船。", "寶祲耿不掩，球聲忽復珊。", "聞者已瞠若，鬻之諒悠然。", "良瓌彼何憎，擊缶俗所便。", "老我詎能聰，妙音誤至前。", "古人子所思，而我豈古賢。", "借不滿子賞，能不聊子歎。", "故家富彥士，梧竹映芝蘭。", "紫餘乃祖橐，朱遍羣從轓。", "迅趾豈地行，逸翎當雲鶱。", "勗哉摶羊角，何必懷西山。"]'),
('a8b2417e-d80e-49fe-bd81-395504295c7e','不寐聽雨','楊萬里','宋','宋诗','song-poetry','','[]','雨到中宵寂不鳴，只聞風拂樹梢輕。',32,'全唐诗/poet.song.139000.json','["雨到中宵寂不鳴，只聞風拂樹梢輕。", "瓦溝收拾殘零水，併作簷間一滴聲。"]'),
('4be601de-6ef5-43d2-9385-b75ab830d54d','送張元直尉鹽官二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','璧水寒虀客，春闈擢桂郎。',48,'全唐诗/poet.song.139000.json','["璧水寒虀客，春闈擢桂郎。", "折腰端小耐，整翮未須忙。", "德進官無小，詩癯譽更香。", "會看兩鸂鶒，飛下蓼灘傍。"]'),
('7ef9bebe-914d-4766-8128-7c125d442563','送張元直尉鹽官二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','溧水孟東野，南昌梅子真。',48,'全唐诗/poet.song.139000.json','["溧水孟東野，南昌梅子真。", "平生一少府，千載兩高人。", "白馬松梢寺，朱旗雪外春。", "村行如得句，寄我大江濱。"]'),
('4118d0b3-6507-428a-94a8-be161cb68d8b','和胡運幹投贈','楊萬里','宋','宋诗','song-poetry','','[]','詩似離騷與國風，一襟塵土爲君空。',64,'全唐诗/poet.song.139000.json','["詩似離騷與國風，一襟塵土爲君空。", "來從月脇天心外，墮在冰甌雪椀中。", "判却青燈窮活計，早歸紫禁策元功。", "麴生未怕愁城峻，聊遣渠儂爲九攻。"]'),
('1b73d3be-1812-4b98-a1b8-70e0db08d3ab','夜雨獨覺','楊萬里','宋','宋诗','song-poetry','','[]','枕上還鄉枕上回，更更點點把人催。',64,'全唐诗/poet.song.139000.json','["枕上還鄉枕上回，更更點點把人催。", "雨將苔砌滴到曉，風揀荻簾疎處來。", "每到凋年每多感，不教睡眼不曾開。", "來宵我識華胥路，莫近茶甌近酒杯。"]'),
('d7091da2-0c16-41db-922e-3519571bb03d','夜聞風聲','楊萬里','宋','宋诗','song-poetry','','[]','作寒作暑無處避，開花落花儘他意。',64,'全唐诗/poet.song.139000.json','["作寒作暑無處避，開花落花儘他意。", "只有夜聲殊可憎，偏攪愁人五更睡。", "幸自無形那有聲，無端樹子替渠鳴。", "斫盡老槐與枯柳，更看渠儂作麽生。"]'),
('8b857179-b291-49c7-b53b-556f165c6585','詠齏','楊萬里','宋','宋诗','song-poetry','','[]','庾郎晚菘翡翠茸，金城土酥玉雪容。',122,'全唐诗/poet.song.139000.json','["庾郎晚菘翡翠茸，金城土酥玉雪容。", "如何俱墮瑶甕中，却與醯雞同閟宮。", "金井銀床水清泚，雪山冰谷鹽輕脆。", "秋風一月釀得成，字曰受辛非麴生。", "太學儒生朝復暮，茹冷啜寒那可度。", "十年雪汁凍蔬腸，一夜饑雷聽更鼓。", "不如甕頭吏部甕頭醒，一逢受辛還一醒，畢卓與爾同死生。"]'),
('c8f60750-cfa8-4251-a34c-577b4603c644','鱟醤','楊萬里','宋','宋诗','song-poetry','','[]','忽有瓶罌至，捲將江海來。',48,'全唐诗/poet.song.139000.json','["忽有瓶罌至，捲將江海來。", "玄霜凍龜殻，紅霧染珠胎。", "魚鮓兼蝦鮓，奴才更婢才。", "平章堪一飯，斷送更三杯。"]'),
('5d4ba986-ab0d-42e8-8ea8-d77a59655a8f','池冰二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','池底枯荷瘦不勝，池冰新琢玉壺凝。',32,'全唐诗/poet.song.139000.json','["池底枯荷瘦不勝，池冰新琢玉壺凝。", "如何留到炎蒸日，上有荷花下有冰。"]'),
('f05c5d04-994e-4841-8a8b-3983542d3c49','池冰二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','怕寒不敢上高臺，上得高臺急急回。',32,'全唐诗/poet.song.139000.json','["怕寒不敢上高臺，上得高臺急急回。", "日欲消冰風不允，天猶未夕月先來。"]'),
('39adb4fd-2175-4919-89ab-87b8e2f3ee96','節日新晴歸自天慶','楊萬里','宋','宋诗','song-poetry','','[]','初日明雁腹，酸風迎馬頭。',48,'全唐诗/poet.song.139000.json','["初日明雁腹，酸風迎馬頭。", "如何一雨過，添却滿城秋。", "樓觀色俱喜，槐榆影獨愁。", "節中公事少，吏散得吾休。"]'),
('c28efd92-376f-4f98-ac18-2e705d03d48b','城上野步用轆轤體','楊萬里','宋','宋诗','song-poetry','','[]','寒勁無遺暖，晴行失老懷。',48,'全唐诗/poet.song.139000.json','["寒勁無遺暖，晴行失老懷。", "葉飛楓骨立，萍盡沼奩開。", "路好仍回首，泥殘敢放鞋。", "登臨不須盡，留眼要重來。"]'),
('dcf57860-a9b2-47f7-a897-4627fade36e5','晴眺','楊萬里','宋','宋诗','song-poetry','','[]','野意隨宜有，山光入望無。',48,'全唐诗/poet.song.139000.json','["野意隨宜有，山光入望無。", "寒曦不自暖，落木幾曾枯。", "不分霜前樹，長啼月下烏。", "苦吟徐便悔，可惜數莖鬚。"]'),
('4c4f2adc-a862-4dd0-b1c0-244ac153fd50','霜曉','楊萬里','宋','宋诗','song-poetry','','[]','霜重曉未覺，日高融始寒。',24,'全唐诗/poet.song.139000.json','["霜重曉未覺，日高融始寒。", "空牆半根濕，落葉片聲乾。"]'),
('efbe0cb6-3354-4475-8342-01af998e3d74','晚興','楊萬里','宋','宋诗','song-poetry','','[]','老來懷抱向誰開，歲晚無花薦一杯。',64,'全唐诗/poet.song.139000.json','["老來懷抱向誰開，歲晚無花薦一杯。", "處分新霜且留菊，辟差寒日早開梅。", "只教詩句清如雪，看得榮名細似埃。", "管葛諸人端解事，也曾遭我笑渠來。"]'),
('fdc1dcb5-72dd-4d6f-ae3d-436bc01f1403','暮寒','楊萬里','宋','宋诗','song-poetry','','[]','過雁雙仍急，寒鴉隻已多。',48,'全唐诗/poet.song.139000.json','["過雁雙仍急，寒鴉隻已多。", "絕憐晴色好，無奈暮寒何。", "眼病書休讀，心勞句尚哦。", "老生窮事業，此外豈無他。"]'),
('3d947bfe-6677-474a-8a68-313e370a9597','酒蛤蜊','楊萬里','宋','宋诗','song-poetry','','[]','飲者憐渠有典刑，見渠借箸眼偏青。',32,'全唐诗/poet.song.139000.json','["飲者憐渠有典刑，見渠借箸眼偏青。", "平生閉口不論事，晚歲搜腸求獨醒。"]'),
('92c500cb-9a80-410c-8569-91433b1b0453','蒲桃乾','楊萬里','宋','宋诗','song-poetry','','[]','涼州博酒不勝癡，銀漢乘槎領得歸。',32,'全唐诗/poet.song.139000.json','["涼州博酒不勝癡，銀漢乘槎領得歸。", "玉骨瘦來無一把，向來馬乳太輕肥。"]'),
('9f0639cc-3795-47aa-aaad-2dce0cf85031','梨','楊萬里','宋','宋诗','song-poetry','','[]','掛冠大谷肯干時，飣坐風流特地奇。',64,'全唐诗/poet.song.139000.json','["掛冠大谷肯干時，飣坐風流特地奇。", "骨裏馨香衣不隔，胸中冰雪齒偏知。", "賣漿碎搗瓊爲汁，解甲方憐玉作肌。", "老子醉來渾謝客，見渠倒屣只嫌遲。"]'),
('9bf979a0-c422-4f3d-ac8e-b6bad6d3a493','蠟燭','楊萬里','宋','宋诗','song-poetry','','[]','未夜身先卧，不春花已開。',24,'全唐诗/poet.song.139000.json','["未夜身先卧，不春花已開。", "泣殘雙淚雨，愁得寸心灰。"]'),
('e00a4f53-4353-49d7-ae7c-759ea4cb745b','小立浄遠亭','楊萬里','宋','宋诗','song-poetry','','[]','清景無終極，頻來未屬厭。',24,'全唐诗/poet.song.139000.json','["清景無終極，頻來未屬厭。", "遠山秋後出，茅屋近來添。"]'),
('73a50d1b-ce2b-4ec0-81b5-4d8c3bb79fb5','新晴曉步','楊萬里','宋','宋诗','song-poetry','','[]','冬來暮暮雨絲絲，竹徑梅坡迹頓稀。',32,'全唐诗/poet.song.139000.json','["冬來暮暮雨絲絲，竹徑梅坡迹頓稀。", "作意新晴聊一出，行逢濕路却成歸。"]'),
('f48cf705-07b5-4090-958a-a24d1ce38052','探梅','楊萬里','宋','宋诗','song-poetry','','[]','春傍梅梢瘦處回，小花未忍折將來。',32,'全唐诗/poet.song.139000.json','["春傍梅梢瘦處回，小花未忍折將來。", "却緣久住成幽事，剩看南枝一度開。"]'),
('19a8d746-0ae5-4b92-88e0-454bda759ae2','和王司法雨中惠詩二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','絕憐法曹三尺喙，不辦太倉五升米。',128,'全唐诗/poet.song.139000.json','["絕憐法曹三尺喙，不辦太倉五升米。", "胡奴走送今寂然，公路如何令至此。", "春花秋月千首詩，一字不曾堪療饑。", "黄獨已空鑱底用，玉徽凍脫琴爲炊。", "窮鬼偏隨天下士，再結柳車君但試。", "不應滿腹貯六奇，豈有逐貧無一計。", "詩中哀怨海樣深，青燈搔首夜沉沉。", "一尊往慰風雨晚，莫管带圍寬一眼。"]'),
('53fa2650-7e9d-426e-8c5c-836847bc2089','和王司法雨中惠詩二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','無那詩愁著莫人，風顛雨急更昏昏。',64,'全唐诗/poet.song.139000.json','["無那詩愁著莫人，風顛雨急更昏昏。", "登臨無地可散策，剝啄阿誰來叩門。", "安得與渠呼玉酒，醉餘同看落金盆。", "齋厨索寞如懸罄，慚媿酸寒遣一尊。"]'),
('e49b558d-6a1e-4d8f-8411-16109e35656e','惠泉酒熟','楊萬里','宋','宋诗','song-poetry','','[]','敲冰汲山泉，炊玉釀霜醅。',96,'全唐诗/poet.song.139000.json','["敲冰汲山泉，炊玉釀霜醅。", "忽然油成泓，失却瓊作堆。", "抱甕輸竹渠，挈瓶注銀杯。", "銀杯不解飲，傾瀉入我懷。", "酒聖凡五傳，道統到吾儕。", "誰云孟氏醇，軻死不傳來。", "醉鄉天張幕，糟丘麴爲臺。", "吾欲往相宅，今夕未擬回。"]'),
('5ae2df97-d2be-4ccf-b2c0-103880b3fa90','晝倦','楊萬里','宋','宋诗','song-poetry','','[]','愛日曛人欲睡昏，自勻嫩火炷爐薰。',32,'全唐诗/poet.song.139000.json','["愛日曛人欲睡昏，自勻嫩火炷爐薰。", "蜘蛛已去惟存網，猶罥窗間一隻蚊。"]'),
('871954a1-47bb-4a11-ad6c-221e03c77ec3','戲題水墨山水屏','楊萬里','宋','宋诗','song-poetry','','[]','櫂郎大似半邊蠅，摘蕙爲船折草撐。',32,'全唐诗/poet.song.139000.json','["櫂郎大似半邊蠅，摘蕙爲船折草撐。", "今夜不知何處泊，浪頭正與嶺頭平。"]'),
('2cd0ea86-3eb5-416e-9c38-00de6aa6bf64','以糟蟹洞庭甘送丁端叔端叔有詩因和其韻','楊萬里','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','斗州只解寄鵝毛，鼎肉何曾饋百牢。',64,'全唐诗/poet.song.139000.json','["斗州只解寄鵝毛，鼎肉何曾饋百牢。", "驅使木奴供露顆，催科郭索獻霜螯。", "鄉封萬戶只名醉，天作一丘都是糟。", "却被新詩太清絕，喚將雪虐更風饕。"]'),
('92ed007b-482f-437e-92ed-27c0090dfe2c','曉坐','楊萬里','宋','宋诗','song-poetry','','[]','拂曉文書已罷休，却披詩卷散閑愁。',32,'全唐诗/poet.song.139000.json','["拂曉文書已罷休，却披詩卷散閑愁。", "只驚兩眼生光彩，日到東窗半角頭。"]'),
('e96e1cd7-5b41-46c3-b0c6-75a2bb67447f','凍蠅','楊萬里','宋','宋诗','song-poetry','','[]','隔窗偶見負暄蠅，雙脚挼挲弄曉晴。',32,'全唐诗/poet.song.139000.json','["隔窗偶見負暄蠅，雙脚挼挲弄曉晴。", "日影欲移先會得，忽然飛落別窗聲。"]'),
('23922093-0af9-48af-81db-e3165716c8e7','壕上書事','楊萬里','宋','宋诗','song-poetry','','[]','十里長壕展碧漪，波痕只去不曾歸。',32,'全唐诗/poet.song.139000.json','["十里長壕展碧漪，波痕只去不曾歸。", "鷺鷥已飽渾無幹，獨立朝陽理雪衣。"]'),
('e18c427c-c346-43dc-9b00-29d93dfe31f0','霜','楊萬里','宋','宋诗','song-poetry','','[]','天欲吹霜不作難，連宵也費許多寒。',32,'全唐诗/poet.song.139000.json','["天欲吹霜不作難，連宵也費許多寒。", "新裝瓊甲爲蔬甲，仍化朱欄作玉欄。"]'),
('7ed71d1d-462a-4f7a-82be-9d0b0a88e3ec','冬至前三日','楊萬里','宋','宋诗','song-poetry','','[]','故山千里幾時回，又見初陽動琯灰。',32,'全唐诗/poet.song.139000.json','["故山千里幾時回，又見初陽動琯灰。", "酒不逢人還易醉，詩如得句偶然來。"]'),
('12086a9f-b052-4366-be8e-ecb8a0cc016f','鴉','楊萬里','宋','宋诗','song-poetry','','[]','穉子相看只笑渠，老夫亦復小盧胡。',32,'全唐诗/poet.song.139000.json','["穉子相看只笑渠，老夫亦復小盧胡。", "一鴉飛立鈎欄角，子細看來還有鬚。"]'),
('43466851-0cd2-40f2-8a91-2e322205e50b','朝飯罷登浄遠亭','楊萬里','宋','宋诗','song-poetry','','[]','近水孤亭迥，縈城一徑斜。',48,'全唐诗/poet.song.139000.json','["近水孤亭迥，縈城一徑斜。", "霜林烏鵲國，冰岸鷺鷥家。", "殊覺冬曦暖，還拈小扇遮。", "傳呼惠山水，來瀹建溪茶。"]'),
('d19eb08b-63eb-41ee-9cc7-d19b0345d326','近節','楊萬里','宋','宋诗','song-poetry','','[]','節裏非無事，忙中自有閑。',48,'全唐诗/poet.song.139000.json','["節裏非無事，忙中自有閑。", "因風煩白鳥，折簡喚青山。", "詩卷一兩冊，齋房三四間。", "興來長得句，却道在塵寰。"]'),
('d227479d-ae82-4ba9-85f7-6eedbeced4b0','冬至日歸自天慶觀二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','逗曉清寒未苦嚴，輕霜隨分點茅簷。',32,'全唐诗/poet.song.139000.json','["逗曉清寒未苦嚴，輕霜隨分點茅簷。", "霧中失却溪邊寺，不見浮屠只見尖。"]'),
('3178f2be-73a1-4065-a891-2e906683365e','冬至日歸自天慶觀二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','節裏人家笑語饒，日高猶自燭光交。',32,'全唐诗/poet.song.139000.json','["節裏人家笑語饒，日高猶自燭光交。", "霜林遮眼八九葉，露竹出牆三四梢。"]'),
('32178f4b-8fb9-4a38-be77-2d3d9fc72511','蠟梅','楊萬里','宋','宋诗','song-poetry','','[]','栗玉圓彫蕾，金鍾細著行。',48,'全唐诗/poet.song.139000.json','["栗玉圓彫蕾，金鍾細著行。", "來從真蠟國，自號小黄香。", "夕吹撩寒馥，晨曦透暖光。", "南枝本同姓，喚我作它楊。"]'),
('be70df1d-b7a4-45f8-bb66-1f05bcf705b5','蠟梅四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','蜜蜂底物是生涯，花作餱糧蠟作家。',32,'全唐诗/poet.song.139000.json','["蜜蜂底物是生涯，花作餱糧蠟作家。", "歲晚略無花可採，却將香蠟吐成花。"]'),
('b9e851ce-a3c4-491d-b83e-d55b17ada397','蠟梅四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','眉間蜜酒發輕黄，對著詩人不惜香。',32,'全唐诗/poet.song.139000.json','["眉間蜜酒發輕黄，對著詩人不惜香。", "金作仙衣元自冷，月中仍带一身霜。"]'),
('f60f6e3a-0fe7-4e63-b673-f4328396fe80','蠟梅四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','莟頭元不是花房，融蠟熬酥戲滴將。',32,'全唐诗/poet.song.139000.json','["莟頭元不是花房，融蠟熬酥戲滴將。", "忽見微舒金爪甲，不知中有紫香囊。"]'),
('1db01d34-21c8-4396-a08d-28d55a38a8fb','蠟梅四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','江梅珍重雪衣裳，薄相紅梅學杏裝。',32,'全唐诗/poet.song.139000.json','["江梅珍重雪衣裳，薄相紅梅學杏裝。", "渠獨小參黄面老，額間艷艷發金光。"]'),
('19bbc2e7-a7f4-4e55-875d-197e9c4815d2','霜塞轆轤體二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','滴地酒成凍，喧天鴉訴寒。',48,'全唐诗/poet.song.139000.json','["滴地酒成凍，喧天鴉訴寒。", "窗風經怒響，簾日漏溫痕。", "偶爾尋梅去，其如駐屐難。", "沙鷗脚不襪，故故踏冰翻。"]'),
('493c6a46-38f5-4ade-a7d4-b24c59049b4a','霜塞轆轤體二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','今曉難離火，平生不擁爐。',48,'全唐诗/poet.song.139000.json','["今曉難離火，平生不擁爐。", "只緣青女降，便與管城疎。", "淡日明還暗，微暄有似無。", "誰能忍寒得，苦死去看書。"]'),
('647fdf09-5224-4d59-93c3-4398ff3f3144','苦寒三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','畏暑長思雪繞身，苦寒却願柳回春。',32,'全唐诗/poet.song.139000.json','["畏暑長思雪繞身，苦寒却願柳回春。", "晚來斜日無多暖，映著西窗亦可人。"]'),
('7865b90b-b436-4cc8-bf1b-3909e8a539ff','苦寒三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','添盡紅爐著盡衣，一杯方覺暖如癡。',32,'全唐诗/poet.song.139000.json','["添盡紅爐著盡衣，一杯方覺暖如癡。", "人言霜後寒無奈，春在甕中渠不知。"]'),
('a6cc7696-67e6-4059-8483-a65f44a0268a','苦寒三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','冰和菜把菜和冰，心喜冬葅齒却憎。',32,'全唐诗/poet.song.139000.json','["冰和菜把菜和冰，心喜冬葅齒却憎。", "且忍牙車寒一點，教他胸次雪千層。"]'),
('c3815b93-4274-426c-a863-270571ed45a9','晚晴獨酌二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','冷落杯盤下箸稀，今年淮白較來遲。',32,'全唐诗/poet.song.139000.json','["冷落杯盤下箸稀，今年淮白較來遲。", "異鄉黄雀真無價，稍暖瓊酥不得時。"]'),
('5adf0e0a-ba18-448e-a1e4-4ea24f52c606','晚晴獨酌二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','霜熟寒輕際晚時，簾間過影一鴉歸。',32,'全唐诗/poet.song.139000.json','["霜熟寒輕際晚時，簾間過影一鴉歸。", "夕陽端與誰爲地，只照游塵絮樣飛。"]'),
('a41273bb-aeee-44bc-a6d2-2ed1ea7a4a4d','城頭曉步二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','古城秋後不勝荒，人跡新行一逕長。',32,'全唐诗/poet.song.139000.json','["古城秋後不勝荒，人跡新行一逕長。", "竹影已摇將午日，草根猶有夜來霜。"]'),
('34ac459d-8909-48a5-9394-737b0bf94d7c','城頭曉步二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','城東行遍却城西，欲問梅花乞一枝。',32,'全唐诗/poet.song.139000.json','["城東行遍却城西，欲問梅花乞一枝。", "雪糝久團霜後朶，嗔人頻看故開遲。"]'),
('319c81af-29bd-4c86-b73e-218b853cc406','送丁牧仲新除奉常寺簿入朝','楊萬里','宋','宋诗','song-poetry','','[]','帝念潜龍雪邸臣，寵光玉樹照青春。',64,'全唐诗/poet.song.139000.json','["帝念潜龍雪邸臣，寵光玉樹照青春。", "家藏履舄星辰舊，天借旂常日月新。", "從此雲霄君穩步，向來鵷鷺我曾鄰。", "曲臺簿正多廊廟，西府璇樞是一人。"]'),
('0b2927f1-0fb2-49aa-836a-2a10504bff78','贈節推學士','楊萬里','宋','宋诗','song-poetry','','[]','奏篇驚倒漢廷臣，一眼元無四海人。',64,'全唐诗/poet.song.139000.json','["奏篇驚倒漢廷臣，一眼元無四海人。", "天下無雙聊小却，洛陽年少是前身。", "雲鵬飛上偏嫌早，霧豹深藏更幾春。", "寬作十年相見著，剩將風雪試松筠。"]'),
('df53a8ae-95b0-469d-ad2c-853ef3ddad3a','懷古堂前小梅漸開四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','梅邊春意未全回，淡日微風暗裏催。',64,'全唐诗/poet.song.139000.json','["梅邊春意未全回，淡日微風暗裏催。", "近水數株殊小在，一梢雙朶忽齊開。", "生愁落去輕輕折，不怕清寒得得來。", "腸斷故園千樹雪，大江西處亂雲堆。"]'),
('3a72f83b-2da8-4cd5-9d84-195e30e8ed7f','懷古堂前小梅漸開四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','隨意行穿翠篠林，暗香撩我獨關心。',64,'全唐诗/poet.song.139000.json','["隨意行穿翠篠林，暗香撩我獨關心。", "遥看小朶不勝好，走近寒梢無處尋。", "未吐誰知膚底雪，半開猶護蕊頭金。", "老來嬾去渾無緒，奈此南枝索苦吟。"]'),
('41c3a483-2cb5-4927-934f-040055ceb4da','懷古堂前小梅漸開四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','絕艷元非著粉團，真香亦不在鬚端。',64,'全唐诗/poet.song.139000.json','["絕艷元非著粉團，真香亦不在鬚端。", "何曾天上冰玉質，却怕人間霜雪寒。", "枝似去年仍轉瘦，花於來歲定誰看。", "老夫官滿梅應熟，齒軟猶禁半點酸。"]'),
('b1c60bfb-97e9-4c9c-a74e-d893598aafe8','懷古堂前小梅漸開四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','揀得疎花折得回，銀瓶冰水養教開。',64,'全唐诗/poet.song.139000.json','["揀得疎花折得回，銀瓶冰水養教開。", "忽然燈下數枝影，喚作窗間一樹梅。", "歲律又殘還見此，我頭自白不須催。", "相看姑置人間事，嚼玉餐香嚥一杯。"]'),
('602df1cf-df04-4dce-8135-cd007ada7c7a','雪中登浄遠亭四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','犯雪來登浄遠亭，飛花著水旋成冰。',32,'全唐诗/poet.song.139000.json','["犯雪來登浄遠亭，飛花著水旋成冰。", "瓊田萬頃珠千樹，真在瑶臺十二層。"]'),
('f27c9cc5-3ed6-4cce-8e61-5d0be02265fb','雪中登浄遠亭四首  其二','楊萬里','宋','宋诗','song-poetry','','[]','數片初飛點砌苔，須臾不覺玉千堆。',32,'全唐诗/poet.song.139000.json','["數片初飛點砌苔，須臾不覺玉千堆。", "去年無雪非無雪，留作今年一併來。"]'),
('5fad9e16-097f-4f06-9ba1-270340ac4287','雪中登浄遠亭四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','壕水深清一鏡如，天傾瑶屑打成酥。',32,'全唐诗/poet.song.139000.json','["壕水深清一鏡如，天傾瑶屑打成酥。", "瑠璃缸面熬瓊粥，釀出珠宮白玉腴。"]'),
('639c9d3c-c025-4d24-9d02-a62bad2161c5','雪中登浄遠亭四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','忍却清寒得得來，不堪騎吏苦相催。',32,'全唐诗/poet.song.139000.json','["忍却清寒得得來，不堪騎吏苦相催。", "雁穿銀色界中去，人到水晶宮裏回。"]'),
('59b7a248-b746-4b44-b975-4cd27e949a79','和趙鼎輔府判投贈賀雪之句','楊萬里','宋','宋诗','song-poetry','','[]','登城放目雪光中，萬水千山一色同。',64,'全唐诗/poet.song.139000.json','["登城放目雪光中，萬水千山一色同。", "逗曉月華猶在地，未春柳絮已隨風。", "忽傳別駕贈佳句，道是頻年當屢豐。", "撚斷冰鬚愁寡和，玉花飛繞正濛濛。"]'),
('b9809f0c-0ca0-485b-9030-28639a715b13','觀雪二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','銀屋瑶階頃刻成，緩飄急灑總無聲。',64,'全唐诗/poet.song.139000.json','["銀屋瑶階頃刻成，緩飄急灑總無聲。", "屑雲作粉如何濕，琱玉爲花乃爾輕。", "空裏仰看元不見，日光未透不妨晴。", "滿庭更遣遲銷著，剩借書窗幾夜明。"]'),
('affbefa4-2a37-4d24-bd7b-8e2e1a582422','觀雪二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','坐看深來尺許强，偏於薄暮發寒光。',64,'全唐诗/poet.song.139000.json','["坐看深來尺許强，偏於薄暮發寒光。", "半空舞倦居然嬾，一點風來特地忙。", "落盡瓊花天不惜，封它梅蕊玉無香。", "倩誰細撚成湯餠，換却人間煙火腸。"]'),
('7f087f4e-8f21-46e5-86c4-70a484af5db8','和吳寺丞喜雪','楊萬里','宋','宋诗','song-poetry','','[]','珠唾銀鉤贈一通，炯如密雪墮寒空。',64,'全唐诗/poet.song.139000.json','["珠唾銀鉤贈一通，炯如密雪墮寒空。", "飛來數片不霑袖，剪出六花全是風。", "骨冷魂清殘醉裏，日光玉潔晚晴中。", "先生秀句今無敵，誰誦相如奏舜瞳。"]'),
('b879fd84-aa6f-4f87-8506-22d94f6a5832','雪晴','楊萬里','宋','宋诗','song-poetry','','[]','銀色三千界，瑶林一萬重。',48,'全唐诗/poet.song.139000.json','["銀色三千界，瑶林一萬重。", "新晴天嫩綠，落照雪輕紅。", "兒劣敲冰柱，身清墮蕊宮。", "何須師鮑謝，詩在玉虛中。"]'),
('d8fe3e85-c30d-48f8-b130-abdcc1fff08a','晴後雪凍','楊萬里','宋','宋诗','song-poetry','','[]','負暄尚覺日無功，炙手仍愁火失紅。',64,'全唐诗/poet.song.139000.json','["負暄尚覺日無功，炙手仍愁火失紅。", "本是雪前風作雪，却緣雪後雪生風。", "四郊凍合如相約，七日晴來不肯融。", "舊說醉鄉堪避暑，避寒也合此鄉中。"]'),
('b688d88d-54a7-4a35-9bb9-f5ec6f2f2327','和丁端叔喜雪','楊萬里','宋','宋诗','song-poetry','','[]','天將一雪浄乾坤，便恐湯泉亦不溫。',64,'全唐诗/poet.song.139000.json','["天將一雪浄乾坤，便恐湯泉亦不溫。", "瑶草忽生無種子，梅花寒損要溫存。", "清游未到先回棹，高卧何如且閉門。", "珍重故人貽妙語，追還正始最初元。"]'),
('45c0db1e-5de7-4fe5-92e1-27608b589731','雪凍未解散策郡圃','楊萬里','宋','宋诗','song-poetry','','[]','積雪偏工霽後凝，不妨冷極不妨清。',64,'全唐诗/poet.song.139000.json','["積雪偏工霽後凝，不妨冷極不妨清。", "靜聞簷滴元無雨，倒挂冰牙未怕晴。", "獨往獨來銀粟地，一行一步玉沙聲。", "圃中散策饒君强，敢犯霜風上古城。"]'),
('08b831c9-fc6d-4971-b693-79a5a8f27524','雪後十日日暖雪猶未融','楊萬里','宋','宋诗','song-poetry','','[]','地凍雪起立，簷生冰倒垂。',48,'全唐诗/poet.song.139000.json','["地凍雪起立，簷生冰倒垂。", "日穿銀笋透，風琢玉山欹。", "今曉還差暖，清寒退尚遲。", "生愁便銷去，將底伴吟髭。"]'),
('42a004af-6e02-4c43-83e7-03c5f4d5f27d','殘雪','楊萬里','宋','宋诗','song-poetry','','[]','殘雪堆成山數重，懸崖幽竇玉玲瓏。',32,'全唐诗/poet.song.139000.json','["殘雪堆成山數重，懸崖幽竇玉玲瓏。", "如何借得仙人掌，擎取瓊瑶三四峰。"]'),
('df06893a-df78-4ef7-8052-35cb5d1615ce','多稼亭日色甚暖忽有雪數片自晴空而下已而復無','楊萬里','宋','宋诗','song-poetry','','[]','霽日何曾惹寸雲，忽飛些子雪如塵。',32,'全唐诗/poet.song.139000.json','["霽日何曾惹寸雲，忽飛些子雪如塵。", "不知底處天花落，風裏吹來數點春。"]'),
('51191bea-83b7-4414-b523-0ef38cf70ad2','兒啼索飯','楊萬里','宋','宋诗','song-poetry','','[]','飽暖君恩豈不知，小兒窮慣只長饑。',32,'全唐诗/poet.song.139000.json','["飽暖君恩豈不知，小兒窮慣只長饑。", "朝朝聽得兒啼處，正是炊粱欲熟時。"]'),
('78a84c81-8b28-4c05-91d2-fd0c837cb147','寒雀','楊萬里','宋','宋诗','song-poetry','','[]','百千寒雀下空庭，小集梅梢話晚晴。',32,'全唐诗/poet.song.139000.json','["百千寒雀下空庭，小集梅梢話晚晴。", "特地作團喧殺我，忽然驚散寂無聲。"]'),
('ba3c97e3-f3f5-4ad6-b435-0dbd4dbb4044','晚眺','楊萬里','宋','宋诗','song-poetry','','[]','晚暖好登臨，吾衰也不禁。',24,'全唐诗/poet.song.139000.json','["晚暖好登臨，吾衰也不禁。", "雪殘千嶂玉，日落萬梢金。"]'),
('41397d77-15e8-43ce-b70e-dd4417e9938b','雪夜候迎使客','楊萬里','宋','宋诗','song-poetry','','[]','六花不放一塵生，晴後猶餘十日凝。',64,'全唐诗/poet.song.139000.json','["六花不放一塵生，晴後猶餘十日凝。", "新月未光輸與雪，夜風儘冷只留冰。", "候迎銀漢槎頭客，挑盡玉蟲窗下燈。", "紙帳蒲團地爐煖，自憐不及草庵僧。"]'),
('8a034c15-6490-4ab7-8246-cd01d660b598','燭下梅花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','燭下一枝梅，欲開猶未開。',24,'全唐诗/poet.song.139000.json','["燭下一枝梅，欲開猶未開。", "渾如玉冠子，戴月上瓊臺。"]'),
('1653b954-d698-4c50-b717-2f747678d6c6','燭下梅花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','窗外雪猶凍，瓶中梅不開。',24,'全唐诗/poet.song.139000.json','["窗外雪猶凍，瓶中梅不開。", "燭花將暖氣，催得早春回。"]'),
('55d80be1-91f7-4144-be36-8557736d5291','燭下瓶中江蠟二梅','楊萬里','宋','宋诗','song-poetry','','[]','江梅蠟梅同日折，白晝看來兩清絕。',32,'全唐诗/poet.song.139000.json','["江梅蠟梅同日折，白晝看來兩清絕。", "如何對立燭光中，只見江梅白於雪。"]'),
('b1b8f8f6-2305-4380-b9ec-c6959988abd1','使客不至夜歸獨酌','楊萬里','宋','宋诗','song-poetry','','[]','使客夜不至，還舍欣小歇。',48,'全唐诗/poet.song.139000.json','["使客夜不至，還舍欣小歇。", "杯盤只草草，足可相暖熱。", "庭前雪夜明，道是簾外月。", "及見盤中酥，喚作庭前雪。"]'),
('95c0f06f-a2cb-437b-b38d-45b85bb1a052','謝趙行之惠霜柿','楊萬里','宋','宋诗','song-poetry','','[]','紅葉曾題字，烏椑昔擅場。',48,'全唐诗/poet.song.139000.json','["紅葉曾題字，烏椑昔擅場。", "凍乾千顆蜜，尚带一林霜。", "核有都無底，吾衰喜細嘗。", "慚無瓊玖句，報惠不相當。"]'),
('637dadb9-b112-4a6d-a006-117b21a6c1ad','謝葉叔羽總領惠雙淮白二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','寶奩寡貢笑權臣，筠掩分甘荷故人。',64,'全唐诗/poet.song.139000.json','["寶奩寡貢笑權臣，筠掩分甘荷故人。", "天下衆鱗誰出右，淮南雙玉忽嘗新。", "未知丙穴果何似，只恐子魚無此珍。", "敢遣腹腴勸年少，一杯端合壽吾親。"]'),
('aa70b632-6484-4a45-84d7-7d6164d253b8','謝葉叔羽總領惠雙淮白二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','情知北味飲中瓌，暖律何緣到死灰。',64,'全唐诗/poet.song.139000.json','["情知北味飲中瓌，暖律何緣到死灰。", "去歲海紅猶間識，今年淮白不曾來。", "一寒尚有綈袍贈，雙鯉仍隨尺素回。", "厚祿故人書盡絕，只餘計相解相哀。"]'),
('405a22b8-ca36-49bc-813e-382039a40371','詠酥','楊萬里','宋','宋诗','song-poetry','','[]','似膩還成爽，纔凝又欲飄。',24,'全唐诗/poet.song.139000.json','["似膩還成爽，纔凝又欲飄。", "玉來盤底碎，雪到口邊銷。"]'),
('98f2a293-b997-4e4b-a7d5-05758e763d7c','送客歸登浄遠亭二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','犯寒送客只勞神，上到危亭眼頓新。',32,'全唐诗/poet.song.139000.json','["犯寒送客只勞神，上到危亭眼頓新。", "雪汁滴人清入髓，莫將衫袖障頭巾。"]'),
('6d1a8e6a-4a89-4206-b50c-06cb9e97a187','送客歸登浄遠亭二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','池冰動處水生瀾，未覺今朝抵死寒。',32,'全唐诗/poet.song.139000.json','["池冰動處水生瀾，未覺今朝抵死寒。", "便恐雪銷難再得，不辭鞋濕數來看。"]'),
('1f9cb94d-e71d-4d85-81f6-4b262ba0c939','和范至能參政寄二絕句  其一','楊萬里','宋','宋诗','song-poetry','','[]','生憎雁鶩只盈前，忽覽新詩意豁然。',32,'全唐诗/poet.song.139000.json','["生憎雁鶩只盈前，忽覽新詩意豁然。", "錦字展來看未足，玉蟲挑盡不成眠。"]'),
('c8afeb84-9267-4be1-81a1-609b51fbecc0','和范至能參政寄二絕句  其二','楊萬里','宋','宋诗','song-poetry','','[]','夢中相見慰相思，玉立長身漆點髭。',32,'全唐诗/poet.song.139000.json','["夢中相見慰相思，玉立長身漆點髭。", "不遣紫宸朝補衮，却教雪屋夜哦詩。"]'),
('d8343c6b-d042-4e7e-9c38-f1b6449c8746','卧治齋夜坐','楊萬里','宋','宋诗','song-poetry','','[]','今年一雪徧江淮，半月晴光凍不開。',32,'全唐诗/poet.song.139000.json','["今年一雪徧江淮，半月晴光凍不開。", "孤坐郡齋人寂寂，一枝紅燭兩瓶梅。"]'),
('e85c26ca-57cd-438a-bf3b-94d0aac1598f','十一月二十八日雪至十二月十一日日色方暖積雪始融','楊萬里','宋','宋诗','song-poetry','','[]','日華今日始微暄，次第梅花暖更妍。',32,'全唐诗/poet.song.139000.json','["日華今日始微暄，次第梅花暖更妍。", "只有樹陰偏得意，占它殘雪不還天。"]'),
('b3062474-6772-4563-ad49-ea1187d57f5b','穉子弄冰','楊萬里','宋','宋诗','song-poetry','','[]','穉子金盆脫曉冰，彩絲穿取當銀鉦。',32,'全唐诗/poet.song.139000.json','["穉子金盆脫曉冰，彩絲穿取當銀鉦。", "敲成玉磬穿林響，忽作玻瓈碎地聲。"]'),
('d7242b56-5bcd-45f3-8fba-12c2197bef0c','寄題石湖先生范至能參政石湖精舍二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','萬頃平湖石琢成，尚存越壘對吳城。',64,'全唐诗/poet.song.139000.json','["萬頃平湖石琢成，尚存越壘對吳城。", "如何豪傑干戈地，却入先生杖屨聲。", "古往今來真一夢，湖光月色自雙清。", "東風不解談興廢，只有年年春草生。"]'),
('dfa40328-67c6-49fb-aa23-aa3a4e1ed6d0','寄題石湖先生范至能參政石湖精舍二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','不關白眼視青雲，四海如今幾若人。',64,'全唐诗/poet.song.139000.json','["不關白眼視青雲，四海如今幾若人。", "渭水傅巖看後代，東坡太白即前身。", "整齊宇宙徐揮手，點綴湖山別是春。", "解遣雙魚傳七字，遥知掉脫小烏巾。"]'),
('fc87f12b-4ada-4c34-b5b1-e59149b5cb0d','和丁端叔歲晚書懷','楊萬里','宋','宋诗','song-poetry','','[]','嗟予不能知止如邴曼容，又不能畢昏如尚子平。',133,'全唐诗/poet.song.139000.json','["嗟予不能知止如邴曼容，又不能畢昏如尚子平。", "軟紅塵裏白雙鬢，坐見歲律空崢嶸。", "催科撫字兩何有，伎倆已窮慚九九。", "拔薤一本水一杅，多謝同朝金石友。", "雪欺老病忽抵巇，西山凍裂不留薇。", "詩壇老將更黷武，我已三北猶窮追。", "老懷不中數怊悵，急漉鵝黄翻甕盎。", "苛留殘雪更些時，爲我裝嚴麗譙上。"]'),
('66d691a7-4345-4e39-a8b9-ad40806b1ce8','郡圃殘雪三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','半依籬脚半依城，多傍梅邊水際亭。',32,'全唐诗/poet.song.139000.json','["半依籬脚半依城，多傍梅邊水際亭。", "最是晚晴斜照裏，黄金日射萬銀星。"]'),
('1b8e4250-7e3f-4bdc-803a-315e15cd1170','郡圃殘雪三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','南風融雪北風凝，晚日城頭已可登。',32,'全唐诗/poet.song.139000.json','["南風融雪北風凝，晚日城頭已可登。", "莫道雪融便無跡，雪融成水水成冰。"]'),
('e7505843-401c-44c1-8c28-0166bcc081e2','郡圃殘雪三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','城外城中雪半開，遠峰依舊玉崔嵬。',32,'全唐诗/poet.song.139000.json','["城外城中雪半開，遠峰依舊玉崔嵬。", "池冰綻處纔如線，便有鴛鴦浮過來。"]'),
('d28bab22-1dff-4916-b016-c03a10bffaa4','月夜觀雪三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','仙人愛雪不嫌寒，挈月來看夜不眠。',32,'全唐诗/poet.song.139000.json','["仙人愛雪不嫌寒，挈月來看夜不眠。", "游遍瓊樓霜欲曉，却將玉鏡掛青天。"]'),
('8bcf81b4-5696-4efa-9024-8046e5b6e526','月夜觀雪三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','月光雪色兩清寒，見月初疑是雪團。',32,'全唐诗/poet.song.139000.json','["月光雪色兩清寒，見月初疑是雪團。", "看得雪光還似月，元來雪月一般般。"]'),
('dea225a1-e840-4a85-9537-7d7705c461c1','月夜觀雪三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','月色還將雪色同，雪光却與月光通。',32,'全唐诗/poet.song.139000.json','["月色還將雪色同，雪光却與月光通。", "都將大地作月窟，仍牓碧天名雪宮。"]'),
('382c5516-6147-473a-bce7-bcfdbeed1bcd','雪晴窗開展唐詩得一片桃花悵然賦之','楊萬里','宋','宋诗','song-poetry','','[]','偶開詩卷雪窗晨，中有桃花片尚新。',32,'全唐诗/poet.song.139000.json','["偶開詩卷雪窗晨，中有桃花片尚新。", "却憶携詩花底看，回頭又是一年春。"]'),
('0631c79f-04c0-4128-b5af-740790210dc2','梅露堂燕客夜歸','楊萬里','宋','宋诗','song-poetry','','[]','藥玉船中酒似空，水沉煙上雪都融。',32,'全唐诗/poet.song.139000.json','["藥玉船中酒似空，水沉煙上雪都融。", "梅堂客散人初靜，椽燭燒殘一尺紅。"]'),
('20e36691-a3e1-4b00-8901-536148d48c4d','城壕冰泮','楊萬里','宋','宋诗','song-poetry','','[]','雪力平欺半月晴，東風今日始開冰。',32,'全唐诗/poet.song.139000.json','["雪力平欺半月晴，東風今日始開冰。", "長壕徹底都銷盡，只有樓陰玉一稜。"]'),
('bf33bb29-ed86-498e-bfbc-b4e74d1e1ac4','櫻桃煎','楊萬里','宋','宋诗','song-poetry','','[]','含桃丹更圜，輕質觸必碎。',60,'全唐诗/poet.song.139000.json','["含桃丹更圜，輕質觸必碎。", "外看千粒珠，中藏半泓水。", "何人弄好手，萬顆搗虛脆。", "印成花鈿薄，染作冰澌紫。", "北果非不多，此味良獨美。"]'),
('f714d191-0494-4d3a-adfa-afa405ca47b7','郡圃雪霽便有春意','楊萬里','宋','宋诗','song-poetry','','[]','臘傍梅梢盡，春從水底歸。',48,'全唐诗/poet.song.139000.json','["臘傍梅梢盡，春從水底歸。", "草拳擎雪健，桃糝隔年肥。", "夜夜還鄉夢，心心逐雁飛。", "誰言五斗米，便勝北山薇。"]'),
('22d8dd26-b4ed-432f-a45f-a411279780a6','郡圃雪銷已盡惟餘城陰一街雪','楊萬里','宋','宋诗','song-poetry','','[]','陽林日暖雪全銷，陰逕瓊瑶尚寸高。',32,'全唐诗/poet.song.139000.json','["陽林日暖雪全銷，陰逕瓊瑶尚寸高。", "半疋斜鋪白花錦，倩誰裁作水霜袍。"]'),
('66778a8a-ef19-482b-ba8b-8241d31d69b2','晚望','楊萬里','宋','宋诗','song-poetry','','[]','天墮楸枰作稻畦，啼烏振鷺當枯棋。',32,'全唐诗/poet.song.139000.json','["天墮楸枰作稻畦，啼烏振鷺當枯棋。", "不論勝負端何似，黑子終多白子稀。"]'),
('c8200060-aa24-4b30-9830-c7ced172e0b4','送客歸至郡圃殘雪銷盡','楊萬里','宋','宋诗','song-poetry','','[]','三日東風入萬家，草間殘雪不留些。',32,'全唐诗/poet.song.139000.json','["三日東風入萬家，草間殘雪不留些。", "兒童道是雪猶在，笑指梅花作雪花。"]'),
('01da46fa-728e-4022-b412-33f4fe56929d','陳能之少卿殿撰挽詩','楊萬里','宋','宋诗','song-poetry','','[]','玉立頌臺上，風生憲府中。',48,'全唐诗/poet.song.139000.json','["玉立頌臺上，風生憲府中。", "雪霜欺兩鬢，日月照孤忠。", "荷橐相將紫，銘旌作麽紅。", "北堂萱草露，應灑碧梧桐。"]'),
('df14587d-645b-47f9-b415-f0c2de753b22','梅花數枝篸兩小瓷瓶雪寒一夜二瓶凍裂剝出二水精瓶梅花在焉蓋冰結而爲此也','楊萬里','宋','宋诗','song-poetry','','[]','何人雙贈水精瓶，梅花數枝瓶底生。',146,'全唐诗/poet.song.139000.json','["何人雙贈水精瓶，梅花數枝瓶底生。", "瘦枝尚带折痕在，隔瓶照見透骨明。", "大枝開盡花如雪，小枝未開更清絕。", "爭從瓶口迸出來，其奈堪看不堪掇。", "人言水精初出萬壑時，欲凝未凝如凍脂。", "上有江梅花正盛，吹折數枝墮寒鏡。", "玉工割取到人間，琢出瓶子和梅看。", "至今猶有未凝處，瓶裏水珠走來去。", "只愁窗外春日紅，瓶子化作亡是公。"]'),
('c5f4395a-4f78-43c8-a75d-33a71516f656','遣人探梅翟園云尚未開','楊萬里','宋','宋诗','song-poetry','','[]','傳語翟園千樹梅，不應藞苴索詩催。',64,'全唐诗/poet.song.139000.json','["傳語翟園千樹梅，不應藞苴索詩催。", "今年雪後悄無信，去歲臘前强半開。", "我欲明朝携酒去，花須連夜喚春回。", "東風肯報南枝否，待釂東風三百杯。"]'),
('f80191d4-5d3f-443e-9603-9265e9e28b62','十二月二十一日迎春','楊萬里','宋','宋诗','song-poetry','','[]','星淡孤螢月一梳，迎春早起正愁予。',64,'全唐诗/poet.song.139000.json','["星淡孤螢月一梳，迎春早起正愁予。", "土牛只解催人老，春氣自來何事渠。", "官柳野梅殘雪後，金幡玉勝曉光初。", "却思歸跨春山犢，繭栗仍將掛漢書。"]'),
('7de1dd35-e9f1-4933-a6aa-3033bc06efe1','己亥正月二日送李伯和提幹歸豫章','楊萬里','宋','宋诗','song-poetry','','[]','伯和來自西山西，西山爽氣在睫眉。',163,'全唐诗/poet.song.139000.json','["伯和來自西山西，西山爽氣在睫眉。", "胸中八索貯奇古，筆下九河走風雨。", "君不見李家人物它家無，老蚌一産俱明珠。", "郎罷致身已碧落，衆雛爭先見頭角。", "伯珍魁名北斗傍，仲簡插脚鴛鷺行。", "如何伯也袖兩手，却去外臺作賓友。", "荆溪病守鬢星星，一見鄉人雙眼明。", "白雲飛處忽心動，不堪折柳還相送。", "我自爲客仍送君，梅邊雪裏正新春。", "還家燈火更青簡，給札蘭臺未渠晚。"]'),
('b7f9dc2c-df95-47a2-aa86-d038a305acca','正月三日驟暖多稼亭前梅花盛開四首  其一','楊萬里','宋','宋诗','song-poetry','','[]','春被梅花抵死催，今年春向去年回。',32,'全唐诗/poet.song.139000.json','["春被梅花抵死催，今年春向去年回。", "春回十日梅初覺，一夜商量一併開。"]'),
('e2bdca14-7f0f-48d0-82b3-782c674cc5ba','正月三日驟暖多稼亭前梅花盛開四首  其二','楊萬里','宋','宋诗','song-poetry','','["\u897f\u6e56"]','絕愛西湖疎影詩，要知猶是未開時。',32,'全唐诗/poet.song.139000.json','["絕愛西湖疎影詩，要知猶是未開時。", "如今開盡渾無縫，只見花頭不見枝。"]'),
('bf0c82ee-8576-464e-a350-d7c898be793c','正月三日驟暖多稼亭前梅花盛開四首  其三','楊萬里','宋','宋诗','song-poetry','','[]','初開猶見蔕和心，今日來看花滿林。',32,'全唐诗/poet.song.139000.json','["初開猶見蔕和心，今日來看花滿林。", "日照一團都是雪，更無紅蠟與黄金。"]'),
('4737587f-f99d-4793-b220-ebf3dedc2deb','正月三日驟暖多稼亭前梅花盛開四首  其四','楊萬里','宋','宋诗','song-poetry','','[]','却緣臘雪勒孤芳，等待晴光曬麝囊。',32,'全唐诗/poet.song.139000.json','["却緣臘雪勒孤芳，等待晴光曬麝囊。", "小立樹西人不會，東風供我打頭香。"]'),
('c3ebe97b-2e66-49cf-965b-aeb121f2370a','春興','楊萬里','宋','宋诗','song-poetry','','[]','窗底梅花瓶底老，瓶邊破硯梅邊好。',64,'全唐诗/poet.song.139000.json','["窗底梅花瓶底老，瓶邊破硯梅邊好。", "詩人忽然詩興來，如何見硯不見梅。", "急磨玄圭染霜紙，撼落花鬚浮硯水。", "詩成字字梅樣香，却把春風寄誰子。"]'),
('f582d61c-465b-456b-9f63-9dfd13aebdb4','歲之二日欲游翟園以寒風而止','楊萬里','宋','宋诗','song-poetry','','[]','歲前問訊翟園梅，不知作麽不肯開。',156,'全唐诗/poet.song.139000.json','["歲前問訊翟園梅，不知作麽不肯開。", "歲後遣人訪消息，春風一夜花都拆。", "老夫聞此喜欲癲，小兒終夕不成眠。", "南烹北果手自飣，漆櫑銀瓶色相映。", "千騎朝來填㦸門，雙旌已復指梅園。", "東風無端動地起，橫作清寒止游子。", "老夫孤悶搔白頭，小兒勸翁翁勿愁。", "人言好事莫作意，雨妬風憎鬼神忌。", "欲游不必言，阻游不必計。", "從今只揀天色佳，走就梅花求一醉。"]'),
('f54d4c74-448b-4191-ad79-4b285c295945','謝陳希顔惠兔羓','楊萬里','宋','宋诗','song-poetry','','[]','東郭阿㕙駝褐裳，清腹不著煙火香。',184,'全唐诗/poet.song.139000.json','["東郭阿㕙駝褐裳，清腹不著煙火香。", "姮娥喚入廣寒殿，詔許搗藥不許嘗。", "金丹煉成紫皇喜，玉臼自携銀漢洗。", "偷將缺吻吸瓊漿，蛻盡骨毛作仙子。", "鬢絲吹落桂枝風，人間封作管城公。", "先生何許得尸解，貌如枯蟾带玄疥。", "麒麟擘脯未必如，耶律曬羓差不大。", "先生錦心冰雪腸，銀鈎珠唾千萬章。", "管城奔命困書囿，阿㕙漆身嬉醉鄉。", "老夫去年左車脫，匙抄爛飯猶戛戛。", "太息再拜謝阿㕙，尚堪挂壁縈蛛塵，一飯瞻仰齒生津。"]'),
('f35b5646-19f9-4b86-939b-89b818a456e6','初三日游翟園','楊萬里','宋','宋诗','song-poetry','','[]','羽衣曉謁玄元殿，霜封萬屋明飛霰。',256,'全唐诗/poet.song.139000.json','["羽衣曉謁玄元殿，霜封萬屋明飛霰。", "扶桑跳出丹砂丸，光射半天縈紫電。", "歸塗微暖春衫知，小風不動旗脚垂。", "老夫掉頭心獨喜，翟園梅花招我嬉。", "呼兒媻姍且勃窣，纔出譙門寒刮骨。", "東風十里卷黄塵，眼花頭眩吹倒人。", "劣到翟園風便止，猿鶴前導花迎門。", "玉林亭子絕幽絕，江梅千樹吹香雪。", "茂松軒裏清更清，松風一鼎煎茶聲。", "春光催柳未肯青，池水借日無留冰。", "殷勤犯寒我不枉，分付勝遊天豈輕。", "主人看客眼不白，鸚鵡傳呼餉肴核。", "桃花碎片點鱸鮓，紫茸堆盤擘鶉腊。", "霜餘橘顆金彈香，雪底笋芽玉版色。", "老夫欲醉金叵羅，穉子先唱驪駒歌。", "不羞冷面對風物，奈爾玉笋金柑何。"]'),
('6535c2d0-b223-439c-b895-8388be83adfa','多稼亭前兩株梅盛開','楊萬里','宋','宋诗','song-poetry','','[]','翟園看梅不滿眼，載酒何曾傾一盞。',208,'全唐诗/poet.song.139000.json','["翟園看梅不滿眼，載酒何曾傾一盞。", "空有千株半未花，欲剪一枝無可揀。", "歸來却登多稼亭，玉妃驟降千娉婷。", "素羅衣裳濯瑶水，珠宮樓閣開銀屏。", "國香萬斛量不盡，雪嶺諸峰互相映。", "身騎白鳳繞瓊林，肝膽透寒骨毛冷。", "看來只是兩株梅，如何遣儂心眼開。", "花頭密密紛無數，萼萼枝枝砌成樹。", "夕陽斜照光燭天，微風欲度遮無路。", "君不見侯門女兒真箇癡，獺髓熬酥滴北枝。", "又不見畫工兔穎矜好手，冰水和鉛描玉肌。", "先生不能奄有二子者，報答風光只有詩。", "今夕不醉仍無歸。"]'),
('3df41fe5-5f6f-4466-ad90-a5676a649472','戲題所見','楊萬里','宋','宋诗','song-poetry','','[]','田家不遣兒牧豬，老烏替作牧豬奴。',144,'全唐诗/poet.song.139000.json','["田家不遣兒牧豬，老烏替作牧豬奴。", "不羞卑冗頗得志，草根更與豬爲戲。", "一烏驅豬作觳觫，一烏騎豬作騏驥。", "騎之不穩驅不前，坐看頑鈍手無鞭。", "人與馬牛雖各樣，一生同住烏衣巷。", "叱聲啞啞喙欲乾，豬竟不曉烏之言。", "騎者不從驅者鬭，爭牛訟馬傍無救。", "豬亦自食仍自行，一任兩烏雙鬭爭。", "不緣一童逐烏起，兩烏頃刻鬭至死。"]'),
('6a1a7979-ab1f-45d4-9c5c-4d0687499086','梅花下遇小雨','楊萬里','宋','宋诗','song-poetry','','[]','偶來花下聊散策，落英滿地珠爲席。',128,'全唐诗/poet.song.139000.json','["偶來花下聊散策，落英滿地珠爲席。", "繞花百匝不忍歸，生怕幽芳怨孤寂。", "仰頭欲折一枝斜，自插白鬢明烏紗。", "傍人勸我不用許，道我滿頭都是花。", "初來也覺香破鼻，頃之無香亦無味。", "虛疑黄昏花欲睡，不知被花薰得醉。", "忽然細雨濕我頭，雨落未落花先愁。", "三點兩點也不惡，未要打空花片休。"]'),
('1bd4ac33-2ff8-4bef-a6a1-a94256c5ea48','落梅有歎','楊萬里','宋','宋诗','song-poetry','','[]','纔看臘後得春饒，愁見風前作雪飄。',32,'全唐诗/poet.song.139000.json','["纔看臘後得春饒，愁見風前作雪飄。", "脫蕊收將熬粥喫，落英仍好當香燒。"]'),
('6a6be840-7c1d-45eb-a6ef-c7f1c32a0447','郡治燕堂庭中梅花','楊萬里','宋','宋诗','song-poetry','','[]','林中梅花如隠士，只多野氣無塵氣。',112,'全唐诗/poet.song.139000.json','["林中梅花如隠士，只多野氣無塵氣。", "庭中梅花如貴人，也無野氣也無塵。", "不疎不密隨宜了，旋落旋開無不好。", "珠簾遣風細爲吹，畫簷護霜寒更微。", "詩翁繞階未得句，先送詩材與翁語。", "有酒如澠誰伴翁，玉雪對飲惟渠儂。", "翁欲還家即明發，更爲梅兄留一月。"]'),
('f734f4f6-c3d1-47d3-aa05-c4f869266c8f','細雨','楊萬里','宋','宋诗','song-poetry','','[]','孤悶無言獨倚門，梅花細雨欲黄昏。',32,'全唐诗/poet.song.139000.json','["孤悶無言獨倚門，梅花細雨欲黄昏。", "可憐簷滴不脫灑，點點何曾離舊痕。"]'),
('16ea41ce-c02b-4bdf-a917-baf4daed047c','水精膾','楊萬里','宋','宋诗','song-poetry','','[]','上饒靈山無它靈，空山滿腹著水精。',134,'全唐诗/poet.song.139000.json','["上饒靈山無它靈，空山滿腹著水精。", "炯然非石亦非玉，乃是陰崖絕壑千秋萬歲之堅冰。", "只知靈山有爽氣，誰知水精有奇味。", "詩人新試餐玉方，解遣堅凝作鬆脆。", "銀刀細下雪縷飛，金盤飣出瓊瑶堆。", "齒牙著處霜霰響，殽鯖厭後胸襟開。", "尊前歡伯來督戰，坐上嘉賓欲驚散。", "胸中自有水精宮，不怕醉鄉無畔岸。"]'),
('13f0e68b-c92a-45bf-8b32-0a81c27eb2ea','雨後曉起問訊梅花','楊萬里','宋','宋诗','song-poetry','','[]','前日看梅風吹倒，昨日看梅雨霑帽。',176,'全唐诗/poet.song.139000.json','["前日看梅風吹倒，昨日看梅雨霑帽。", "近梅一日或再來，遠梅隔年纔一到。", "夜來爲梅愁雨聲，挑燈起坐至天明。", "不知消息平安否，早來問訊還疾走。", "橫枝雨後轉清妍，玉容洗粧晨更鮮。", "絕似孤山半峰雪，不羨玉井十丈蓮。", "十事八九不如意，人生巧墮天公計。", "簿書海底白人頭，孤負江南風月秋。", "憶昔少年命同社，月裏傳觴梅影下。", "一片花飛落酒中，十分便罰瑠璃鍾。", "如今老病不飲酒，梅花也合憐衰翁。"]'),
('79546b32-686e-448b-ac5d-2b40be6ca43b','壕上感春','楊萬里','宋','宋诗','song-poetry','','[]','長壕無事不耐靜，若非織綃便磨鏡。',208,'全唐诗/poet.song.139000.json','["長壕無事不耐靜，若非織綃便磨鏡。", "竹君不作五斗謀，風前折腰也如磬。", "先生節裏城上嬉，朝游暮游不肯歸。", "晴空大聲斗作惡，萬鴉退飛一鴉落。", "乃是黑風江北來，更將黑雲頭上堆。", "翻手爲晴覆手雨，自晴自雨何須怒。", "先生不妨且覓句，挽之不來推不去。", "坐看梅花一萬枝，化成粉蝶作團飛。", "紛紛掠面收不得，稍稍積砌吹還稀。", "落盡梅花天不管，晚來許寒朝許暖。", "一年待春春不回，一年探梅梅不開。", "春回今纔幾許日，梅開如何頓蕭瑟。", "少壯幾時奈老何，落花未抵春愁多。"]'),
('93562173-41ca-48ea-95ce-ff70cd57d05b','觀小兒戲打春牛','楊萬里','宋','宋诗','song-poetry','','[]','小兒著鞭鞭土牛，學翁打春先打頭。',96,'全唐诗/poet.song.139000.json','["小兒著鞭鞭土牛，學翁打春先打頭。", "黄牛黄蹄白雙角，牧童綠蓑笠青篛。", "今年土脉應雨膏，去年不似今年樂。", "兒聞年登喜不饑，牛聞年登愁不肥。", "麥穗即看雲作帚，稻米亦復珠盈斗。", "大田耕盡却耕山，黄牛從此何時閑。"]'),
('7ce414ef-c5e9-46f3-8b9f-0e6938657dba','謝親戚寄黄雀','楊萬里','宋','宋诗','song-poetry','','[]','萬金家書寄中庭，牘背仍題雙掩并。',144,'全唐诗/poet.song.139000.json','["萬金家書寄中庭，牘背仍題雙掩并。", "不知千里寄底物，白泥紅印三十瓶。", "瓷瓶淺染茱萸紫，心知親賓寄鄉味。", "印泥未開出饞水，印泥一開香撲鼻。", "江西山間黄羽衣，純綿被體白如脂。", "偶然一念隨世網，身插兩翼那能飛。", "誤蒙諸公相俎豆，月裏花邊一杯酒。", "先生與渠元不疎，兩年眼底不見渠。", "端能訪我荆溪曲，願借前籌酌酃淥。"]'),
('ccdea21d-a38b-4734-9edc-1076477c88e8','牛尾狸','楊萬里','宋','宋诗','song-poetry','','[]','狐公韻勝冰玉肌，字則未聞名季貍。',64,'全唐诗/poet.song.139000.json','["狐公韻勝冰玉肌，字則未聞名季貍。", "誤隨齊相燧牛尾，策勳封作糟丘子。", "子孫世世襲膏粱，黄雀子魚鴻雁行。", "先生試與季貍語，有味其言須聽取。"]'),
('7930a67c-0f56-450a-95b8-f8c89d9c04ae','得小兒壽俊家書','楊萬里','宋','宋诗','song-poetry','','[]','父子初別雙淚垂，別我既久忘却思。',112,'全唐诗/poet.song.139000.json','["父子初別雙淚垂，別我既久忘却思。", "忽得一書喜且悲，恰似向來初別時。", "汝翁在官緣索米，吾兒在家勉經史。", "舉頭二千四百里，亙山啼鳥偏入耳。", "詩成自哦只自知，便風不敢寄吾兒。", "汝望白雲穿却眼，若得此詩恐腸斷。", "徑須父子早歸田，粗茶淡飯終殘年。"]'),
('1cda9b3d-a5a2-494b-a0c5-7dc76fde41df','書莫讀','楊萬里','宋','宋诗','song-poetry','','[]','書莫讀，詩莫吟。',100,'全唐诗/poet.song.139000.json','["書莫讀，詩莫吟。", "讀書兩眼枯見骨，吟詩箇字嘔出心。", "人言讀書樂，人言吟詩好。", "口吻長作秋蟲聲，只令君瘦令君老。", "君瘦君老且勿論，傍人聽之亦煩惱。", "何如閉目坐齋房，下簾掃地自焚香。", "聽風聽雨都有味，健來即行倦來睡。"]'),
('f2d15c17-cbfb-46d5-9059-dd457be25876','春草二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','天欲遊人不踏塵，一年一換翠茸茵。',32,'全唐诗/poet.song.139000.json','["天欲遊人不踏塵，一年一換翠茸茵。", "東風猶自嫌蕭索，更遣飛花繡好春。"]'),
('061f8039-ad09-4285-9f7c-e39472942c94','春草二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','年年春色屬垂楊，金撚千絲翠萬行。',32,'全唐诗/poet.song.139000.json','["年年春色屬垂楊，金撚千絲翠萬行。", "今歲草芽先得計，攙它濃翠奪它黄。"]'),
('c5a75de2-8aa5-4303-8a31-2f5b3be8692c','春陰','楊萬里','宋','宋诗','song-poetry','','[]','春晴幸好却春陰，雲意涔涔半欲霖。',32,'全唐诗/poet.song.139000.json','["春晴幸好却春陰，雲意涔涔半欲霖。", "日色忽開雲又合，急收碎影一簾金。"]'),
('cfd74bc0-2806-44cb-994a-361913de0780','小瓶梅花','楊萬里','宋','宋诗','song-poetry','','[]','梅萼纔開已亂飛，不堪雨打更風吹。',32,'全唐诗/poet.song.139000.json','["梅萼纔開已亂飛，不堪雨打更風吹。", "蕭蕭只隔窗間紙，瓶裏梅花總不知。"]'),
('7e6d1fe1-9ab6-4b67-b2bd-64d78914668c','夜坐二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','繡簾無力護東風，燭影何曾正當紅。',32,'全唐诗/poet.song.139000.json','["繡簾無力護東風，燭影何曾正當紅。", "獸炭貂裘猶道冷，梅花不易玉霜中。"]'),
('eba11d60-ca7f-42df-b8b4-a880aa557bca','夜坐二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','寒宵老眼只長醒，蝴蝶頻催夢不成。',32,'全唐诗/poet.song.139000.json','["寒宵老眼只長醒，蝴蝶頻催夢不成。", "不是三更三四點，如何一睡到天明。"]'),
('e5b66b15-5221-4d41-862f-9031f2b933f0','燭下和雪折梅','楊萬里','宋','宋诗','song-poetry','','[]','梅兄衝雪來相見，雪片滿鬚仍滿面。',64,'全唐诗/poet.song.139000.json','["梅兄衝雪來相見，雪片滿鬚仍滿面。", "一生梅瘦今却肥，是雪是梅渾不辨。", "喚來燈下細看渠，不知真箇有雪無。", "只見玉顔流汗珠，汗珠滿面滴到鬚。"]'),
('5e897f85-bfc7-4fe5-badd-354e95eedcbf','鳩銜枝營巢樹間經月不成而去','楊萬里','宋','宋诗','song-poetry','','[]','鳩婦那知自不材，樹陰疎處起樓臺。',32,'全唐诗/poet.song.139000.json','["鳩婦那知自不材，樹陰疎處起樓臺。", "可憐積木如山樣，一桷何曾架得來。"]'),
('075d5ae9-9b85-4b8b-826d-e65d943a3182','鵲營巢既成爲鳩所據','楊萬里','宋','宋诗','song-poetry','','[]','乾鵲平生浪苦辛，一年卜築一番新。',32,'全唐诗/poet.song.139000.json','["乾鵲平生浪苦辛，一年卜築一番新。", "如何月下空三匝，宅子還將住別人。"]'),
('76479a1a-f4e8-47cf-b5d8-fe3bd230f9a8','上元前大雪即晴','楊萬里','宋','宋诗','song-poetry','','[]','臘前三白已奇絕，年後六花仍作團。',64,'全唐诗/poet.song.139000.json','["臘前三白已奇絕，年後六花仍作團。", "纔定忽斜偏有思，欲消還凍不勝寒。", "且留大地萬銀屋，要伴青天孤玉盤。", "今歲上元君記取，紅燈白月雪中看。"]'),
('41b5942b-b5fb-474e-bd39-621b6459624f','郡中上元燈減舊例三之二而又迎送使客七首  其一','楊萬里','宋','宋诗','song-poetry','','[]','紅錦芙蓉碧牡丹，今番燈火減前番。',32,'全唐诗/poet.song.139000.json','["紅錦芙蓉碧牡丹，今番燈火減前番。", "雪泥沒膝霜風緊，也有遊人看上元。"]'),
('c87ed11f-7580-4939-8328-c332bb3c6c91','郡中上元燈減舊例三之二而又迎送使客七首  其二','楊萬里','宋','宋诗','song-poetry','','[]','北使纔歸南使來，前船未送後船催。',32,'全唐诗/poet.song.139000.json','["北使纔歸南使來，前船未送後船催。", "元宵行樂年年事，兒女嗔人夜不回。"]'),
('5e1bbfac-1001-4309-af0c-9915da46e7b0','郡中上元燈減舊例三之二而又迎送使客七首  其三','楊萬里','宋','宋诗','song-poetry','','[]','憶昔三衢看上元，玉虹橫貫水精簾。',32,'全唐诗/poet.song.139000.json','["憶昔三衢看上元，玉虹橫貫水精簾。", "窮州今夕酸寒殺，老眼看來自不忺。"]'),
('4ef975b1-fa4d-47df-a26f-12dd85c61ee5','郡中上元燈減舊例三之二而又迎送使客七首  其四','楊萬里','宋','宋诗','song-poetry','','[]','兒時行樂幾時愁，老去情懷懶出遊。',32,'全唐诗/poet.song.139000.json','["兒時行樂幾時愁，老去情懷懶出遊。", "市上人家重時節，典釵賣釧買燈毬。"]'),
('bccb22f3-ed7d-4711-89dc-64ec69d1cebd','郡中上元燈減舊例三之二而又迎送使客七首  其五','楊萬里','宋','宋诗','song-poetry','','[]','不是東風巧剪裁，如何春夜碧蓮開。',32,'全唐诗/poet.song.139000.json','["不是東風巧剪裁，如何春夜碧蓮開。", "江城寂寞無歌舞，喚得梅花勸一杯。"]'),
('d6f93a48-704a-4d1c-80a2-afdc4ea97b04','郡中上元燈減舊例三之二而又迎送使客七首  其六','楊萬里','宋','宋诗','song-poetry','','[]','雪後樓臺欲暮時，遊人只道上燈遲。',32,'全唐诗/poet.song.139000.json','["雪後樓臺欲暮時，遊人只道上燈遲。", "月輪貼在梅花背，錯認梅枝作桂枝。"]'),
('830a83a7-bddf-42c4-bcbe-86323b079643','郡中上元燈減舊例三之二而又迎送使客七首  其七','楊萬里','宋','宋诗','song-poetry','','[]','村裏風回市裏聲，月中人看雪中燈。',32,'全唐诗/poet.song.139000.json','["村裏風回市裏聲，月中人看雪中燈。", "滿城只道歡猶少，不道譙門冷似冰。"]'),
('acfed6f5-4097-4c24-80eb-0ef7ab36821b','郡圃杏花二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','小樹嫣然一兩枝，晴醺雨醉總相宜。',64,'全唐诗/poet.song.139000.json','["小樹嫣然一兩枝，晴醺雨醉總相宜。", "絕憐欲白仍紅處，政是微開半吐時。", "得幸東風無與對，主張春色更還誰。", "海棠穠麗梅花淡，匹似渠儂別樣奇。"]'),
('17410e4b-191f-4fc5-8926-bcc9a2b2a74b','郡圃杏花二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','迥出千花合受降，不然受拜亦何妨。',64,'全唐诗/poet.song.139000.json','["迥出千花合受降，不然受拜亦何妨。", "行穿小樹尋晴朶，自挽芳條嗅暖香。", "却恨來時差已晚，不如清曉看新粧。", "朗吟清露溫風句，惱殺詩翁只斷腸。"]'),
('4490758c-5191-472b-90f8-e22f9ebb6600','華鏜秀才著六經解以長句書其後','楊萬里','宋','宋诗','song-poetry','','[]','河圖三畫已剩却，堯典萬言猶欠著。',187,'全唐诗/poet.song.139000.json','["河圖三畫已剩却，堯典萬言猶欠著。", "向來潜聖天何言，六經非渠一手作。", "杏花壇下撥不開，天公更遣麒麟催。", "乾坤造化登青竹，洙泗光芒付綠苔。", "堂上書生真苦相，蠹簡嚼穿渾不放。", "屋上架屋更屋上，後千萬年作何樣。", "華元夜登子反床，華鏜晨趨孔子堂。", "當時浪說析骸骨，今日覃思彫肺腸。", "華君將身博凍餒，毛穎可憐彼何罪。", "君不見老農驅牛耕壠頭，稻雲割盡牛亦休。", "毛穎爲君秃盡髮，問君何時放渠歇。", "短檠青燈明復滅。"]'),
('43463820-1e0e-49d3-b542-5a6913e47839','上元後猶寒二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','雪後不妨寒較差，莫教一併放千花。',32,'全唐诗/poet.song.139000.json','["雪後不妨寒較差，莫教一併放千花。", "舊來池上金絲柳，新學江西鷹爪茶。"]'),
('670f3793-a9ee-493d-b6e4-a84cdabda284','上元後猶寒二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','道是春工做物華，春工元自不由它。',32,'全唐诗/poet.song.139000.json','["道是春工做物華，春工元自不由它。", "杏花只作去年面，萱草別抽今歲芽。"]'),
('7b87f87e-f578-4dea-8700-46d5e79c7295','夜觀庭中梅花','楊萬里','宋','宋诗','song-poetry','','[]','霧質雲爲屋，瓊膚玉作裳。',24,'全唐诗/poet.song.139000.json','["霧質雲爲屋，瓊膚玉作裳。", "花明不是月，夜靜偶聞香。"]'),
('396720d4-d581-475c-bcdc-555a6c97d10f','春夜孤坐三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','兒女齁齁鼻息聲，虛堂誰伴一先生。',32,'全唐诗/poet.song.139000.json','["兒女齁齁鼻息聲，虛堂誰伴一先生。", "春寒夜靜燈花落，數盡殘更睡不成。"]'),
('ffd0fe85-929a-4f6e-bea3-8198788d3ee5','春夜孤坐三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅花雪後杏花風，老面逢春只强紅。',32,'全唐诗/poet.song.139000.json','["梅花雪後杏花風，老面逢春只强紅。", "詩句行來行去裏，情懷不醉不醒中。"]'),
('f8ebbf95-6686-489a-91b7-5f10ff7b0c64','春夜孤坐三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','老來覓句苦難成，細把風斤鏤薄冰。',32,'全唐诗/poet.song.139000.json','["老來覓句苦難成，細把風斤鏤薄冰。", "行到長廊人寂寂，隔窗一點讀書燈。"]'),
('ea2a5917-25aa-497b-a279-a9a8cfbd9cbf','休日城上三首  其一','楊萬里','宋','宋诗','song-poetry','','[]','到得荆溪鬢盡斑，二年心力不曾閑。',32,'全唐诗/poet.song.139000.json','["到得荆溪鬢盡斑，二年心力不曾閑。", "如今歸去無餘戀，只有梅花慘別顔。"]'),
('331e889f-7a80-44d6-83b4-fc75e8b8a1b0','休日城上三首  其二','楊萬里','宋','宋诗','song-poetry','','[]','休日呼兒上古城，胡床何處不隨行。',32,'全唐诗/poet.song.139000.json','["休日呼兒上古城，胡床何處不隨行。", "莫嫌一陣東風惡，分外教他數日晴。"]'),
('110fdfc4-645d-43b8-beae-f34938cdfdbb','休日城上三首  其三','楊萬里','宋','宋诗','song-poetry','','[]','望中遠樹各依行，春後新晴未斷霜。',32,'全唐诗/poet.song.139000.json','["望中遠樹各依行，春後新晴未斷霜。", "池面得風呈縐碧，梅鬚經雨褪危黄。"]'),
('ee40321b-718b-43d8-9b73-76e44118c544','多稼亭看梅二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','先生次第即還家，更上城頭一望賒。',32,'全唐诗/poet.song.139000.json','["先生次第即還家，更上城頭一望賒。", "行盡荒寒無意思，不如來此看梅花。"]'),
('2828c22b-c0e0-42c4-bb43-fa3ce1073155','多稼亭看梅二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','梅花不合太爭春，政盛開時却惱人。',32,'全唐诗/poet.song.139000.json','["梅花不合太爭春，政盛開時却惱人。", "試折一枝輕著手，驚飛萬點撲衣巾。"]'),
('68c5a833-0489-4ead-a796-14ea78713f2e','鑷白','楊萬里','宋','宋诗','song-poetry','','[]','莫把菱花鑷白髭，勸君留取伴吟詩。',32,'全唐诗/poet.song.139000.json','["莫把菱花鑷白髭，勸君留取伴吟詩。", "錦囊若要添新句，繡口如何減素絲。"]'),
('9b9ea6e9-0cc1-4f5e-a769-ee4074548338','東窗梅影上有寒雀往來','楊萬里','宋','宋诗','song-poetry','','[]','梅花寒雀不須摹，日影描窗作畫圖。',32,'全唐诗/poet.song.139000.json','["梅花寒雀不須摹，日影描窗作畫圖。", "寒雀解飛花解舞，君看此畫古今無。"]'),
('2d6876d4-c963-462c-94d7-cf28636cbc17','瑞香','楊萬里','宋','宋诗','song-poetry','','[]','買斷春光與曉晴，幽香逸豔獨婷婷。',64,'全唐诗/poet.song.139000.json','["買斷春光與曉晴，幽香逸豔獨婷婷。", "齊開忽作欒枝錦，未坼猶疑紫素馨。", "絕愛小花和月露，折將一朶篸銀瓶。", "今年偶憶年時句，倦倚彫欄酒半醒。"]'),
('02e9a995-2d46-4e7d-9202-d3278dff8a21','燒香','楊萬里','宋','宋诗','song-poetry','','[]','小閣疎櫺春晝長，沉煙半穗弄輕黄。',32,'全唐诗/poet.song.139000.json','["小閣疎櫺春晝長，沉煙半穗弄輕黄。", "老鈴略不知人意，故故搴簾放出香。"]'),
('11244c86-96eb-4cab-896b-6bf72306bee2','看畫常州圖迎新太守','楊萬里','宋','宋诗','song-poetry','','[]','畫工吮筆畫常州，老子來看却自羞。',32,'全唐诗/poet.song.139000.json','["畫工吮筆畫常州，老子來看却自羞。", "若遣此圖還解語，道儂調戲幾君侯。"]'),
('28e0e443-5af5-4570-b391-0e6e28530b21','風急落梅','楊萬里','宋','宋诗','song-poetry','','[]','梅花已是不勝癯，無頼東風特地粗。',32,'全唐诗/poet.song.139000.json','["梅花已是不勝癯，無頼東風特地粗。", "狼籍玉英渾不惜，强留嫣蔕與枯鬚。"]'),
('3994ba13-12d1-43af-b318-a172b870a786','探春','楊萬里','宋','宋诗','song-poetry','','[]','五日纔能一日來，眼生方覺有春回。',32,'全唐诗/poet.song.139000.json','["五日纔能一日來，眼生方覺有春回。", "向來日日頻來探，只道園花不肯開。"]'),
('f1987995-a44c-40a3-b741-673058165c4a','晚晴二首  其一','楊萬里','宋','宋诗','song-poetry','','[]','風收點滴曉簷聲，雲放朦朧晚日明。',32,'全唐诗/poet.song.139000.json','["風收點滴曉簷聲，雲放朦朧晚日明。", "楊柳染絲纔喜雨，梅花泣玉却祈晴。"]'),
('2b7a99fa-e549-49f8-8403-2f18768d3835','晚晴二首  其二','楊萬里','宋','宋诗','song-poetry','','[]','先生老態似枯禪，解后東風也欲顛。',32,'全唐诗/poet.song.139000.json','["先生老態似枯禪，解后東風也欲顛。", "纔雨便晴寒便暖，四時佳處是春天。"]'),
('4798f330-1c4a-4eb5-90be-e1f761860f38','理髮','楊萬里','宋','宋诗','song-poetry','','[]','髮脫心知不再生，新年底急頓星星。',32,'全唐诗/poet.song.139000.json','["髮脫心知不再生，新年底急頓星星。", "城邊老柳也欺我，春裏滿頭依舊青。"]'),
('faf12df9-c7ee-4070-afc8-932ffc6cf531','晚照','楊萬里','宋','宋诗','song-poetry','','[]','閑對斜陽數隙塵，何曾萬事一關身。',32,'全唐诗/poet.song.139000.json','["閑對斜陽數隙塵，何曾萬事一關身。", "湯瓶得火自相語，酒盞爲人先作春。"]'),
('7d3cf7a0-19f7-4054-9a9a-4eecb8b10a7d','奉和持國曼叔方叔送師直歸馬上同賦之什','梅堯臣','宋','宋诗','song-poetry','','[]','郊外桃李花，赤赤復白白。',72,'全唐诗/poet.song.14000.json','["郊外桃李花，赤赤復白白。", "爲君歌古曲，行子在南陌。", "衆人各已歸，春風送無跡。", "安知春風送，到處花當客。", "我病出獨難，併請春風讁。", "此情無遠近，千里不能隔。"]'),
('e4431754-b22a-49b6-8f7c-f5b5a06f6ff6','和韓子華寄東華市玉版鮓','梅堯臣','宋','宋诗','song-poetry','','[]','客從都下來，遠遺東華鮓。',48,'全唐诗/poet.song.14000.json','["客從都下來，遠遺東華鮓。", "荷香開新包，玉臠識舊把。", "色絜已可珍，味佳寧獨捨。", "莫問魚與龍，予非博物者。"]'),
('e6a0e0e3-54ce-4d73-b09c-4c822e3e4b25','喜雨','梅堯臣','宋','宋诗','song-poetry','','[]','冬涉春無雨，侵晨忽沛然。',48,'全唐诗/poet.song.14000.json','["冬涉春無雨，侵晨忽沛然。", "燕曾知社後，雷未發聲前。", "細濕林花暗，輕霑土脈全。", "看看一百五，風勢莫狂顛。"]'),
('e4cee36a-94de-4ef5-84cd-8dc233072abd','送王判官之江陰軍幙','梅堯臣','宋','宋诗','song-poetry','','[]','往時初渡江，頗愛江南美。',48,'全唐诗/poet.song.14000.json','["往時初渡江，頗愛江南美。", "誰知坐卧間，思及煙波裏。", "絮逐𩶆魚繁，豉添蒓線紫。", "君行語風物，到日應相似。"]'),
('bfdc3618-beb5-4ea3-a794-95c4e68daf5b','送王龍圖源叔之襄陽','梅堯臣','宋','宋诗','song-poetry','','[]','忽驚車騎臨，乃是荆州長。',96,'全唐诗/poet.song.14000.json','["忽驚車騎臨，乃是荆州長。", "登堂語出處，陳事猶夢想。", "別逾二十年，相遇今始兩。", "爵位異禮數，齒髮可下上。", "但問我何有，而獨不愛曩。", "敢告守拙愚，此道未嘗枉。", "行當至峴山，羊公存廟像。", "簫鼓有時奠，道德其可仰。"]'),
('18ccd255-f727-40c8-aca6-9467325af595','依韻和持國新植西軒','梅堯臣','宋','宋诗','song-poetry','','[]','開地臨廣衢，崇崇十餘畝。',156,'全唐诗/poet.song.14000.json','["開地臨廣衢，崇崇十餘畝。", "新軒稍偏北，治圃亦西酉。", "盎中植菡萏，水不過升斗。", "小桂未得地，驗活徒掐朽。", "上乏幽禽啼，下多穴蟻走。", "藥苗雖無補，欲比山中有。", "澆灌同一時，萌芽或先後。", "松株不滿尺，廊廟色已厚。", "稟性久且堅，物理豈無偶。", "椶櫚仍未大，散葉纔八九。", "夏綠與冬青，各各自爲友。", "吾軒還處西，脩竹爾後取。", "兩莫論是非，但可吟對酒。"]'),
('3e95e75c-df9e-4989-901a-9f06a46f8d99','送師直之會稽宰','梅堯臣','宋','宋诗','song-poetry','','[]','天下風物佳，莫出吳與越。',96,'全唐诗/poet.song.14000.json','["天下風物佳，莫出吳與越。", "新罷吳官來，又隨越舸發。", "連宰吳越間，皆邇蛟鼉窟。", "伯氏復同郡，邑境接民垡。", "寧將內隔外，正似肉附骨。", "姚江遺魚蟹，稽山奉筍蕨。", "足得相交歡，高堂未華髮。", "送子意不盡，念逐有明月。"]'),
('380df18f-f536-4164-b59a-a9410729f899','西湖觀新出鵝兒道損持國曼叔請予賦之','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春菢畏雷後，鷇開形已完。',48,'全唐诗/poet.song.14000.json','["春菢畏雷後，鷇開形已完。", "嫩毛輕染蘗，小掌未全丹。", "見物初能啑，浮波尚怕寒。", "山陰無道士，更長換應難。"]'),
('302aff35-f1ea-43dd-a204-a2dcd7f7fd98','送李密學赴亳州','梅堯臣','宋','宋诗','song-poetry','','[]','倦輸關內粟，遂請潁川符。',72,'全唐诗/poet.song.14000.json','["倦輸關內粟，遂請潁川符。", "治績可稱最，士民將以蘇。", "譙都君命重，苦縣祖風殊。", "仙檜留陰在，甘棠即化敷。", "行舟通遠水，候騎溢長衢。", "他日人懷望，煙雲自滿湖。"]'),
('ae6642d3-56fa-4c55-93b8-01209b9ebdb9','送樊秀才歸安州','梅堯臣','宋','宋诗','song-poetry','','[]','開元有謫仙，酒隠向安陸。',108,'全唐诗/poet.song.14000.json','["開元有謫仙，酒隠向安陸。", "子嘗慕其人，文字不拘束。", "月下每醉吟，落紙輒數幅。", "今當安陸歸，白酒村中熟。", "一名猶未成，雙親淚盈目。", "切莫苦銜杯，無心不擇祿。", "去去煙水間，野禽嘷古木。", "聞聲不得名，將投山舍宿。", "此趣自可嘉，非如走塵轂。"]'),
('2c875f6a-fc5b-4a96-815e-a10d94e7c431','依韻李密學合流河口見懷','梅堯臣','宋','宋诗','song-poetry','','[]','二水交流抱閭井，清潭幾曲自淵回。',32,'全唐诗/poet.song.14000.json','["二水交流抱閭井，清潭幾曲自淵回。", "已浮畫舸遥遥去，更愛雙鷖泛泛來。"]'),
('df797228-86e8-458a-aa48-81c37251abe1','觀理蔬','梅堯臣','宋','宋诗','song-poetry','','[]','野薺不堪食，蕪菁今正肥。',48,'全唐诗/poet.song.14000.json','["野薺不堪食，蕪菁今正肥。", "夏畦人所病，老圃方可窺。", "乳雀爭銜蝶，鳴鴉各護兒。", "於陵豈復有，空學桔槔爲。"]'),
('35cba09c-c662-474b-88bd-39ae57d71c1b','哭尹師魯','梅堯臣','宋','宋诗','song-poetry','','[]','謫死古來有，無如君甚冤。',48,'全唐诗/poet.song.14000.json','["謫死古來有，無如君甚冤。", "文章不世用，器業欲誰論。", "野鳥災王傅，招辭些屈原。", "平生洛陽友，零落幾人存。"]'),
('54a359b1-8b41-4a58-8387-337664fce3f9','泛舟和持國','梅堯臣','宋','宋诗','song-poetry','','[]','綠源去未窮，夾岸樹濛濛。',48,'全唐诗/poet.song.14000.json','["綠源去未窮，夾岸樹濛濛。", "弱蔓低侵水，殘芳不隠叢。", "浣衣思越婦，折笋擬江童。", "薄暮迴船處，潭魚動鏡中。"]'),
('992b29f2-acea-43eb-ae6b-c9059c63ae80','欲晚訪韓持國忽道損見過不克往持國示詩因答','梅堯臣','宋','宋诗','song-poetry','','[]','西雲沉日脚，命僕駕我車。',48,'全唐诗/poet.song.14000.json','["西雲沉日脚，命僕駕我車。", "我車已在庭，有客方詣廬。", "談笑不覺夕，雞黍且煩渠。", "重約勿以怪，但當摘園蔬。"]'),
('a2dd1ce1-1f75-49bb-92de-df4e5275d81e','送京西轉運李刑部移京東轉運','梅堯臣','宋','宋诗','song-poetry','','[]','列藩環王都，遂分東西道。',72,'全唐诗/poet.song.14000.json','["列藩環王都，遂分東西道。", "統制連別京，守臣多碩老。", "外臺持權綱，才具必美好。", "公今且更踐，入用頗不早。", "乃令山東粟，餉饋歲可保。", "古路趨汶陽，長風吹綠草。"]'),
('c673a6ef-732a-422a-8270-687f7cdfd382','送李庭老歸河陽','梅堯臣','宋','宋诗','song-poetry','','[]','五月馳乘車，歸心豈畏暑。',48,'全唐诗/poet.song.14000.json','["五月馳乘車，歸心豈畏暑。", "道上多清陰，日中不遑處。", "函谷自控带，大河無險阻。", "時平獨往還，拜壽觴屢舉。"]'),
('d1bbf2c5-d02f-435d-ba85-a1838b5cdf5d','詠雙杏子其核亦然','梅堯臣','宋','宋诗','song-poetry','','[]','子核成雙杏，將寄同心人。',24,'全唐诗/poet.song.14000.json','["子核成雙杏，將寄同心人。", "定棲鴛鴦魄，爲物豈無因。"]'),
('36295b9a-6cff-424d-b988-04ecaeb0750a','和王仲儀楸花十二韻','梅堯臣','宋','宋诗','song-poetry','','[]','春陽發草木，美好一同時。',144,'全唐诗/poet.song.14000.json','["春陽發草木，美好一同時。", "桃李雜山櫻，紅白開繁枝。", "楸英獨步媚，淡紫相參差。", "大葉與勁幹，簇萼密自宜。", "圖出帝宮樹，聳向白玉墀。", "高絕不近俗，直許天人窺。", "今植郡庭中，根遠未可移。", "但欣東風來，不恨和煦遲。", "山禽勿蹙踏，蜂蝶休掇之。", "昔聞韓吏部，爲爾作好詩。", "愛陰無纖穿，就陰東西隨。", "公今亦牽此，端坐曾莫疑。"]'),
('f662ac75-d0b4-404f-a023-da1352e36ccc','目昏','梅堯臣','宋','宋诗','song-poetry','','[]','我目忽病昏，白晝若逢霧。',48,'全唐诗/poet.song.14000.json','["我目忽病昏，白晝若逢霧。", "窺驚隻物雙，書輒下筆誤。", "來人髣髴是，飛鳥朦朧度。", "紜紜孰辨別，此已忘好惡。"]'),
('c0cb8bf1-885e-4287-9590-3dd08593c34f','送韓八太祝歸京師求醫','梅堯臣','宋','宋诗','song-poetry','','[]','少年絜而腴，茸茸頷有鬚。',144,'全唐诗/poet.song.14000.json','["少年絜而腴，茸茸頷有鬚。", "冒熱跨馬去，去去天王都。", "借問去何謂，就醫將疾驅。", "客曰實誑我，健壯其非夫。", "敢告固不紿，但怪所見愚。", "瘠者未必病，病者未必癯。", "天馬不著肉，日走萬里途。", "山熊豈無膏，養體唯恐痡。", "滯結在於內，安得形肌膚。", "厥貌雖美好，厥疢勿須臾。", "療之欲其漸，熾之非愛軀。", "此行不飲別，安得持酒壺。"]'),
('6aa53110-485b-40b3-94fd-f7676da82519','記春水多紅雀傳云自新羅而至道損得之請余賦','梅堯臣','宋','宋诗','song-poetry','','[]','赤羽異蒿鷃，來自東夷國。',72,'全唐诗/poet.song.14000.json','["赤羽異蒿鷃，來自東夷國。", "羣集成皋間，翩翩皆一色。", "舉臆發朱砂，爲瑞應火德。", "穿屋彼非類，啄粟慙與食。", "清聲殊啁啾，所蓄每陋逼。", "應當放之去，重展萬里翼。"]'),
('a47e574a-8c91-4829-a224-164b15d7bf89','持國遺食','梅堯臣','宋','宋诗','song-poetry','','[]','乞食非爲貧，妻病妾且死。',72,'全唐诗/poet.song.14000.json','["乞食非爲貧，妻病妾且死。", "晨爨不暖釜，朝飯亦輟匕。", "遺我我所恤，食我我所恥。", "我恥曾我求，我恤寧我止。", "應乏豈在豐，赴義實未鄙。", "漂母殊下鄉，爲惠得終始。"]'),
('cdd8af16-34a9-4f47-bfa1-2d151518fb7d','捫蝨得蚤','梅堯臣','宋','宋诗','song-poetry','','[]','茲日頗所愜，捫蝨反得蚤。',48,'全唐诗/poet.song.14000.json','["茲日頗所愜，捫蝨反得蚤。", "去惡雖未殊，快意乃爲好。", "物敗誰可必，鈍老而狡夭。", "穴蟻不囓人，其命常自保。"]'),
('ad89ee41-53e0-4b9a-bce2-7b5d9cb3ceb8','同道損世則元輔遊西湖於卞氏借雙鶴以觀','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u592a\u6e56"]','塘蒲蔭綠水，菡萏豔修渚。',132,'全唐诗/poet.song.14000.json','["塘蒲蔭綠水，菡萏豔修渚。", "想像華亭野，但欠鳴鶴侶。", "同來三四人，趣向頗相與。", "思見此清禽，無能覿翔羽。", "城隅有大第，世本官吳楚。", "嘗同太湖石，不惜持金取。", "欲作園林勝，園林寧暇覩。", "今當問其家，借賞無吾拒。", "果亦致之來，奮毛如喜舞。", "雖生滄海心，翅重不得舉。", "還爾稻粱貪，崇丘在何所。"]'),
('59fd6cd4-0c5c-478d-96fe-f7b0b125ed40','送上虞孫主簿','梅堯臣','宋','宋诗','song-poetry','','[]','稽山參雲深，剡水與天碧。',48,'全唐诗/poet.song.14000.json','["稽山參雲深，剡水與天碧。", "行將啼鳥親，翫不游鱗隔。", "況世住新安，又嘗爲粵客。", "風物知所諳，窮幽梯翠壁。"]'),
('049a95fc-bd96-455b-9852-6ad5f09dead1','寄題金州孫御史處陰亭','梅堯臣','宋','宋诗','song-poetry','','[]','有形則有影，畏影當念形。',72,'全唐诗/poet.song.14000.json','["有形則有影，畏影當念形。", "日月難久晦，處陰乃暫停。", "光照不復離，疾走何所寧。", "當是誚尼父，我輩烏忍聽。", "結廬雖可託，夜燭亦熒熒。", "直躬觀罔兩，將此同醉醒。"]'),
('07ecf3f7-7c00-4ca3-8be8-045fa7802885','石榴','梅堯臣','宋','宋诗','song-poetry','','[]','榴枝苦多雨，過熟坼已半。',48,'全唐诗/poet.song.14000.json','["榴枝苦多雨，過熟坼已半。", "秋雷石罌破，曉日丹砂爛。", "任從雕俎薦，豈待霜刀判。", "張騫西使時，蒟醤同歸漢。"]'),
('3365d496-eff4-4fd6-9d30-392e72203491','七夕','梅堯臣','宋','宋诗','song-poetry','','[]','古來傳織女，七夕渡明河。',48,'全唐诗/poet.song.14000.json','["古來傳織女，七夕渡明河。", "巧意世爭乞，神光誰見過。", "隔年期已拙，舊俗驗方訛。", "五色金盤果，蜘蛛浪作窠。"]'),
('2ca06432-f7d5-4614-8e56-1edd3ab3147c','同諸韓及孫曼叔晚遊西湖三首  其一','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晚日城頭落，輕鞍果下凉。',48,'全唐诗/poet.song.14000.json','["晚日城頭落，輕鞍果下凉。", "野蜂銜水沫，舟子剝菱黄。", "木老識秋氣，徑幽聞草香。", "幅巾聊去檢，不作楚人狂。"]'),
('3eb5e9d8-e3b3-4955-8ecd-8bf6c85c3c6a','同諸韓及孫曼叔晚遊西湖三首  其二','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爍電未成雨，凉風先入衣。',48,'全唐诗/poet.song.14000.json','["爍電未成雨，凉風先入衣。", "青天忽開影，紅日尚餘暉。", "蛺蝶作團起，蜻蜓相戴飛。", "嘲謔不覺夕，跨馬月中歸。"]'),
('4b3341a0-d96c-4d68-b558-03fbf7424e70','同諸韓及孫曼叔晚遊西湖三首  其三','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舟中演滿意不淺，却坐林塘景欲昏。',32,'全唐诗/poet.song.14000.json','["舟中演滿意不淺，却坐林塘景欲昏。", "翠色蜻蜓立菱蘂，青絲騕裊秣城根。"]'),
('286cfeca-55cd-41a3-b7fb-d98b7608a252','韓玉汝遺澄心紙二軸初得此物歐陽永叔又得於宋次道又得於君伯氏子華今則四矣','梅堯臣','宋','宋诗','song-poetry','','[]','三得澄心紙，吾嘗再有詩。',48,'全唐诗/poet.song.14000.json','["三得澄心紙，吾嘗再有詩。", "粗能條本末，不復語興衰。", "堪入右軍跡，慙無幼婦辭。", "君家兄弟意，將此比烏絲。"]'),
('f0f3120d-841f-4336-9bc3-54ddb7f19fe1','和王仲儀二首 麝香','梅堯臣','宋','宋诗','song-poetry','','[]','游伏柏林下，食柏遂生香。',48,'全唐诗/poet.song.14000.json','["游伏柏林下，食柏遂生香。", "空知噬臍患，豈有周身防。", "赤豹以尾死，猛虎以睛喪。", "儻或益於用，捐軀死其常。"]'),
('ba75235a-7572-474e-9a50-fd0064da3033','和王仲儀二首 凌霄花','梅堯臣','宋','宋诗','song-poetry','','[]','草木不解行，隨生自有理。',72,'全唐诗/poet.song.14000.json','["草木不解行，隨生自有理。", "觀此引蔓柔，必憑高樹起。", "氣類固未合，縈纏豈由己。", "仰見蒼虬枝，上發彤霞蘂。", "層霄不易凌，樵斧誰家子。", "一日摧作薪，此物當共委。"]'),
('7f3f2d1f-a5e8-4e21-bb4e-572fb80f6d42','七月二十一夜聞韓玉汝宿城北馬鋪','梅堯臣','宋','宋诗','song-poetry','','[]','暗樹秋風擺葉鳴，桃枝竹簟冷逾清。',32,'全唐诗/poet.song.14000.json','["暗樹秋風擺葉鳴，桃枝竹簟冷逾清。", "孤燈淡淡短亭客，半夜蕭蕭聞雨聲。"]'),
('a2dfac7c-63d4-48d0-aab7-3d936930c5dd','夢過三陵','梅堯臣','宋','宋诗','song-poetry','','[]','夢過漢陵間，秋風石馬閒。',24,'全唐诗/poet.song.14000.json','["夢過漢陵間，秋風石馬閒。", "當年侍臣淚，泣盡向三山。"]'),
('2975f772-b934-4bba-a3a4-c196015edc53','詠扇','梅堯臣','宋','宋诗','song-poetry','','[]','翦紈成薄質，誰將擬月輪。',48,'全唐诗/poet.song.14000.json','["翦紈成薄質，誰將擬月輪。", "閔竭夏后德，同我天王仁。", "及至爲時用，豈必畫美人。", "何憂秋風來，退保藏其真。"]'),
('34202205-332f-4d02-bc75-9eb44e50eee0','送曼叔襄城尉','梅堯臣','宋','宋诗','song-poetry','','[]','昔君乘紫騮，來獵荒城下。',48,'全唐诗/poet.song.14000.json','["昔君乘紫騮，來獵荒城下。", "復乘紫騮去，不逢亭長駡。", "溪風欲涉時，山雪獨歸夜。", "此趣信所諳，羈官莫悲叱。"]'),
('d38b9226-3d63-4b58-afea-5f9a4a637e17','送吳給事自許昌移淮西','梅堯臣','宋','宋诗','song-poetry','','[]','直道昔參輔，獨將天下憂。',72,'全唐诗/poet.song.14000.json','["直道昔參輔，獨將天下憂。", "忠言悟明主，退請拜諸侯。", "坐閤政方舉，移藩心所求。", "蔡人迎且喜，許俗愛難留。", "夾路車徒盛，分疆禾黍秋。", "穆陵無夜閉，仁化自公修。"]'),
('ae9fdc00-5b03-4cd3-aa99-cb64f3894b39','亳州李密學寄御棗一篋','梅堯臣','宋','宋诗','song-poetry','','[]','沛譙有鉅棗，味甘蜜相差。',60,'全唐诗/poet.song.14000.json','["沛譙有鉅棗，味甘蜜相差。", "其赤如君心，其大如王瓜。", "嘗貢趨國門，豈及貧儒家。", "今見待士意，下異盧仝茶。", "食之無厭飫，詠德曾未涯。"]'),
('9f6f4e2b-7c81-481e-af2e-a77dcb2dfe69','九月五日夢歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','[]','朝鏡惡白髮，夕夢對故人。',48,'全唐诗/poet.song.14000.json','["朝鏡惡白髮，夕夢對故人。", "常恨道路隔，忽喜顔色親。", "相笑勿問年，青銅早傷神。", "雞嚎天欲白，向者猶疑真。"]'),
('d7a62997-6c6e-4800-8f35-a26b9062da64','自尉氏南至京皆水及人脛','梅堯臣','宋','宋诗','song-poetry','','[]','陸行畏水深，舟行畏水淺。',48,'全唐诗/poet.song.14000.json','["陸行畏水深，舟行畏水淺。", "河流去時閤，涂潦歸時踐。", "事與時相違，我慙行處蹇。", "人生莫爲客，爲客此安免。"]'),
('8000620c-5c57-45ae-9574-35c6160d9536','九月十六日自許昌迴至京師胥平叔宋中道迓于郊外','梅堯臣','宋','宋诗','song-poetry','','[]','今日至國門，二子來迎我。',48,'全唐诗/poet.song.14000.json','["今日至國門，二子來迎我。", "適遇信陵冢，冢棘秋葉墮。", "翩翻隨人飛，拂馬右或左。", "謂此獨無情，亦與吾意可。"]'),
('c5474bc1-d827-4d8b-9f43-8a4b42d69e71','裴如晦赴河陽幕','梅堯臣','宋','宋诗','song-poetry','','[]','嚎風一夜動，作雪欲愁客。',48,'全唐诗/poet.song.14000.json','["嚎風一夜動，作雪欲愁客。", "客莫苦嗟行，農望明年麥。", "方來笑語同，又是關河隔。", "主人賢且智，不待子所畫。"]'),
('d38c1050-9f04-4f22-ac39-d45daed11b53','送韓子華十月拜掃','梅堯臣','宋','宋诗','song-poetry','','[]','白露已變霜，孝心竟悲惻。',48,'全唐诗/poet.song.14000.json','["白露已變霜，孝心竟悲惻。", "薦衣如念存，拜壠不遑息。", "带劍蓬池外，兼程困馬力。", "禮畢便當還，於誠乃爲得。"]'),
('6b8277fd-3346-4b37-9bd0-9a2cf81a2b34','送韓六玉汝宰錢塘','梅堯臣','宋','宋诗','song-poetry','','[]','頃尋高士廬，正值浸湖雪。',96,'全唐诗/poet.song.14000.json','["頃尋高士廬，正值浸湖雪。", "雪中千萬峯，參差縣前列。", "僧居或隠見，岸樹隨曲折。", "驚鳬如避人，遠向寒煙滅。", "潛希爲子男，儻得遂疎拙。", "今逾二十年，志願徒切切。", "方聞落君手，與我曾未別。", "景多詩莫窮，歸載壓車轍。"]'),
('ae1ea164-f8fe-49bf-a87e-d3fb2a967a25','得曾鞏秀才所附滁州歐陽永叔書答意','梅堯臣','宋','宋诗','song-poetry','','[]','客從淮上來，往問故人信。',132,'全唐诗/poet.song.14000.json','["客從淮上來，往問故人信。", "袖銜藤紙書，題字遠已認。", "既喜開其封，固覺減吾吝。", "新詩不作寄，乃見子所慎。", "向來能如今，豈有得觀釁。", "南方歲苦熱，生蝗復饑饉。", "憂心日自勞，霜髮應滿鬢。", "知予欲東歸，曉夕目不瞬。", "貧難久待乏，薄祿藉霑潤。", "雖爲委吏冗，亦自甘以進。", "相望未得親，終朝如抱疹。"]'),
('779a633b-2a12-4bb5-a279-59beef0598ba','追詠崔奉禮小園','梅堯臣','宋','宋诗','song-poetry','','[]','前此訪君時，已觀堂宇邃。',60,'全唐诗/poet.song.14000.json','["前此訪君時，已觀堂宇邃。", "安知中屏開，自有幽林致。", "花搴巖桂紅，石擘雲根翠。", "正當秋風來，不見摇落意。", "日得吟其間，何須去爲吏。"]'),
('5610e5aa-a0da-4b5e-91c4-ef261b0f7d05','宋中道快我生女','梅堯臣','宋','宋诗','song-poetry','','[]','爾嘗喜詛予，生女竟勿怪。',48,'全唐诗/poet.song.14000.json','["爾嘗喜詛予，生女竟勿怪。", "今遂如爾口，是宜爲爾快。", "亦既以言酬，固且殊眥睚。", "慰情何必男，茲語當自戒。"]'),
('0a29e3d7-81a6-40cf-8e32-53fe26e6fc0d','詠宋中道宅椶櫚','梅堯臣','宋','宋诗','song-poetry','','[]','青青椶櫚樹，散葉如車輪。',84,'全唐诗/poet.song.14000.json','["青青椶櫚樹，散葉如車輪。", "擁蘀交紫髯，歲剝豈非仁。", "用以覆雕輿，何憚尅厥身。", "今植公侯第，愛惜知幾春。", "完之固不長，只與薺本均。", "幸當敕園吏，披割見日新。", "是能去窘束，始得物理親。"]'),
('3f976c52-6d83-4af9-9977-924e56856932','詠秤','梅堯臣','宋','宋诗','song-poetry','','[]','聖人防爭心，權衡爲之設。',48,'全唐诗/poet.song.14000.json','["聖人防爭心，權衡爲之設。", "後世失其平，有星徒爾列。", "物物尚可欺，銖銖不須別。", "將淳天下民，安得必毀折。"]'),
('f3dbc59e-1435-4674-8669-6c0c3de8c6c0','詠象韓子華邀賦','梅堯臣','宋','宋诗','song-poetry','','[]','軀大力無用，遠物賞馴柔。',48,'全唐诗/poet.song.14000.json','["軀大力無用，遠物賞馴柔。", "食芻與飲水，百倍於馬牛。", "猶能絡金羈，不可伏車輈。", "蒼舒曾智秤，千鈞空壓舟。"]'),
('ece3fa13-eade-4c7f-83fa-a7cdaea7595a','依韻答惠勤上人','梅堯臣','宋','宋诗','song-poetry','','[]','釋子本樂靜，宜不事物牽。',48,'全唐诗/poet.song.14000.json','["釋子本樂靜，宜不事物牽。", "我慙姑蘇守，復賞杼山然。", "三歲與之別，其學已增前。", "忽此有來贈，老拙謬躭研。"]'),
('98b1cfec-9e83-4595-85d7-7a4109e54a7f','答顯忠上人','梅堯臣','宋','宋诗','song-poetry','','[]','驅馬傍馳道，歸自許西偏。',96,'全唐诗/poet.song.14000.json','["驅馬傍馳道，歸自許西偏。", "高車非舊貴，立避槐樹邊。", "心雖欲往謁，僕餒行不前。", "是甘處窮巷，晨笑微生煙。", "儻有好事者，扣門與留連。", "或有袖中詩，語熟氣頗全。", "曾不類緇褐，始可令勉旃。", "京師百許寺，知幾相差肩。"]'),
('63aad9e4-813f-4d2d-bd65-51d182871e40','送韓仲文奉使','梅堯臣','宋','宋诗','song-poetry','','[]','往使匈奴國，持節豈辭遥。',84,'全唐诗/poet.song.14000.json','["往使匈奴國，持節豈辭遥。", "朔北正苦寒，風汝與雪飄。", "燕山何處是，漢銘應已銷。", "前車渡冰河，後騎鳴金鑣。", "行行至穹廬，尊我不敢囂。", "玉爵親獻酬，名裘進狐貂。", "禮成復命日，菀抑舒楊條。"]'),
('94009b31-643a-4698-9911-2cacf61a252e','送劉司勳奉使','梅堯臣','宋','宋诗','song-poetry','','[]','授命出絕域，北至單于庭。',60,'全唐诗/poet.song.14000.json','["授命出絕域，北至單于庭。", "駞鳴沙磧遥，馬倦朔雪零。", "幽州古道上，胡笳應夜聽。", "嘗聞昔時語，南看北辰星。", "使回儻可記，乃得驗天形。"]'),
('390d2be2-d0ba-49fe-8afd-f2367f986a45','依韻和歐陽永叔秋懷擬孟郊體見寄二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','我居西北地，秋無東南風。',72,'全唐诗/poet.song.14000.json','["我居西北地，秋無東南風。", "木脫不塞望，高臺空九重。", "音塵安可得，鴻鴈鳴霜中。", "日看紫苔生，乃見三經窮。", "一聞離騷篇，寫盡楚客胸。", "胸懷如寶匣，夜夜吼生銅。"]'),
('5ca1fdf4-3fda-46f0-acf2-eb03f00ee6f6','依韻和歐陽永叔秋懷擬孟郊體見寄二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','秋思公何高，堆積自嵱嵷。',84,'全唐诗/poet.song.14000.json','["秋思公何高，堆積自嵱嵷。", "出爲悲秋辭，萬仞見孤聳。", "念我老於詩，我髮實種種。", "而後傷故人，故人多作塚。", "陰風夜木嘷，窸窣聞鬼悚。", "獨我忘形骸，百事乃纖冗。", "不眠霜月上，霜月如可捧。"]'),
('894751a4-8891-472c-a74a-4ce93d73996e','裴如晦自河陽至同韓玉汝謁之','梅堯臣','宋','宋诗','song-poetry','','[]','朝聞單騎歸，徑走至其第。',96,'全唐诗/poet.song.14000.json','["朝聞單騎歸，徑走至其第。", "扣門童僕頑，拒我色甚戾。", "不顧遂登堂，有馬堂下繫。", "辨詐大呼卿，稍應西屋際。", "逡巡冠带出，青綬何曳曳。", "有似縮殻龜，藏頭非得計。", "況與二三子，交分久已締。", "恕爾避客尤，新婚復新婿。"]'),
('329c8973-2ede-4f85-af98-36fb3feafaf6','詠王宗說園黄木芙蓉','梅堯臣','宋','宋诗','song-poetry','','[]','水中兼木末，相擬有嘉花。',48,'全唐诗/poet.song.14000.json','["水中兼木末，相擬有嘉花。", "玉蘂圻蒸粟，金房落晚霞。", "涉江從楚女，采菊聽陶家。", "事與離騷異，吾將搴以誇。"]'),
('58baf18d-e8a0-4d19-a852-1e0b47a8affe','二馬','梅堯臣','宋','宋诗','song-poetry','','[]','舊馬十年跨，老劣多緩行。',48,'全唐诗/poet.song.14000.json','["舊馬十年跨，老劣多緩行。", "新駒三萬錢，頗愛舉蹄輕。", "不使異芻秣，均養存其情。", "君門趨早朝，風勁力已生。"]'),
('efc66514-7600-4b10-9166-b0201406ea06','依韻和發運許主客詠影','梅堯臣','宋','宋诗','song-poetry','','[]','答影陶潛興，長吟爲我聽。',48,'全唐诗/poet.song.14000.json','["答影陶潛興，長吟爲我聽。", "與之相遇日，曾不異於形。", "動靜隨生趣，存藏委曜靈。", "莊周疾走意，推本置諸銘。"]'),
('17fc2c37-2874-42ff-9b55-3ea727c53b8b','寄題周源員外衢州萃賢亭','梅堯臣','宋','宋诗','song-poetry','','[]','昨朝江南客，語子川上亭。',48,'全唐诗/poet.song.14000.json','["昨朝江南客，語子川上亭。", "有時飛雨來，不見前山青。", "卉萼人未識，鳥響日可聽。", "既將遲賢者，無使童僕扃。"]'),
('3986529d-28cf-46cd-8a72-eb8dd5233574','答楚僧智普始與吳僧顯忠來過今見二人詩進於舊矣','梅堯臣','宋','宋诗','song-poetry','','[]','我初見子時，子作楚人語。',48,'全唐诗/poet.song.14000.json','["我初見子時，子作楚人語。", "復與吳客來，音俱變齊魯。", "乃知久處益，薰蕕可同舉。", "更當富於學，茲言聊以補。"]'),
('767baa1f-30d3-454e-80be-0c655afee382','鴨雛','梅堯臣','宋','宋诗','song-poetry','','[]','春鴨日浮波，羽冷難伏卵。',96,'全唐诗/poet.song.14000.json','["春鴨日浮波，羽冷難伏卵。", "嘗因雞抱時，託以雞窠暖。", "三旬殻既坼，乳毛寒脛短。", "雞寧辨其雛，翅擁情欵欵。", "一日向水涯，所稟殊未斷。", "泛然去中流，雞呼心悹悹。", "人之苟異懷，負義不足算。", "有志在養毓，勿論報德限。"]'),
('1b127638-bb9d-4e30-a30b-105dc41d60fb','有覩十一月七日','梅堯臣','宋','宋诗','song-poetry','','[]','來恨我馬遲，去恨我馬疾。',36,'全唐诗/poet.song.14000.json','["來恨我馬遲，去恨我馬疾。", "馬蹄塵作雲，已隔粲然質。", "時時顧且遥，亂緒如有失。"]'),
('9f901ec9-97f9-4c6e-a641-81189bcfde2a','杜挺之贈端溪圓硯','梅堯臣','宋','宋诗','song-poetry','','[]','雪壓古寺深，中有卧病客。',168,'全唐诗/poet.song.14000.json','["雪壓古寺深，中有卧病客。", "訪之語久清，饑馬齧庭柏。", "案頭蠻溪硯，其狀若圓璧。", "指此欲爲贈，而將助吟席。", "非意予敢貪，既拒頗不懌。", "大出楮中有，素許當自擇。", "强持慰勤心，歸以示朋戚。", "哂曰豈其然，爲汲寒泉滌。", "滌彼僞飾物，紙乾見頑石。", "清晨走髯奴，無厭願求易。", "拜賜遂如初，明月懷吞蝕。", "微分鸜目瑩，尚漬墨花碧。", "詞答謂我愚，悔復料已逆。", "明日未央朝，執手笑啞啞。"]'),
('216ad3e7-a781-4932-9dfe-063d540ab618','吳沖卿示和韓持國詩一卷輒以爲謝','梅堯臣','宋','宋诗','song-poetry','','[]','葉公所好者，熟已識頭角。',60,'全唐诗/poet.song.14000.json','["葉公所好者，熟已識頭角。", "一日真物來，駭汗沛且渥。", "我初見韓子，蜿蜒噴雷雹。", "子復蛟龍文，氣象不可捉。", "畏懷但驚顧，得與前事較。"]'),
('dd29e7b8-9341-4e7f-a1e0-1bbc3b4be5d0','范景仁席中賦莆萄','梅堯臣','宋','宋诗','song-poetry','','[]','朱盤何纍纍，紫乳封霜厚。',36,'全唐诗/poet.song.14000.json','["朱盤何纍纍，紫乳封霜厚。", "今爲馬谷繁，昔釀梁州酒。", "乃知西土珍，漢使傳應久。"]'),
('f3a36775-f139-4f62-b1a8-01ae4fe3ce30','夜聽鄰家唱','梅堯臣','宋','宋诗','song-poetry','','[]','夜中未成寐，鄰歌聞所稀。',48,'全唐诗/poet.song.14000.json','["夜中未成寐，鄰歌聞所稀。", "想像朱唇動，髣髴梁塵飛。", "誤節應偷笑，竊聽起披衣。", "披衣曲已終，窗月存餘暉。"]'),
('1938feec-550e-4764-b032-9be33983e8a8','宋次道得廣南金橘爲餉且有詩因和酬','梅堯臣','宋','宋诗','song-poetry','','[]','越橘如金丸，爛然已盈篋。',48,'全唐诗/poet.song.14000.json','["越橘如金丸，爛然已盈篋。", "誰傳嶺外信，尚带霜前葉。", "莫嫌道路遠，得與樽俎接。", "主人無吝心，懷歸予敢輒。"]'),
('f270275b-c1e2-491c-9b68-99d0edbf4dc8','李廷老席上送韓持國歸許昌得早字','梅堯臣','宋','宋诗','song-poetry','','[]','馬蹄踐霜華，遊國歸何早。',48,'全唐诗/poet.song.14000.json','["馬蹄踐霜華，遊國歸何早。", "重裘不畏寒，況復非遠道。", "誰言未顧期，登第鬢如葆。", "解裝喜可知，月下金壺倒。"]'),
('94ed59d3-55a1-46fb-8ba5-42cb1ee00a12','送韓持國','梅堯臣','宋','宋诗','song-poetry','','[]','曰予非才敏，乃與世寡游。',144,'全唐诗/poet.song.14000.json','["曰予非才敏，乃與世寡游。", "三四洛陽友，過半已成丘。", "晚節五六人，文行皆潔修。", "韓氏棣萼盛，於我爲薰蕕。", "君比衆最篤，我唱君非酬。", "昔我竹軒下，破窗風颼飀。", "君時不厭過，逍遥談未休。", "頗爲俗士憎，恬不防吝尤。", "邇來我還都，君亦辭舊州。", "舊州君所隠，安得此久留。", "雪晴命駕歸，使我生悲愁。", "誰見潩水上，定更不驚鷗。"]'),
('5b576299-0ba7-43d8-9ee2-1fa4391bdd30','遲月','梅堯臣','宋','宋诗','song-poetry','','[]','遲月月已上，清光在高木。',24,'全唐诗/poet.song.14000.json','["遲月月已上，清光在高木。", "未能照我庭，團團隔東屋。"]'),
('48e6403c-38c6-430a-b824-c3f56ff1e7b4','風笛','梅堯臣','宋','宋诗','song-poetry','','[]','既殊出塞聲，還非江上聽。',24,'全唐诗/poet.song.14000.json','["既殊出塞聲，還非江上聽。", "夜吹送悠揚，高樓月方迥。"]'),
('0b4c7971-db16-4c50-9657-93914138c9ec','霜鐘','梅堯臣','宋','宋诗','song-poetry','','[]','昔向寒溪卧，遠寺撞白雲。',24,'全唐诗/poet.song.14000.json','["昔向寒溪卧，遠寺撞白雲。", "今也趨早朝，殘月馬上聞。"]'),
('ac7efd41-083b-41e4-bbfe-5e86485b524c','鳴琴','梅堯臣','宋','宋诗','song-poetry','','[]','雖傳古人聲，不識古人意。',24,'全唐诗/poet.song.14000.json','["雖傳古人聲，不識古人意。", "古人今已遠，悲哉廣陵思。"]'),
('4e96fc6d-98e1-4ac1-848e-6c74219d28ab','和曹光道詠直廬屏中六鶴','梅堯臣','宋','宋诗','song-poetry','','[]','漢家爲瑞雙黄鵠，只道飛翻太液池。',32,'全唐诗/poet.song.14000.json','["漢家爲瑞雙黄鵠，只道飛翻太液池。", "不似雲屏六畫鶴，帝宮深處有人知。"]'),
('29a78f60-6370-43e7-a9f9-fda125e2af4f','晚歸聞韓子華見訪','梅堯臣','宋','宋诗','song-poetry','','[]','門外多車騎，後迹亂前蹤。',60,'全唐诗/poet.song.14000.json','["門外多車騎，後迹亂前蹤。", "誰識此來過，塵蹄重復重。", "歸有野僕言，恨不故人逢。", "豈無肴酒設，所向乖所從。", "未能一往見，懶拙其必容。"]'),
('4b4c97fb-8d8f-4626-9444-e06ff713333e','送丹陽新守李國博歸洪州','梅堯臣','宋','宋诗','song-poetry','','[]','蔡水冬不枯，唯愁夜冰結。',60,'全唐诗/poet.song.14000.json','["蔡水冬不枯，唯愁夜冰結。", "歸船及暖下，窮臘未飛雪。", "淮潁地漸偏，川上雲常泄。", "幾日接春波，南風楚江徹。", "拜親懷郡章，予慕嗟才劣。"]'),
('67d741f7-cc57-462e-a1bb-ae4ee169129e','食薺','梅堯臣','宋','宋诗','song-poetry','','[]','世羞食薺貧，食薺我所甘。',72,'全唐诗/poet.song.14000.json','["世羞食薺貧，食薺我所甘。", "適見採薺人，自出國門南。", "土蠹瘦鐵刀，霜亂青竹籃。", "携持入凍池，挑以根葉參。", "手龜不自飽，食此尚可慙。", "肥羔朱尾魚，腥羶徒爾貪。"]'),
('0a94f0f1-466c-4cb4-a0ad-acc708fcf944','甘陵亂','梅堯臣','宋','宋诗','song-poetry','','[]','甘陵兵亂百物灰，火光屬天聲如雷。',80,'全唐诗/poet.song.14000.json','["甘陵兵亂百物灰，火光屬天聲如雷。", "雷聲三日屋瓦摧，殺人不問嬰與孩。", "守官迸走藏浮埃，後日稍稍官軍來。", "圍城幾匝如重鋂，萬甲雪色停皚皚。", "孰敢專輒但取裁，黄土始堅難速頹。"]'),
('9d14ca2b-bc91-4bb2-bd94-5869bce06589','夜飲席上賦松子','梅堯臣','宋','宋诗','song-poetry','','[]','風松有霜子，吹落幽人庭。',36,'全唐诗/poet.song.14000.json','["風松有霜子，吹落幽人庭。", "幽人畏狼藉，日掃出巖扃。", "誰將稱遠物，乃信涉滄溟。"]'),
('de6c329d-ad97-4575-a5f3-08efe2de0cac','送李審言殿丞歸河陽','梅堯臣','宋','宋诗','song-poetry','','[]','大河冬合時，上可馳車馬。',48,'全唐诗/poet.song.14000.json','["大河冬合時，上可馳車馬。", "子歸從橋安，黄流在冰下。", "況命使於家，其美世爲寡。", "是宜飭以行，慰此懷慕者。"]'),
('5554d617-f5e0-47d6-a830-52d165948018','送王宗說寺丞歸南京','梅堯臣','宋','宋诗','song-poetry','','[]','晏歲欲飛雪，滿天含凍雲。',48,'全唐诗/poet.song.14000.json','["晏歲欲飛雪，滿天含凍雲。", "犯寒單騎速，獵吹紫裘薰。", "庭鵲還先喜，池鴻去始聞。", "公應問貧賤，善說莫如君。"]'),
('4ff3da54-de22-49c7-ab26-6274d8f1eb3e','李審言將歸河陽值雪遺金波酒','梅堯臣','宋','宋诗','song-poetry','','[]','朔吹卷天吼，遠郊無鳥飛。',48,'全唐诗/poet.song.14000.json','["朔吹卷天吼，遠郊無鳥飛。", "忽驚門戶白，昨夜打窗微。", "閭巷我方懶，關山君獨歸。", "翻能寄醇酎，爲此解寒威。"]'),
('2fb82982-a6d3-4dfa-b87c-81a685c7f440','對雪憶往歲錢塘西湖訪林逋三首  其一','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔乘野艇向湖上，泊岸去尋高士初。',32,'全唐诗/poet.song.14000.json','["昔乘野艇向湖上，泊岸去尋高士初。", "折竹壓籬曾礙過，却尋松下到茅廬。"]'),
('97ef2bc9-1c87-4e5e-92cb-9c111439a090','對雪憶往歲錢塘西湖訪林逋三首  其二','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','旋燒枯栗衣猶濕，去愛峯前有徑開。',32,'全唐诗/poet.song.14000.json','["旋燒枯栗衣猶濕，去愛峯前有徑開。", "日暮更寒歸欲懶，無端撩亂入船來。"]'),
('ece30215-2623-45de-bf89-b98d940803f2','對雪憶往歲錢塘西湖訪林逋三首  其三','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','樵童野犬迎人後，山葛棠梨案酒時。',32,'全唐诗/poet.song.14000.json','["樵童野犬迎人後，山葛棠梨案酒時。", "不畏尖風吹入牖，更教牀畔覓鴟夷。"]'),
('b0214fa1-b8da-4ca1-9b24-fc44a9cac766','送鄞宰王殿丞','梅堯臣','宋','宋诗','song-poetry','','[]','君行問埼鮚，殊物可講解。',48,'全唐诗/poet.song.14000.json','["君行問埼鮚，殊物可講解。", "一寸明月腹，中有小碧蟹。", "生意各臑臑，黔角容夬夬。", "願言寬賦刑，越俗久疲憊。"]'),
('086213b9-4aaa-4ccb-8360-7c40063324c5','元日朝','梅堯臣','宋','宋诗','song-poetry','','[]','萬國諸侯振玉珂，踏雲朝會雪初過。',64,'全唐诗/poet.song.14000.json','["萬國諸侯振玉珂，踏雲朝會雪初過。", "欲聞鳳管天邊度，數聽雞人樓上歌。", "放仗旌旗方偃亞，迴頭宮闕更嵯峨。", "謬陪王屬曾何補，泛泛慙同上下波。"]'),
('fedb507a-75fc-4baa-a86e-a45c02cd748f','答祖擇之遺新羅墨','梅堯臣','宋','宋诗','song-poetry','','[]','海上老松苑，霹靂燒瘦龍。',60,'全唐诗/poet.song.14000.json','["海上老松苑，霹靂燒瘦龍。", "胡人犀皮膠，團煤煙膏濃。", "色奪陽烏翅，來涉溟渤重。", "君獲乃爲贈，我謬蟲鳥蹤。", "且作異土玩，不愧西域筇。"]'),
('dfabc410-6dbd-46e9-9040-be29f5b6ae7f','對殘雪懷歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','[]','窮臘一尺雪，跨春氣逾嚴。',48,'全唐诗/poet.song.14000.json','["窮臘一尺雪，跨春氣逾嚴。", "童僕苦病瘃，庭戶無與杴。", "日消夜復凍，霰積泥相醃。", "懶出獨懷遠，何由寄江帆。"]'),
('a6631b79-2d47-47a9-8727-57d17e845369','寄題時上人碧雲堂','梅堯臣','宋','宋诗','song-poetry','','[]','望望佳人來，未來雲已暮。',48,'全唐诗/poet.song.14000.json','["望望佳人來，未來雲已暮。", "當時千里恨，不獨看雲故。", "何此啟虛堂，定知吟秀句。", "還會古人心，古人非特賦。"]'),
('dedf471a-55ea-489d-b6f3-29e1dd4f910e','和宋中道元夕二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','結山當衢面九門，華燈滿國月半昏。',96,'全唐诗/poet.song.14000.json','["結山當衢面九門，華燈滿國月半昏。", "春泥踏盡遊人繁，鳴蹕下天歌吹喧。", "深坊靜曲走車轅，爭前鬭盛亡卑尊。", "靚妝麗服何柔溫，交觀互視各吐吞。", "磨肩一過難久存，眼尾獲笑迷精魂。", "貂裘比比王侯孫，夜闌鞍馬相馳奔。"]'),
('390ce7b3-9863-4ba9-a38d-a61aea4041bb','和宋中道元夕二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','春風來解吹殘雪，燈燭迎陽萬戶燃。',64,'全唐诗/poet.song.14000.json','["春風來解吹殘雪，燈燭迎陽萬戶燃。", "竟看繁星在平地，不妨明月滿中天。", "赭袍已向端門御，仙曲初聞法部傳。", "車馬不閒通曙色，康莊時見拾珠鈿。"]'),
('3612826d-f0fc-4d4a-861d-688c9a5ab9a6','李國博遺浙薑建茗','梅堯臣','宋','宋诗','song-poetry','','[]','吳薑漬吳糟，越茗苞越籜。',48,'全唐诗/poet.song.14000.json','["吳薑漬吳糟，越茗苞越籜。", "咀辛聊案杯，啜味可奴酪。", "但拜故人貺，何言爲物薄。", "我心易厭足，不比填溝壑。"]'),
('fd05fabb-2f38-4929-bc74-3790cbebc138','送臨江胥令','梅堯臣','宋','宋诗','song-poetry','','[]','初從桃源還，却向竟陵去。',48,'全唐诗/poet.song.14000.json','["初從桃源還，却向竟陵去。", "今作中州官，山水不曾飫。", "且當傳竹枝，莫學乘籃轝。", "雲木杜鵑時，千巖響行處。"]'),
('5ea28985-f1d2-4e3b-b4de-b64e64823572','寄題滁州醉翁亭','梅堯臣','宋','宋诗','song-poetry','','[]','瑯琊谷口泉，分流漾山翠。',108,'全唐诗/poet.song.14000.json','["瑯琊谷口泉，分流漾山翠。", "使君愛泉清，每來泉上醉。", "醉纓濯潺湲，醉吟異憔悴。", "日暮使君歸，野老紛紛至。", "但留山鳥啼，與伴松間吹。", "借問結廬何，使君游息地。", "借問醉者何，使君閒適意。", "借問鎸者何，使君自爲記。", "使君能若此，吾詩不言刺。"]'),
('2a8046f2-ece2-45bb-9a7e-0155f89d1bdd','戊子正月二十六日夜夢','梅堯臣','宋','宋诗','song-poetry','','[]','自我再婚來，二年不入夢。',48,'全唐诗/poet.song.14000.json','["自我再婚來，二年不入夢。", "昨宵見顔色，中夕生悲痛。", "暗燈露微明，寂寂照梁棟。", "無端打窗雪，更被狂風送。"]'),
('ae6ed542-0625-4dee-853a-63f48e1068da','賜緋魚','梅堯臣','宋','宋诗','song-poetry','','[]','蹉跎四十七，腰間始懸魚。',48,'全唐诗/poet.song.14000.json','["蹉跎四十七，腰間始懸魚。", "茜袍雖可貴，髮短齒已疎。", "兒女眼未識，競來牽人裾。", "不知外朝衆，君恩慙有餘。"]'),
('42ee8bf6-b467-4d88-affe-1edb6b5f474d','和答韓子華餉子魚','梅堯臣','宋','宋诗','song-poetry','','[]','南方海物難具名，子魚珍美無與并。',80,'全唐诗/poet.song.14000.json','["南方海物難具名，子魚珍美無與并。", "完鱗全乙異臭腥，素鹽漬曝生花輕。", "其頭戢戢筠篋盈，出自通印時所評。", "遠涉川陸來都城，親賓交遺已見情。", "食指嘗動吾竊驚，果獲異味亦足明。"]'),
('747e7662-e9ab-4331-aca1-41cef0bc64c2','和答韓奉禮餉荔枝','梅堯臣','宋','宋诗','song-poetry','','[]','韓盛人所希，四海饋名物。',72,'全唐诗/poet.song.14000.json','["韓盛人所希，四海饋名物。", "韓復未疎予，分珍曾不一。", "莆陽荔子乾，皺殻紅釘密。", "存甘尚可嘉，本味固已失。", "遥思海樹繁，带露摘初日。", "安得穆王駿，能置萬里疾。"]'),
('51dc1c55-0c9c-45c6-906a-ae37e7b0f62f','閏正月二日夜張氏納婦','梅堯臣','宋','宋诗','song-poetry','','[]','婚姻貴及時，周有摽梅詩。',48,'全唐诗/poet.song.14000.json','["婚姻貴及時，周有摽梅詩。", "雪後花爭發，人歸室且宜。", "坐中傳漏鼓，戶外轉星旗。", "環佩遥聞出，當脩廟見儀。"]'),
('afda661f-fad2-4211-8906-395e72eb535d','酌別謝通微判官兼懷歐陽永叔','梅堯臣','宋','宋诗','song-poetry','','[]','識君童稚時，而今君齒壯。',72,'全唐诗/poet.song.14000.json','["識君童稚時，而今君齒壯。", "不見二十年，顔貌已非向。", "親戚多零落，欲語還悲愴。", "更問平生交，久從滁水上。", "君又滁水歸，寄音傾桂釀。", "儻復二十年，吾焉保無恙。"]'),
('05568dc9-0f80-4ec2-96e8-076c2a1e12c9','和永叔郡齋聞百舌','梅堯臣','宋','宋诗','song-poetry','','[]','響舌能令百鳥羞，聽時丹杏發山郵。',32,'全唐诗/poet.song.14000.json','["響舌能令百鳥羞，聽時丹杏發山郵。", "春雲不定雨來急，濕翅蒼茫高樹頭。"]'),
('1af644d6-c293-474b-bad6-bfbc0933e576','送陶太博通判廣信軍','梅堯臣','宋','宋诗','song-poetry','','[]','平時易水頭，不復起邊愁。',48,'全唐诗/poet.song.14000.json','["平時易水頭，不復起邊愁。", "壯士去來久，寒波空自流。", "臨塘移鷺羽，隔戍見氈裘。", "半似江南美，軍和勝宴游。"]'),
('1b87e235-146c-4144-a150-6441d91f1135','答王太祝卷','梅堯臣','宋','宋诗','song-poetry','','[]','朝迴泥塗不可出，饑馬倦僕驅之頑。',80,'全唐诗/poet.song.14000.json','["朝迴泥塗不可出，饑馬倦僕驅之頑。", "閉門獨與古人語，黄卷未終聞扣關。", "賢哉公族肯來顧，詩袖大篇令我刪。", "珠光玉瑩絕瑕纇，强欲指擿徒羞顔。", "自同培塿最淺狹，安得與子論丘山。"]'),
('c0eeda0b-774f-48e9-9154-af3617160657','送張太博通判袁州','梅堯臣','宋','宋诗','song-poetry','','[]','君非身尤謫南州，南方尚鬼其俗媮。',88,'全唐诗/poet.song.14000.json','["君非身尤謫南州，南方尚鬼其俗媮。", "蛇爲鄰，虎爲陬，丹茅苦竹深幽幽。", "邑人祠鬼拜古樹，竹杯一仰來烹牛。", "牛死齧戄常不幸，誰得禁止專鋤鉤。", "借曰未信君且往，民將語怪君聽不。", "仰山頭，有行舟。"]'),
('11700ce0-e1d0-4e08-9db2-acf49fec63d4','依韻和宋中道雨夜','梅堯臣','宋','宋诗','song-poetry','','[]','暗驚料峭寒，春雪兼春雨。',48,'全唐诗/poet.song.14000.json','["暗驚料峭寒，春雪兼春雨。", "知勝早朝人，閒眠不開戶。", "丘壑豈無容，泥塗還自取。", "誰吟何遜詩，不覺逢逢鼓。"]'),
('49702d6e-75d2-429c-ab0b-1d7827c01b92','讀裴如晦萬里集書其後','梅堯臣','宋','宋诗','song-poetry','','[]','君自萬里迴，遂成萬里集。',96,'全唐诗/poet.song.14000.json','["君自萬里迴，遂成萬里集。", "其詩二百篇，文字必已立。", "定應侔前人，未嘗有蹈襲。", "古溪蠻鐵刀，出塚土花澀。", "誰將飾以玉，鐔上光熠熠。", "宋子序其端，精悍孰鉗摯。", "搜新造空蒙，俗眼不得入。", "示予要賦之，短戈慙後執。"]'),
('32a75fdc-51df-404c-bb99-ea43cfd47dec','見胥平叔','梅堯臣','宋','宋诗','song-poetry','','[]','歷君門兮九重，雲黕黕兮欲雨。',28,'全唐诗/poet.song.14000.json','["歷君門兮九重，雲黕黕兮欲雨。", "隠翠幕兮觀予，心眷眷兮不語。"]'),
('5b313836-bb7b-4a85-aeec-5cb8fa232d50','宣麻','梅堯臣','宋','宋诗','song-poetry','','[]','彬美下一國，曾無相印酬。',48,'全唐诗/poet.song.14000.json','["彬美下一國，曾無相印酬。", "莫驚除拜峻，自是戰功優。", "壯士頗知勇，諸儒方貴謀。", "淮西封亦薄，裴度死生羞。"]'),
('9c5196e8-8719-49ec-a9a7-e7b1726cb20c','朧月','梅堯臣','宋','宋诗','song-poetry','','[]','夜晴初見月，雲薄未分明。',48,'全唐诗/poet.song.14000.json','["夜晴初見月，雲薄未分明。", "高樹尚無影，遠鴻時有聲。", "下階嫌履濕，閉戶認苔生。", "寂寂牆陰暝，更長已漸傾。"]'),
('01466ef4-978f-41ac-a3fb-af0a80f0732b','兵','梅堯臣','宋','宋诗','song-poetry','','[]','太平無戰陣，漢卒久生驕。',48,'全唐诗/poet.song.14000.json','["太平無戰陣，漢卒久生驕。", "金甲不曾擐，犀弓應自調。", "嗟爲燎原火，終作覆巢梟。", "若使威刑立，三軍豈敢囂。"]'),
('85306dfd-3882-4e77-8e06-e5f249637fc2','泥','梅堯臣','宋','宋诗','song-poetry','','[]','一夜添春雨，中衢長舊泥。',48,'全唐诗/poet.song.14000.json','["一夜添春雨，中衢長舊泥。", "屐黏憂折齒，馬滑畏顛蹄。", "去啄從江鶴，相呼任竹雞。", "朝來放朝請，始與逸人齊。"]'),
('151067b0-1555-4383-bb19-532e446a627e','聞韓仲文使歸','梅堯臣','宋','宋诗','song-poetry','','[]','傳道使車迴，柳條黄未開。',48,'全唐诗/poet.song.14000.json','["傳道使車迴，柳條黄未開。", "曉寒非絕漠，春色近章臺。", "名馬北方至，賓鴻南國來。", "明朝齋祓見，天子始稱才。"]'),
('32141526-86b1-428d-9984-a0d445e6358a','未晴','梅堯臣','宋','宋诗','song-poetry','','[]','未晴初止雨，蒸潤尚侵衣。',48,'全唐诗/poet.song.14000.json','["未晴初止雨，蒸潤尚侵衣。", "缺月如羞出，荒雲不肯歸。", "杏花朱欲綻，梅萼雪將稀。", "遠鴈來何急，衝風濕翅飛。"]'),
('ce0519f0-1956-4d0c-97fc-1a585d7089de','夜陰','梅堯臣','宋','宋诗','song-poetry','','[]','月色明還暗，雲寒散復濃。',48,'全唐诗/poet.song.14000.json','["月色明還暗，雲寒散復濃。", "古堂移魍魎，積霧合蛟龍。", "濕菌飛螢出，蒼苔上朽重。", "獨吟嗟向老，氣澀覺偏慵。"]'),
('526e1005-3f6f-435d-8b69-daa5ad5aadc5','夜晴','梅堯臣','宋','宋诗','song-poetry','','[]','新晴月正明，頻聽夜烏驚。',48,'全唐诗/poet.song.14000.json','["新晴月正明，頻聽夜烏驚。", "未向高枝穩，時爲繞樹聲。", "羣飛自紛泊，衆鳥不屏營。", "躁靜於焉見，誰能度物情。"]'),
('081a184a-bd17-4788-a1d8-0fda9eac0ae4','古鑑','梅堯臣','宋','宋诗','song-poetry','','[]','古鑑得荒塚，土花全未磨。',48,'全唐诗/poet.song.14000.json','["古鑑得荒塚，土花全未磨。", "背菱尖尚在，鼻獸角微訛。", "月暗蝦𢋙蝕，塵昏魍魎過。", "但令光彩發，表裏是山河。"]'),
('80ce28e4-526d-48ff-89b2-d2173b977704','橐駞','梅堯臣','宋','宋诗','song-poetry','','[]','鳴駞出西域，銜尾自連連。',48,'全唐诗/poet.song.14000.json','["鳴駞出西域，銜尾自連連。", "漢驛凌雲去，胡人踏雪牽。", "常時識風候，過磧辨沙泉。", "老覺肉封側，猶蒙錦帕鮮。"]'),
('54357e17-89ce-47cc-9be8-bb94dbe3793f','李庭老許遺結絲勒帛','梅堯臣','宋','宋诗','song-poetry','','[]','紉絲作長带，正勝茱萸紋。',48,'全唐诗/poet.song.14000.json','["紉絲作長带，正勝茱萸紋。", "冉冉仍垂紼，𤎥𤎥自有薰。", "鮮華非稱我，脩飾未如君。", "曾不日來取，賢哉知禮云。"]'),
('e398a204-6bd4-4034-9911-f74f5604d7cc','貧','梅堯臣','宋','宋诗','song-poetry','','[]','生甘類原憲，死不學陶朱。',48,'全唐诗/poet.song.14000.json','["生甘類原憲，死不學陶朱。", "但樂詩書在，未憂鐘鼎無。", "恥隨波上下，難免鬼歔歈。", "陋巷曲肱者，終朝還似愚。"]'),
('066d8672-abb0-4078-be6c-94a1dbb347fc','行僧','梅堯臣','宋','宋诗','song-poetry','','[]','風衣何揭揭，有若瓠葉翻。',24,'全唐诗/poet.song.14000.json','["風衣何揭揭，有若瓠葉翻。", "塵土不遠去，白雲藏石門。"]'),
('c4d2652f-dba4-498c-9837-1f708c489eea','送范景仁學士歸蜀焚黄','梅堯臣','宋','宋诗','song-poetry','','[]','蒼山過秦梁，山盡見川陸。',96,'全唐诗/poet.song.14000.json','["蒼山過秦梁，山盡見川陸。", "下馬古成都，訪壟得喬木。", "掃籜開奠席，隕淚濕俎肉。", "當時相如歸，徒自盛車轂。", "不問有是爲，事乃今古獨。", "還因問耆舊，亦莫遺隠卜。", "荒祠古柏下，殘月杜鵑哭。", "憑君約史筆，書作西來目。"]'),
('0b759ec7-0c76-4b1e-bf12-6e99f26945d3','送宋中道鄭州拜掃','梅堯臣','宋','宋诗','song-poetry','','[]','酣酣道旁杏，戢戢壠上柏。',48,'全唐诗/poet.song.14000.json','["酣酣道旁杏，戢戢壠上柏。", "不知烟火禁，但感風露易。", "開關掃墓隧，向樹繫車軶。", "灑淚有餘悲，麒麟高幾尺。"]'),
('0fe49aba-ef33-4a6e-8f16-ab33d2ffd9d0','送韓子華歸許昌','梅堯臣','宋','宋诗','song-poetry','','[]','不值風雨暴，杏過梨已開。',48,'全唐诗/poet.song.14000.json','["不值風雨暴，杏過梨已開。", "社後清明前，燕與人歸來。", "湖中水方漫，誰共泛其隈。", "儻有問顦顇，顦顇未忘杯。"]'),
('4b02c30f-0378-4d33-842f-21e2eeb00dbe','燕','梅堯臣','宋','宋诗','song-poetry','','[]','涎涎隻來燕，飛飛自舞空。',48,'全唐诗/poet.song.14000.json','["涎涎隻來燕，飛飛自舞空。", "輕如漢家后，斜避楚臺風。", "斗折撩沙觜，相高接草蟲。", "向人全不畏，切莫入吳宮。"]'),
('22fd966d-1027-4c3f-9701-a6a5d4640364','送周衍長官知遼州','梅堯臣','宋','宋诗','song-poetry','','[]','二月遼陽去，遼陽草未生。',48,'全唐诗/poet.song.14000.json','["二月遼陽去，遼陽草未生。", "春風吹胡沙，捲起黄雲平。", "土人耕耨晚，種黍何時成。", "塞地寒且薄，百役子宜輕。"]'),
('4fa20551-4105-4c93-b6b0-4a96fc6aa185','寒食','梅堯臣','宋','宋诗','song-poetry','','[]','墳塚徧青山，高低占原谷。',60,'全唐诗/poet.song.14000.json','["墳塚徧青山，高低占原谷。", "向來路已荒，今迷問樵牧。", "涉水到雲林，隔崗聞近哭。", "沃酒白楊下，悲風何飋飋。", "雨止梨園殘，鳩聲在茅屋。"]'),
('5bd49ef2-1eac-4d11-afbc-a89abd1aa329','依韻和太祝同諸君遊園湖見寄','梅堯臣','宋','宋诗','song-poetry','','[]','陽春何處來，客自商丘至。',120,'全唐诗/poet.song.14000.json','["陽春何處來，客自商丘至。", "一唱新辭工，始見故人意。", "園林誰與遊，卉木欣已媚。", "花上有微陰，水邊無近思。", "遥憐數觴豆，何必親歌吹。", "牧馬憶當時，招延遺舊地。", "不逢浮沼雁，但見銜魚翠。", "日予謬詞律，答句嗟蕪累。", "安能接賢彥，樂事聯輕騎。", "獨不負春風，塵纓此懷愧。"]'),
('60561598-56ab-4be2-a39c-d1327973d985','聞學士院試含桃薦寢廟詩擬作','梅堯臣','宋','宋诗','song-poetry','','[]','交交鳴谷鳥，粲粲熟荆桃。',72,'全唐诗/poet.song.14000.json','["交交鳴谷鳥，粲粲熟荆桃。", "寢廟此先薦，離宮將以遨。", "既同羞俎實，且異獻溪毛。", "露顆明朝日，朱光逼赭袍。", "戴經傳自久，漢令著方高。", "天子從茲食，羣臣賜亦叨。"]'),
('f5f20ac3-4d1b-443d-9609-bf01cf6f72d1','韓子華約遊園上馬後雨作遂歸','梅堯臣','宋','宋诗','song-poetry','','[]','誰約玩春物，狂風雲驟開。',48,'全唐诗/poet.song.14000.json','["誰約玩春物，狂風雲驟開。", "擺叢多落蕊，蔽路足昏埃。", "逆水燕迎雨，將生鵝怕雷。", "嵇康今轉懶，騎馬半途迴。"]'),
('b3cbcea8-681f-41e8-b1bd-b97475d6ae8b','大風','梅堯臣','宋','宋诗','song-poetry','','[]','夜風晝不止，天理何可常。',168,'全唐诗/poet.song.14000.json','["夜風晝不止，天理何可常。", "正當春木榮，擺磨枝葉傷。", "東皇務長養，乃值此物狂。", "曷不訴於帝，斥之出遠方。", "風伯有罪五，孰肯進皂囊。", "往時歲苦旱，救熱雨欲滂。", "吹之不使下，雲雷遂深藏。", "復摇江海波，白日沈舟航。", "又卷關塞沙，千里填河隍。", "拔木與退鷁，書傳言已詳。", "今者天柔和，煦煦皆敷芳。", "獨爾何不仁，嚎怒事雄强。", "既其背天時，誅殛固所當。", "鳶鳴兼虎嘯，助惡黨亦昌。"]'),
('6a4af6a6-1337-4b20-b423-81d6c716cd95','春風','梅堯臣','宋','宋诗','song-poetry','','[]','常愁春雲低，誰料春風惡。',48,'全唐诗/poet.song.14000.json','["常愁春雲低，誰料春風惡。", "摇扇無定響，折幹時聞落。", "吹花擁細草，送雨來高閣。", "江燕倚身輕，逆飛前復却。"]'),
('87e2186b-a4ea-441f-b5f6-ffe0b4df8f59','送侯寺丞知鞏縣','梅堯臣','宋','宋诗','song-poetry','','[]','伊洛合河流，正臨歸鞏路。',48,'全唐诗/poet.song.14000.json','["伊洛合河流，正臨歸鞏路。", "崖壁人畏崩，芹泥岸長固。", "山迴邑郭見，馬入雲煙暮。", "宰茲雖所淹，况與鄉黨附。"]'),
('e18d75ca-af30-4cf9-b5bd-bfb37744f141','宋次道家摘寶相花歸清平里','梅堯臣','宋','宋诗','song-poetry','','[]','往歲見此花開遲，手擷羣芳因醉嗅。',128,'全唐诗/poet.song.14000.json','["往歲見此花開遲，手擷羣芳因醉嗅。", "今來須約爛漫看，及過風雨又已後。", "主人爲我特殷勤，架底深深掇孤秀。", "密枝陰蔓不爭開，薄紅細葉尖相鬭。", "先時已落已掃除，最晚堪憐子所厚。", "呼童歸遺不可緩，金盤付與急奔驟。", "暮還已見映雪髻，初拈尚覺香在袖。", "官橋夜市正沽酒，沽酒共賞莫待晝。"]'),
('471532be-8496-4777-9ad9-f2dd69372336','送南京簽判寇中舍','梅堯臣','宋','宋诗','song-poetry','','[]','東風莫迎船，船下黄流急。',48,'全唐诗/poet.song.14000.json','["東風莫迎船，船下黄流急。", "送車猶未動，顧棹已不及。", "離宮佳氣盤，賓幙平時入。", "因君報親舊，將去江南邑。"]'),
('1ab1c1f2-0175-4208-8d1e-3da6c79e0bf1','送韓奉禮隨侍之許昌','梅堯臣','宋','宋诗','song-poetry','','[]','岸之側，多菖蒲。',44,'全唐诗/poet.song.14000.json','["岸之側，多菖蒲。", "岸之下，多乳魚。", "乳魚可以饌，菖蒲可以葅。", "羨君調膳去且樂，因使無忘寄我書。"]'),
('773b278c-2f0d-464c-823b-318e4144a2a5','金明池遊','梅堯臣','宋','宋诗','song-poetry','','[]','三月天池上，都人袨服多。',96,'全唐诗/poet.song.14000.json','["三月天池上，都人袨服多。", "水明摇碧玉，岸響集靈鼉。", "畫舸龍延尾，長橋霓飲波。", "苑光花粲粲，女齒笑瑳瑳。", "行袂相朋接，遊肩與賤摩。", "津樓金間采，幄殿錦文窠。", "挈榼車傍綴，歸郎馬上歌。", "川魚應望幸，幾日翠華過。"]'),
('b3ed958d-b00e-4533-a407-d3df5a991189','和應之還邑道中見寄','梅堯臣','宋','宋诗','song-poetry','','[]','向老思舊交，欲見恨無翅。',72,'全唐诗/poet.song.14000.json','["向老思舊交，欲見恨無翅。", "前時君來都，欣喜乃一至。", "亦既勤我懷，酌酒去拘忌。", "自從離洛陽，此會無三四。", "謝尹最賢豪，已嗟存沒異。", "因酬馬上篇，遂寫相逢意。"]'),
('e3b05f5f-4cc3-45b0-8746-116879779ab7','送韓仲文知許州','梅堯臣','宋','宋诗','song-poetry','','[]','孰不爲太守，所榮歸故鄉。',72,'全唐诗/poet.song.14000.json','["孰不爲太守，所榮歸故鄉。", "僚官詫舊識，邸吏窺新章。", "前去別馬上，今仰立道傍。", "野老拜車塵，里人持壺漿。", "至家塤篪美，謁壠雲日光。", "盛事難盡書，且舉國門觴。"]'),
('907aa620-7ad8-46cd-a07a-34ad8fbd95c3','送薛殿丞知達州','梅堯臣','宋','宋诗','song-poetry','','[]','遠郡古通川，雲煙秀重疊。',48,'全唐诗/poet.song.14000.json','["遠郡古通川，雲煙秀重疊。", "江從巴蜀來，山與岷峨接。", "啼鳥異方音，青林四時葉。", "使君當問俗，市賈皆紅頰。"]'),
('36ca160f-5ebc-42fe-ad21-5857249b58b8','依韻朱學士廉叔憶穎川西湖春色寄獻尚書晏公且將有宛丘之命','梅堯臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','物景有先後，春工無舊新。',144,'全唐诗/poet.song.14000.json','["物景有先後，春工無舊新。", "追歡成杳靄，寄詠苦逡巡。", "湖水與濠接，岸亭將寺鄰。", "豔花簪舞髻，弱藻罥重緡。", "客奏桓伊笛，人歌柳惲蘋。", "何嘗煩几案，自得去埃塵。", "縱語曾忘倦，從游未覺頻。", "賦詩高壓古，下筆敏如神。", "每想魂俱往，終知夢是因。", "廣騷常慕屈，感遇亦希陳。", "借問摛詞者，當時別乘人。", "喜公移幕府，連賞二州春。"]'),
('51096017-cbf4-42ee-a91a-556c7c9b8990','集英殿賜百官宴以雨放','梅堯臣','宋','宋诗','song-poetry','','[]','春來無點雨，三月始聞雷。',48,'全唐诗/poet.song.14000.json','["春來無點雨，三月始聞雷。", "曉殿鳴簷急，羣公罷食迴。", "燕迎風翅健，馬踏霧泥開。", "晚覺微陽透，飛光上綠槐。"]'),
('2aaf53e5-b0ef-4778-bf77-611d50ff4150','送陳太祝歸河陽','梅堯臣','宋','宋诗','song-poetry','','[]','羸馬度關去，夜向河橋歸。',48,'全唐诗/poet.song.14000.json','["羸馬度關去，夜向河橋歸。", "水風來何急，吹裂游子衣。", "到家莫久留，速書赴禮闈。", "大對必有藴，時哉無闊稀。"]'),
('cb0ae5e4-16dd-449b-aee8-39ffed66cd92','送祖擇之秘丞知海州','梅堯臣','宋','宋诗','song-poetry','','[]','驥有千里足，不使千里馳。',108,'全唐诗/poet.song.14000.json','["驥有千里足，不使千里馳。", "人有抱長才，亦復不得施。", "去去作守長，政化尚可爲。", "勿云海濱陋，豈無彼黔黎。", "事舉訟必簡，安能忘酒巵。", "水物錯在俎，鹹腥應自宜。", "朐山日相對，亦莫厭其卑。", "蒼翠入畫戟，濃淡若秀眉。", "但向此中樂，用捨乃繫時。"]'),
('37d2ce31-f142-491a-964c-ce95f74b5534','戊子三月二十一日殤小女稱稱三首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','生汝父母喜，死汝父母傷。',60,'全唐诗/poet.song.14000.json','["生汝父母喜，死汝父母傷。", "我行豈有虧，汝命何不長。", "鴉雛春滿窠，蜂子夏滿房。", "毒螫與惡噪，所生遂飛揚。", "理固不可詰，泣淚向蒼蒼。"]'),
('94801f32-ab33-475b-ae4c-2e71be66158e','戊子三月二十一日殤小女稱稱三首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','蓓蕾樹上花，瑩絜昔嬰女。',48,'全唐诗/poet.song.14000.json','["蓓蕾樹上花，瑩絜昔嬰女。", "春風不長久，吹落便歸土。", "嬌愛命亦然，蒼天不知苦。", "慈母眼中血，未乾同兩乳。"]'),
('33647aab-b76e-4942-b329-7d179cb8e09e','戊子三月二十一日殤小女稱稱三首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','高廣五寸棺，埋此千歲恨。',48,'全唐诗/poet.song.14000.json','["高廣五寸棺，埋此千歲恨。", "至愛割難斷，剛性挫以鈍。", "淚傷染衣班，花惜落蔕嫩。", "天地既許生，生之何遽困。"]'),
('6fc2c5dd-3586-48c6-90e0-2013b2d46d25','與用文師','梅堯臣','宋','宋诗','song-poetry','','[]','師名學佛者，何乃愛吾詩。',60,'全唐诗/poet.song.14000.json','["師名學佛者，何乃愛吾詩。", "吾方嗟世人，各各事奔馳。", "蒼鷹絕海至，不異攫鼠鴟。", "所趨有遠近，所向皆餒饑。", "潄水對無語，風動庭樹枝。"]'),
('81cf8d12-34da-4e16-9f52-00f7d70eaaf1','送吳沖卿學士歸蔡州','梅堯臣','宋','宋诗','song-poetry','','[]','孟夏日南歸，馬耳豎迎風。',48,'全唐诗/poet.song.14000.json','["孟夏日南歸，馬耳豎迎風。", "急雨不及避，斷霓明向東。", "古城汝水傍，化俗寄我公。", "君今去拜慶，酥酪美將同。"]'),
('ecd73153-40ef-46fe-8263-c0b772d7443f','下土橋送刁景純忽大風韓子華先歸遺其小方巾明日持還副以此詩','梅堯臣','宋','宋诗','song-poetry','','[]','昨日汴水頭，共餞東去人。',48,'全唐诗/poet.song.14000.json','["昨日汴水頭，共餞東去人。", "暴風吹黄沙，對面不相親。", "歸來乘大馬，誤擲小方巾。", "平明馳奴還，偷樣古逼真。"]'),
('7d467835-8ffa-4c54-80fb-893d06cc32ea','刁景純期水門再別以風雨不往','梅堯臣','宋','宋诗','song-poetry','','[]','餞客客未至，明朝當更來。',48,'全唐诗/poet.song.14000.json','["餞客客未至，明朝當更來。", "風雨尋船懶，車馬向城迴。", "烏帽吹覺重，清樽想誰開。", "終期江上見，俗禮聊損裁。"]'),
('c207e65e-b7d3-467c-85b9-2b9d6262275c','韓子華訪石昌言不遇石有詩韓邀和答','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞載酒者，去訪子雲居。',48,'全唐诗/poet.song.14000.json','["嘗聞載酒者，去訪子雲居。", "乃值徒御出，遂令談笑虛。", "爲黍寧乏具，題鳳豈有諸。", "一聽負荆語，還想藺相如。"]'),
('d9a2824f-c2d7-4d5f-bcb1-e7d94eb8766e','舟中夜聽汴河水聲','梅堯臣','宋','宋诗','song-poetry','','[]','夏雨漲黄流，夜鳴鄰船柁。',24,'全唐诗/poet.song.14000.json','["夏雨漲黄流，夜鳴鄰船柁。", "乘危冒險人，不識西山餓。"]'),
('d71d964e-e419-4dbc-94a5-7dc29797ef9b','逢王公慥太博','梅堯臣','宋','宋诗','song-poetry','','[]','駑馬不惜蹄，出門莫畏泥。',96,'全唐诗/poet.song.14000.json','["駑馬不惜蹄，出門莫畏泥。", "泥中逢故友，十載相乖睽。", "但怪蒼鬢色，斑斑俯鐵驪。", "少立不及語，交策或東西。", "向晚我還舟，君來訪長堤。", "對論出處跡，存沒生悲啼。", "勿言少壯日，志意吐虹霓。", "而今七不堪，懶又甚於嵇。"]'),
('d50fdd21-c63e-4cd5-8851-4faa4f2df4d0','寄題洪州慈濟師西軒','梅堯臣','宋','宋诗','song-poetry','','[]','西軒無落暉，所頼西庭竹。',48,'全唐诗/poet.song.14000.json','["西軒無落暉，所頼西庭竹。", "竹間有古葉，竹上有繁綠。", "夜雨一洗梢，朝陽似晞沐。", "焚香愛此心，自不同諸俗。"]'),
('92cc54e2-93c7-4f8c-962c-719a8e5bd459','送謝著作歸陳州','梅堯臣','宋','宋诗','song-poetry','','[]','騏驥泥中行，偶蹶未千里。',60,'全唐诗/poet.song.14000.json','["騏驥泥中行，偶蹶未千里。", "終當至高衢，尚苦泥行恥。", "今歸雨濛濛，嘶鳴欲何止。", "乃念彼名駒，近在清川涘。", "他日見騰驤，駑櫪此垂耳。"]'),
('a7cdd227-8a09-442b-b29c-2a1518d1fd27','和石昌言學士官舍十題 病竹','梅堯臣','宋','宋诗','song-poetry','','[]','水邊移得已傷根，枝葉如枯生意少。',32,'全唐诗/poet.song.14000.json','["水邊移得已傷根，枝葉如枯生意少。", "主人不使荒穢侵，遂長琅玕勝凡草。"]'),
('8a307b31-f162-4a81-b0e7-6da9eaf05646','和石昌言學士官舍十題 石榴花','梅堯臣','宋','宋诗','song-poetry','','[]','春花開盡見深紅，夏葉始繁明淺綠。',32,'全唐诗/poet.song.14000.json','["春花開盡見深紅，夏葉始繁明淺綠。", "祇知結子熟秋霖，不識來時有筇竹。"]'),
('aeb3bf2a-682c-48fd-80ad-ad2435d8a5b7','和石昌言學士官舍十題 薏苡','梅堯臣','宋','宋诗','song-poetry','','[]','葉如華黍實如珠，移種官庭特葱蒨。',32,'全唐诗/poet.song.14000.json','["葉如華黍實如珠，移種官庭特葱蒨。", "但蠲病渴付相如，勿恤謗言歸馬援。"]'),
('79cb8785-1c95-4d7e-a711-da23fcae1574','和石昌言學士官舍十題 石蘭','梅堯臣','宋','宋诗','song-poetry','','[]','言石曾非石上生，名蘭乃是蘭之類。',32,'全唐诗/poet.song.14000.json','["言石曾非石上生，名蘭乃是蘭之類。", "療痾炎帝與書功，紉佩楚臣空有意。"]'),
('65376ccc-c1bb-48be-bc78-b0eb033a7a31','和石昌言學士官舍十題 萱草','梅堯臣','宋','宋诗','song-poetry','','[]','人心與草不相同，安有樹萱憂自釋。',32,'全唐诗/poet.song.14000.json','["人心與草不相同，安有樹萱憂自釋。", "若言憂及此能忘，乃是人心爲物易。"]'),
('c5c517c6-8c3a-42ef-a204-0f1f67b8885d','和石昌言學士官舍十題 葵花','梅堯臣','宋','宋诗','song-poetry','','[]','此心生不背朝日，肯信衆草能蘙之。',32,'全唐诗/poet.song.14000.json','["此心生不背朝日，肯信衆草能蘙之。", "真似節旄思屬國，向來零落誰能持。"]'),
('24c782a6-a41d-4ec8-9b43-1ed2819f1fad','和石昌言學士官舍十題 蔬畦','梅堯臣','宋','宋诗','song-poetry','','[]','手自除荒手自鋤，葱鍼已插壅薤本。',32,'全唐诗/poet.song.14000.json','["手自除荒手自鋤，葱鍼已插壅薤本。", "朝芸夕灌豈不勤，比食翦苗閑且穩。"]'),
('05afefe3-2813-42b4-9208-b2aff2e31108','和石昌言學士官舍十題 水紅','梅堯臣','宋','宋诗','song-poetry','','[]','江天淡淡江水平，江岸有花紅作穗。',32,'全唐诗/poet.song.14000.json','["江天淡淡江水平，江岸有花紅作穗。", "今日特向都城開，晝時只合銜魚翠。"]'),
('e10667af-ff06-4aa5-a8b2-adb197834b5f','和石昌言學士官舍十題 甘菊','梅堯臣','宋','宋诗','song-poetry','','[]','世言此解制頹齡，便當園蔬春競種。',32,'全唐诗/poet.song.14000.json','["世言此解制頹齡，便當園蔬春競種。", "到秋猶得泛其英，爛醉莫辭官有俸。"]'),
('2a51ea88-afc4-4165-89ee-7717704f7cc5','和石昌言學士官舍十題 蘭','梅堯臣','宋','宋诗','song-poetry','','[]','楚澤多蘭人未辯，盡以清香爲比擬。',32,'全唐诗/poet.song.14000.json','["楚澤多蘭人未辯，盡以清香爲比擬。", "蕭茅杜若亦莫分，唯取芳聲襲衣美。"]'),
('b3d7e559-07f3-489a-871e-0fddeef35423','勉致仕李秘監','梅堯臣','宋','宋诗','song-poetry','','[]','淵明歸柴桑，家貧食不足。',120,'全唐诗/poet.song.14000.json','["淵明歸柴桑，家貧食不足。", "當其勇去時，不待秫稻熟。", "借問何以然，實恥暫屈辱。", "公常爲近臣，曾不輒媚曲。", "一緣府舍災，遂使還秩祿。", "祿仕四十年，內乏釜鍾粟。", "歸來託四鄰，恓恓無片屋。", "去就異前人，其義已介獨。", "譬之食嗟來，應自甘退縮。", "當營負郭田，漸可事水竹。"]'),
('15fa255b-1535-447e-8676-c7d6590eb5dd','送施景仁太博提點江南坑冶','梅堯臣','宋','宋诗','song-poetry','','[]','楚山豈無銅，楚匠豈不工。',72,'全唐诗/poet.song.14000.json','["楚山豈無銅，楚匠豈不工。", "大鑪常乏鑄，碧丱那得充。", "積弊在鄉縣，孰肯以利籠。", "君今承詔行，諭民當得中。", "苟能使之發，亦莫取之窮。", "此乃事可久，山深山自通。"]'),
('29ac4051-d5e1-4730-a5a1-5ec9d5f09a1f','夜泊虹縣同施景仁太博河上納凉書事','梅堯臣','宋','宋诗','song-poetry','','[]','與君愛清風，移榻就明月。',48,'全唐诗/poet.song.14000.json','["與君愛清風，移榻就明月。", "月落見星繁，星繁如晝熱。", "霑衣輕露墜，響岸崩湍齧。", "坐思都城時，誰許脚不韈。"]'),
('39792038-3a15-4292-bc43-d7482842166b','施景仁邀詠泗州普照王寺古檜','梅堯臣','宋','宋诗','song-poetry','','[]','來尋淮上寺，老檜莫知年。',48,'全唐诗/poet.song.14000.json','["來尋淮上寺，老檜莫知年。", "劫火已鎔像，樛枝寧改煙。", "根拏怪石入，節駮蒼苔堅。", "欲問浮波箭，空嗟此獨傳。"]'),
('2a2e81ed-f8ca-4c10-b021-a1d446ddc681','送王判官同提點坑冶','梅堯臣','宋','宋诗','song-poetry','','[]','地雖不愛寶，利在與民共。',48,'全唐诗/poet.song.14000.json','["地雖不愛寶，利在與民共。", "務國不務民，儻有安得用。", "孟氏美王囿，其說久已誦。", "聊此陳薄言，忉怛不能重。"]'),
('e02f3b19-94e8-4510-8699-bf7823eb1ddb','淮雨','梅堯臣','宋','宋诗','song-poetry','','[]','雨脚射淮鳴萬鏃，跳點起漚魚亂目。',32,'全唐诗/poet.song.14000.json','["雨脚射淮鳴萬鏃，跳點起漚魚亂目。", "濕帆遠遠來未收，雲漏斜陽生半幅。"]'),
('dad2fe2f-fde0-48fc-977e-6ef3a0dd684a','舟次山陽呈王宗說寺丞','梅堯臣','宋','宋诗','song-poetry','','[]','遠客雖有樂，莫如逢故人。',48,'全唐诗/poet.song.14000.json','["遠客雖有樂，莫如逢故人。", "夜懷夷門時，月照楚水濱。", "自居扁舟上，隨處與船鄰。", "宜將到此日，因使報朋親。"]'),
('18e4c71c-ccff-4142-9982-072c293cf961','送崔黄臣寺丞宰臨海','梅堯臣','宋','宋诗','song-poetry','','[]','補官桐廬時，已飽嚴陵釣。',72,'全唐诗/poet.song.14000.json','["補官桐廬時，已飽嚴陵釣。", "進吏六百石，又得臨海嶠。", "因之論出處，足以見風調。", "洪潮可登觀，萬里漲川竅。", "收縮向何歸，由來人莫料。", "憑君能賦才，庶或窮其妙。"]'),
('17678769-118e-475f-933f-d8ab7cbc6739','楚童','梅堯臣','宋','宋诗','song-poetry','','[]','楚童能捕魚，乃在水邊居。',48,'全唐诗/poet.song.14000.json','["楚童能捕魚，乃在水邊居。", "手取眼不顧，情知獺未如。", "鬢上浮萍草，點點綠有餘。", "既挈不暇理，歸來莫取渠。"]'),
('31547b46-9150-49bd-b7d7-8f63f4e3074e','雜詩絕句十七首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','蛙行動萍葉，誤觀作游魚。',24,'全唐诗/poet.song.14000.json','["蛙行動萍葉，誤觀作游魚。", "稍稍引兩股，已變科斗書。"]'),
('445737b8-bdff-4fff-b9a9-631d9cbd865e','雜詩絕句十七首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','青草生水中，日日隨水長。',24,'全唐诗/poet.song.14000.json','["青草生水中，日日隨水長。", "水落何所依，撩亂爲宿莽。"]'),
('06905b39-a884-42cb-98ec-1155d665cda4','雜詩絕句十七首  其三','梅堯臣','宋','宋诗','song-poetry','','[]','有蟲託斷葑，斷葑日夕流。',24,'全唐诗/poet.song.14000.json','["有蟲託斷葑，斷葑日夕流。", "不知止息處，隨夫非自由。"]'),
('70fd3e1f-4785-4b38-baf0-f22018cc9203','雜詩絕句十七首  其四','梅堯臣','宋','宋诗','song-poetry','','[]','荒水浸籬根，籬上蜻蜓立。',24,'全唐诗/poet.song.14000.json','["荒水浸籬根，籬上蜻蜓立。", "魚網挂繞籬，野船籬外入。"]'),
('c220a206-62f1-48d5-9548-5ef971ca71c6','雜詩絕句十七首  其五','梅堯臣','宋','宋诗','song-poetry','','[]','茸茸翦熟絲，雨染燕脂暈。',24,'全唐诗/poet.song.14000.json','["茸茸翦熟絲，雨染燕脂暈。", "滿樹斂黄昏，槿花無此分。"]'),
('42fd3952-e424-4e19-ae5a-0b588dd5f263','雜詩絕句十七首  其六','梅堯臣','宋','宋诗','song-poetry','','[]','青青老鏡葉，下有繁實尖。',24,'全唐诗/poet.song.14000.json','["青青老鏡葉，下有繁實尖。", "浪頭撥船女，刺手終不嫌。"]'),
('64d5c909-8b42-443d-93ae-ef0545a48ab6','雜詩絕句十七首  其七','梅堯臣','宋','宋诗','song-poetry','','[]','岸傍草樹密，往往不知名。',24,'全唐诗/poet.song.14000.json','["岸傍草樹密，往往不知名。", "其間有啼鳥，似與船相迎。"]'),
('93898f1a-d05b-432d-a23d-2f08b6ce3896','雜詩絕句十七首  其八','梅堯臣','宋','宋诗','song-poetry','','[]','青蠅何處來，聚集滿盤間。',24,'全唐诗/poet.song.14000.json','["青蠅何處來，聚集滿盤間。", "誰知腹中物，變化如循環。"]'),
('d0a4d3f1-883b-48b3-8a8f-ab0817b93f1a','雜詩絕句十七首  其九','梅堯臣','宋','宋诗','song-poetry','','[]','水上賣瓜女，摘瓜陂上田。',24,'全唐诗/poet.song.14000.json','["水上賣瓜女，摘瓜陂上田。", "長麻已不識，滿把青銅錢。"]'),
('e0010555-db65-489e-a4c4-2f9cbfe0e4e9','雜詩絕句十七首  其一○','梅堯臣','宋','宋诗','song-poetry','','[]','買魚問水客，始得鯽與魴。',24,'全唐诗/poet.song.14000.json','["買魚問水客，始得鯽與魴。", "操刀欲割鱗，跳怒鬐鬛張。"]'),
('d5e90048-eda6-4c8f-a74e-595318c67314','雜詩絕句十七首  其一一','梅堯臣','宋','宋诗','song-poetry','','[]','沙頭風雨來，帖水野雲黑。',24,'全唐诗/poet.song.14000.json','["沙頭風雨來，帖水野雲黑。", "如觀曹公營，萬弩射船側。"]'),
('e09c1177-3199-4413-8bb7-eafbe28e24fd','雜詩絕句十七首  其一二','梅堯臣','宋','宋诗','song-poetry','','[]','前時雙鴛鴦，失雌鳴不已。',24,'全唐诗/poet.song.14000.json','["前時雙鴛鴦，失雌鳴不已。", "今更作雙來，還悲舊流水。"]'),
('69daf260-f15f-4e5c-b0df-c9a3fc1d4d86','雜詩絕句十七首  其一三','梅堯臣','宋','宋诗','song-poetry','','[]','度水紅蜻蜓，傍人飛欵欵。',24,'全唐诗/poet.song.14000.json','["度水紅蜻蜓，傍人飛欵欵。", "但知隨船輕，不知船去遠。"]'),
('98c43725-ebcd-4b43-8f91-3e18c6c6c433','雜詩絕句十七首  其一四','梅堯臣','宋','宋诗','song-poetry','','[]','塘上挽船人，塘泥深及脛。',24,'全唐诗/poet.song.14000.json','["塘上挽船人，塘泥深及脛。", "落日望前村，心將道途競。"]'),
('8d611449-e911-4b5c-8ff9-4cd5fe591ec6','雜詩絕句十七首  其一五','梅堯臣','宋','宋诗','song-poetry','','[]','燕立茅屋脊，燕銜芹岸泥。',24,'全唐诗/poet.song.14000.json','["燕立茅屋脊，燕銜芹岸泥。", "巢成同養子，薄暮亦同棲。"]'),
('40ca0a88-0361-47b3-8743-41de053c23ee','雜詩絕句十七首  其一六','梅堯臣','宋','宋诗','song-poetry','','[]','鵲銜高樹蟬，危脇繅車響。',24,'全唐诗/poet.song.14000.json','["鵲銜高樹蟬，危脇繅車響。", "露腹不曾肥，殺之嗟已往。"]'),
('9a6e839a-332c-48f3-a114-c25d879546d7','雜詩絕句十七首  其一七','梅堯臣','宋','宋诗','song-poetry','','[]','河畔有釣翁，團泥爲甕缶。',24,'全唐诗/poet.song.14000.json','["河畔有釣翁，團泥爲甕缶。", "坐想秦人聲，思傾杜陵酒。"]'),
('73c56451-222b-4ab1-bd97-7c6788ddcbd4','五月二十夜夢尹師魯','梅堯臣','宋','宋诗','song-poetry','','[]','昨夕夢師魯，相對如平生。',60,'全唐诗/poet.song.14000.json','["昨夕夢師魯，相對如平生。", "及覺語未終，恨恨傷我情。", "去年聞子喪，旅寄誰能迎。", "家貧兒女幼，迢遞洛陽城。", "何當置之歸，西望淚緣纓。"]'),
('582f1906-d924-4376-a28d-71dacf40e730','五月二十四日過高郵三溝','梅堯臣','宋','宋诗','song-poetry','','[]','甲申七月七，未明至三溝。',120,'全唐诗/poet.song.14000.json','["甲申七月七，未明至三溝。", "先妻南陽君，奄化向行舟。", "魂去寂無跡，追之固無由。", "此苦極天地，心瞀腸如抽。", "泣盡淚不續，岸草風颼颼。", "柎殭尚疑生，大呼聲裂喉。", "柁師爲我歎，挽卒爲我愁。", "戊子夏再過，感昔涕交流。", "恐傷新人心，强制揩雙眸。", "未及歸旅櫬，悲恨何時休。"]'),
('67b642e8-b7dd-422b-b9cb-f706728ef7ac','過茱萸堰','梅堯臣','宋','宋诗','song-poetry','','[]','茱萸堰在吳牛死，茱萸堰廢吳牛閑。',28,'全唐诗/poet.song.14000.json','["茱萸堰在吳牛死，茱萸堰廢吳牛閑。", "吳牛閑，東南百貨來如山。"]'),
('195f352d-0ef0-4638-af6b-7dbe6ca09e63','詠歐陽永叔文石硯屏二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','虢州紫石如紫泥，中有瑩白象明月。',64,'全唐诗/poet.song.14000.json','["虢州紫石如紫泥，中有瑩白象明月。", "黑文天畫不可窮，桂樹婆娑生意發。", "其形方廣盈尺間，造化施工常不沒。", "虢州得之自山窟，持作名卿硯傍物。"]'),
('c1316174-646e-4f7d-8b53-15de097f212b','詠歐陽永叔文石硯屏二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','鑿山侵古雲，破石見寒樹。',72,'全唐诗/poet.song.14000.json','["鑿山侵古雲，破石見寒樹。", "分明秋月影，向此石上布。", "中又隠孤壁，紫錦藉圓素。", "山祇與地靈，暗巧不欲露。", "乃值人所獲，裁爲文室具。", "獨立筆硯間，莫使浮埃度。"]'),
('afe9cd3d-aff1-4cf6-b797-0398ef1092d3','永叔進道堂夜話','梅堯臣','宋','宋诗','song-poetry','','[]','海風驅雲來，池雨打荷急。',156,'全唐诗/poet.song.14000.json','["海風驅雲來，池雨打荷急。", "虛堂開西窗，晚坐凉氣入。", "與公語平生，事不一毫及。", "初探易之奧，大衍遺五十。", "乾坤露根源，君臣排角立。", "言史書星瑞，亂止由不戢。", "巨惡參大美，微顯豈相襲。", "陳疏見公忠，曾無與朋執。", "文章包元氣，天地得噓吸。", "明吞日月光，峭古崖壁澀。", "淵論發賢聖，暗溜聞鬼泣。", "夜闌索酒巵，快意頻舉挹。", "未竟天已白，左右如啟蟄。"]'),
('1c640196-bbb7-40ed-9ac3-e538f9690775','贈劉謀閤副','梅堯臣','宋','宋诗','song-poetry','','[]','聲名赫赫在窮塞，眉宇堂堂真丈夫。',32,'全唐诗/poet.song.14000.json','["聲名赫赫在窮塞，眉宇堂堂真丈夫。", "腰劍臂弓輕赴敵，無人不伏魏黄鬚。"]'),
('90758646-96f2-420b-9b06-24b49ff69bb8','長蘆江口','梅堯臣','宋','宋诗','song-poetry','','[]','風駕晚潮急，浪頭相趁過。',48,'全唐诗/poet.song.14000.json','["風駕晚潮急，浪頭相趁過。", "水歸瓜步小，船下秣陵多。", "鷗舞不停翅，燕飛輕帖波。", "今來學楚客，薄暮愛漁歌。"]'),
('ebf6f7d6-7067-4791-a481-376c0c907b67','金陵懷古','梅堯臣','宋','宋诗','song-poetry','','[]','秦莫恃棧閣，吳莫恃壍江。',72,'全唐诗/poet.song.14000.json','["秦莫恃棧閣，吳莫恃壍江。", "不能恃以德，二國竟亦降。", "邇來屢興廢，由險輕萬邦。", "誰知荒凉城，空存如刳腔。", "我今經其下，弔古語愧哤。", "嗟哉石頭潮，助怒常舂撞。"]'),
('06d06b63-aa59-44ac-8aca-42e436d2fb96','江畔','梅堯臣','宋','宋诗','song-poetry','','[]','江畔菱蒲碧無主，吳牛夜𩥇江干歸。',32,'全唐诗/poet.song.14000.json','["江畔菱蒲碧無主，吳牛夜𩥇江干歸。", "舟人不悟月已上，花脚野蚊撩亂飛。"]'),
('eb5079ce-a931-4800-bece-3398d8078662','慈姥山石崖上竹鞭','梅堯臣','宋','宋诗','song-poetry','','[]','江水浸石壁，峭直無鳥蹤。',48,'全唐诗/poet.song.14000.json','["江水浸石壁，峭直無鳥蹤。", "穴垂青竹根，瘦蛇愁作龍。", "霹靂雨脚入，濕點莓苔封。", "世人不得用，八馬今乖慵。"]'),
('a802d7ea-4b95-4733-80d4-694e306c4d09','阻風','梅堯臣','宋','宋诗','song-poetry','','[]','老漁吹浪不肯休，一夜南風打籬響。',32,'全唐诗/poet.song.14000.json','["老漁吹浪不肯休，一夜南風打籬響。", "灘下輕舟未可行，山脚盤渦似車輞。"]'),
('8c87e722-e353-42cd-8af8-e296b5e434c1','慈姥磯下','梅堯臣','宋','宋诗','song-poetry','','[]','蘆汀泱漭外，露斂見孤嶂。',60,'全唐诗/poet.song.14000.json','["蘆汀泱漭外，露斂見孤嶂。", "行舟每出觀，漸近已殊狀。", "傍來認飲牛，正去忽側盎。", "水壑陰若舂，野鳥時與相。", "且待風色迴，出口始浩蕩。"]'),
('51622810-8a4a-4bf0-a919-d150e8a6390f','早發','梅堯臣','宋','宋诗','song-poetry','','[]','吳雞鳴隔山，江月半在水。',48,'全唐诗/poet.song.14000.json','["吳雞鳴隔山，江月半在水。", "齧齧出岸潮，霅霅入蒲葦。", "解䋏泛明鏡，接天知幾里。", "我家今不遥，正住句溪尾。"]'),
('d0660985-225b-486f-acc3-f304910ed7e0','望夫石','梅堯臣','宋','宋诗','song-poetry','','[]','征骨化爲塵，柔肌化爲石。',48,'全唐诗/poet.song.14000.json','["征骨化爲塵，柔肌化爲石。", "高山共蒼蒼，臨水望脈脈。", "青雲卷爲髮，缺月低照額。", "千古遺恨深，終不見車軏。"]'),
('c2e14adc-5813-408e-b392-4675f5e82168','過褐山磯值風','梅堯臣','宋','宋诗','song-poetry','','[]','山口風偏急，磯頭水似煎。',48,'全唐诗/poet.song.14000.json','["山口風偏急，磯頭水似煎。", "喧聲殊倦聽，逆上正難牽。", "暗石誰愁礙，長途未擬前。", "江心看白浪，卷起大於船。"]'),
('2c4d6e6c-260d-48aa-b63d-43fc88b42499','褐山磯上港中泊','梅堯臣','宋','宋诗','song-poetry','','[]','風惡舟難進，聊依浦裏村。',48,'全唐诗/poet.song.14000.json','["風惡舟難進，聊依浦裏村。", "岸潮生蓼節，灘浪聚蘆根。", "日脚看看雨，江心漸漸昏。", "篙師知蟹窟，取以助清樽。"]'),
('95a1fdde-75ac-423e-ae41-11b636a4decf','宿磯上港','梅堯臣','宋','宋诗','song-poetry','','[]','夜深風浪息，月正在南斗。',48,'全唐诗/poet.song.14000.json','["夜深風浪息，月正在南斗。", "遠水生白煙，疏螢出荒莽。", "照蟹屢爇薪，張魚未發笱。", "獨能憐野客，游宦意何有。"]'),
('b4158c99-9de8-41bc-a270-e61f8d258774','謁昭亭廟','梅堯臣','宋','宋诗','song-poetry','','[]','連峯到溪止，澄溜向潭瀉。',96,'全唐诗/poet.song.14000.json','["連峯到溪止，澄溜向潭瀉。", "廟道走山腰，雀雛鳴屋瓦。", "古壁畫雲雷，空庭儼輿馬。", "眷予來故鄉，絜齋陳奠斝。", "尚想昔丱童，維愚託民社。", "每從諸父賽，朅至此祠下。", "今齒踰不惑，雙親世似寡。", "過此無所禱，曷慕逢時者。"]'),
('cb4b8baa-4dc1-4655-9a1c-4c0be07403a2','昭亭潭上別','梅堯臣','宋','宋诗','song-poetry','','[]','行舟晚解去，親戚各還家。',48,'全唐诗/poet.song.14000.json','["行舟晚解去，親戚各還家。", "淚落正濕衣，腸翻如轉車。", "借是昭亭水，相隨亦有涯。", "予今游宦意，曾不學匏瓜。"]'),
('71235e76-63bb-4cc3-8e6a-fc7fbc052ab5','宣州環波亭','梅堯臣','宋','宋诗','song-poetry','','[]','冒暑駐輪轂，徘徊北壕上。',96,'全唐诗/poet.song.14000.json','["冒暑駐輪轂，徘徊北壕上。", "棟宇起中央，芙蓉生四向。", "今吾太守樂，慰此郡人望。", "雨從昭亭來，水入句溪漲。", "蜻蜓立欄角，朱鯉吹荷浪。", "岸木影下布，水鳥時引吭。", "心閑不競物，興適每傾釀。", "薄暮詠醉歸，陪車知幾兩。"]'),
('4b6d7123-b6a4-407d-868f-d5474d127da1','昭亭山','梅堯臣','宋','宋诗','song-poetry','','[]','曰山何必高，要在出雲雨。',144,'全唐诗/poet.song.14000.json','["曰山何必高，要在出雲雨。", "昭亭非峻峯，雄雄若蹲虎。", "旱歲一來祠，霈然隨瀝酤。", "有草牧爾牛，有薪資爾斧。", "有溪出其陰，有潭在其塢。", "獸則貛與貉，魚則魴與鱮。", "山雛水羽聲，下上相雜伍。", "呼名如謙恭，號叫若怒侮。", "崖竹或節疎，嶺松或復腐。", "巨蜂結層房，養子窟深土。", "何事山中人，采以爲市賈。", "其容固已多，其忍吾未取。"]'),
('dd904d0c-6288-46d4-b33a-c8549846c42c','泊姑熟江口邀刁景純相見','梅堯臣','宋','宋诗','song-poetry','','[]','尾生信女子，抱柱死不疑。',72,'全唐诗/poet.song.14000.json','["尾生信女子，抱柱死不疑。", "吾與丞相約，安得不顧期。", "徘徊大江側，念此親相知。", "欲留時已晚，欲去情難持。", "引領望軒車，豈能慰我思。", "願聞下士禮，無曰屈非宜。"]'),
('d468037c-1ff7-46ae-9286-a9278dcd5de5','見牧牛人隔江吹笛','梅堯臣','宋','宋诗','song-poetry','','[]','朝與牛出牧，晝與牛在野。',132,'全唐诗/poet.song.14000.json','["朝與牛出牧，晝與牛在野。", "日暮穿林歸，長笛初在骻。", "面尾騎且吹，音響未成雅。", "隨風散遠近，舉調任高下。", "我方江上來，平溜若鏡瀉。", "悠悠經醉耳，亦足發瀟灑。", "苟能和人心，豈必奏韶夏。", "鄭聲實美好，蠹情如剔剮。", "况其荒敗跡，又亦甚裂瓦。", "南箕成簸揚，寺孟詠侈哆。", "我今留此詩，誰謂馬喻馬。"]'),
('d2de1f0b-629c-4426-ab7a-9f92a9d0fc4b','依韻和歐陽永叔中秋邀許發運','梅堯臣','宋','宋诗','song-poetry','','[]','看取主人無俗調，風前喜御夾衣凉。',64,'全唐诗/poet.song.14000.json','["看取主人無俗調，風前喜御夾衣凉。", "競邀三五最圓魄，知比尋常特地光。", "豔曲旋教皆可聽，秋花雖種未能香。", "曾非惡少休防準，衆寡而今不易當。"]'),
('97c13288-63fc-4f1a-a418-202b610e0dc2','與夏侯繹張唐民游蜀岡大明寺','梅堯臣','宋','宋诗','song-poetry','','[]','秋葉已多蠹，古原看更荒。',48,'全唐诗/poet.song.14000.json','["秋葉已多蠹，古原看更荒。", "廢城無馬入，破冢有狐藏。", "寒日稍清迥，寒山分漭蒼。", "田衣指白水，此下是雷塘。"]'),
('fcd983c3-f892-4b5e-85da-7d6e3a3bbe87','寄麥門冬於符公院','梅堯臣','宋','宋诗','song-poetry','','[]','佳人種碧草，所愛凌風霜。',96,'全唐诗/poet.song.14000.json','["佳人種碧草，所愛凌風霜。", "佳人昔已歿，草色尚蒼蒼。", "陸行載以車，水行載以航。", "于今五六年，與我道路長。", "思人不忍棄，期植寒冢傍。", "我嗟復北去，安得畢此喪。", "留植精舍中，遠挈防根傷。", "他時京峴下，不比野蒿黄。"]'),
('88dec81a-58aa-4f90-90a2-8db3d479f276','送張唐民','梅堯臣','宋','宋诗','song-poetry','','[]','楚甸有行客，西風一孤舟。',48,'全唐诗/poet.song.14000.json','["楚甸有行客，西風一孤舟。", "遠隨淮月上，若與星磋浮。", "野岸襲幽芳，氣清露已秋。", "得意美魚蟹，白酒問沙頭。"]'),
('18013e48-fa9f-4682-9b55-e709465723ab','秋夜同永叔看月','梅堯臣','宋','宋诗','song-poetry','','[]','青天有右目，昏明不常開。',84,'全唐诗/poet.song.14000.json','["青天有右目，昏明不常開。", "常時翳雲氣，古鑑生莓苔。", "秋夜特清徹，乃顧漸西迴。", "靈兔不擣藥，是夜無纖埃。", "與君玩流景，置酒臨層臺。", "單衣濕白露，鳴鴈方南來。", "以言歡未終，鴈聲一何哀。"]'),
('edff5e50-3a15-4f17-9851-7c53f2f523a6','中秋不見月答永叔','梅堯臣','宋','宋诗','song-poetry','','[]','天嫌物兼美，而使密雲藏。',24,'全唐诗/poet.song.14000.json','["天嫌物兼美，而使密雲藏。", "已向石屏見，何須照席光。"]'),
('3f4c3df1-fd89-4c6b-96c8-6ce0099a8a68','和永叔中秋夜會不見月酬王舍人','梅堯臣','宋','宋诗','song-poetry','','[]','主人待月敞南樓，淮雨西來斗變秋。',64,'全唐诗/poet.song.14000.json','["主人待月敞南樓，淮雨西來斗變秋。", "自有嬋娟侍賓榻，不須迢遞望刀頭。", "池魚暗聽歌聲躍，蓮的明傳酒令優。", "更愛西垣舊詞客，共將詩興壓曹劉。"]'),
('6cea2af8-9373-4d11-a7b5-7bcca777e5d9','觀永叔集古錄','梅堯臣','宋','宋诗','song-poetry','','[]','古碑手集一千卷，河北關西得最多。',32,'全唐诗/poet.song.14000.json','["古碑手集一千卷，河北關西得最多。", "莫怕他時費人力，他時自有錦蒙駞。"]'),
('1f6c0f88-4eaa-427f-bac0-17b8a148fe23','觀舞','梅堯臣','宋','宋诗','song-poetry','','[]','誰憐嬌小好腰支，老大而今莫那伊。',32,'全唐诗/poet.song.14000.json','["誰憐嬌小好腰支，老大而今莫那伊。", "太守風流未應淺，更教多唱楚人辭。"]'),
('2db047cc-364b-4753-afbb-866fa854b8dd','留別永叔','梅堯臣','宋','宋诗','song-poetry','','[]','舊友競留連，我征時已晚。',48,'全唐诗/poet.song.14000.json','["舊友競留連，我征時已晚。", "但言會合難，豈道行路遠。", "行路到有期，別離未即返。", "明當各相思，念此去且懶。"]'),
('7da4b571-115d-4f8b-b4c0-cb17af1b66b1','觀永叔畫真','梅堯臣','宋','宋诗','song-poetry','','[]','良金美玉不可畫，可畫惟應色與形。',32,'全唐诗/poet.song.14000.json','["良金美玉不可畫，可畫惟應色與形。", "除却堅明盡非寶，世人何得重丹青。"]'),
('cf8ec705-2bba-40be-a7ef-9e3b3a75a4c6','畫真來嵩','梅堯臣','宋','宋诗','song-poetry','','[]','廣陵太守歐陽公，令爾畫我憔悴容。',64,'全唐诗/poet.song.14000.json','["廣陵太守歐陽公，令爾畫我憔悴容。", "便傳髣髴在縑素，只欠勁直藏心胸。", "與我貨布不肯受，此之醫卜曾非庸。", "公今許爾此一節，爾只丹青其亦逢。"]'),
('39639a31-d23b-4836-bc8c-dd4a86912f6d','別後寄永叔','梅堯臣','宋','宋诗','song-poetry','','[]','前日辭親淚，又爲別友出。',132,'全唐诗/poet.song.14000.json','["前日辭親淚，又爲別友出。", "愁極反無言，欲言詞已窒。", "荷公知我詩，數數形美述。", "茲道日未堙，可與古爲匹。", "孟盧張賈流，其言不相昵。", "或多窮苦語，或特事豪逸。", "而於韓公門，取之不一律。", "乃欲存此心，欲使名譽溢。", "竊比於老郊，深愧言過實。", "然於世道中，固且異謗嫉。", "交情有若此，始可論膠漆。"]'),
('f36cde49-411c-4d81-8fde-1c7a1c14acfa','登楊州北門','梅堯臣','宋','宋诗','song-poetry','','[]','樓上山如淡墨畫，城中水似輕藍挼。',32,'全唐诗/poet.song.14000.json','["樓上山如淡墨畫，城中水似輕藍挼。", "楊州今似刀州景，似聽中和樂職歌。"]'),
('5033efc3-6009-462a-969a-a885e5633361','因目痛有作','梅堯臣','宋','宋诗','song-poetry','','[]','已爲貧孟郊，拚作瞎張籍。',48,'全唐诗/poet.song.14000.json','["已爲貧孟郊，拚作瞎張籍。", "詩句但口吟，世事不眼歷。", "既能分好惡，難用變青白。", "讀書聽吾兒，且未廢朝夕。"]'),
('f21bf2e8-392b-4a23-8f18-f8c2174e0c90','宿邵埭聞雨因買藕芡人迴呈永叔','梅堯臣','宋','宋诗','song-poetry','','[]','秋雨雁來急，夜舟人未眠。',48,'全唐诗/poet.song.14000.json','["秋雨雁來急，夜舟人未眠。", "亂風燈不定，暝色樹相連。", "寒屋猛添響，濕窗愁打穿。", "明朝持藕使，書此寄公前。"]'),
('fa336c38-b0c8-45ee-a6c1-fadb404c8fff','寄許主客','梅堯臣','宋','宋诗','song-poetry','','[]','昨日山光寺前雨，今朝邵伯堰頭風。',64,'全唐诗/poet.song.14000.json','["昨日山光寺前雨，今朝邵伯堰頭風。", "野雲不散低侵水，魚艇無依尚蓋蓬。", "藕味初能消酒渴，蓼花猶愛照波紅。", "楊州有使急迴去，敢此寄聲非塞鴻。"]'),
('3a69d36f-16e4-42b5-bff0-ca47d1372bbc','八月二十二日迴過三溝','梅堯臣','宋','宋诗','song-poetry','','[]','不見沙上雙飛鳥，莫取波中比目魚。',32,'全唐诗/poet.song.14000.json','["不見沙上雙飛鳥，莫取波中比目魚。", "重過三溝特惆悵，西風滿眼是秋蕖。"]'),
('f3e45851-f506-4d35-b1bc-df6d743fea70','牛背雙鸜鵒','梅堯臣','宋','宋诗','song-poetry','','[]','牛背雙鸜鵒，煙陂共入時。',48,'全唐诗/poet.song.14000.json','["牛背雙鸜鵒，煙陂共入時。", "草枯行解美，日晚趁羣遲。", "閒載寧辭遠，相鳴不間雌。", "初驚牧人去，飛上野桑枝。"]'),
('fc303a1f-263a-492d-b4ce-a5cd845cdb4c','廣陵歐陽永叔贈寒林石硯屏','梅堯臣','宋','宋诗','song-poetry','','[]','磷磷石岸上，濃淡樹林分。',48,'全唐诗/poet.song.14000.json','["磷磷石岸上，濃淡樹林分。", "隔水見寒島，暗枝藏宿雲。", "賢哉吾益友，持以贈離羣。", "琥珀不須問，中心多化蚊。"]'),
('a40f76c4-6a4b-4d4e-8a79-a84723dd18b7','岸貧','梅堯臣','宋','宋诗','song-poetry','','[]','無能事耕穫，亦不有雞豚。',48,'全唐诗/poet.song.14000.json','["無能事耕穫，亦不有雞豚。", "燒蚌曬槎沫，織蓑依樹根。", "野蘆編作室，青蔓與爲門。", "稚子將荷葉，還充犢鼻裩。"]'),
('243320de-7872-462e-a110-44e17516e031','村豪','梅堯臣','宋','宋诗','song-poetry','','[]','日擊收田鼓，時稱大有年。',48,'全唐诗/poet.song.14000.json','["日擊收田鼓，時稱大有年。", "爛傾新釀酒，飽載下江船。", "女髻銀釵滿，童袍毳氎鮮。", "里胥休借問，不信有官權。"]'),
('7dadc295-ba49-4b9e-8681-5378d78668c5','晚雲','梅堯臣','宋','宋诗','song-poetry','','[]','黕黕日脚雲，斷續如破灘。',60,'全唐诗/poet.song.14000.json','["黕黕日脚雲，斷續如破灘。", "忽舒金翠尾，始識秦女鸞。", "又改爲連牛，綴燧懷齊單。", "伺黑密不囂，額額城未剜。", "風吹了無物，猶立船頭看。"]'),
('1f141a46-295c-450e-b76e-247268296682','荇','梅堯臣','宋','宋诗','song-poetry','','[]','荇葉光於水，鉤牽入遠汀。',48,'全唐诗/poet.song.14000.json','["荇葉光於水，鉤牽入遠汀。", "淺黄雙蛺蝶，五色小蜻蜓。", "老死懷江女，飄浮笑楚萍。", "西風莫苦急，孤蕊有餘馨。"]'),
('29a5317b-1a1e-4098-b2cb-46b31db64e1a','晚日','梅堯臣','宋','宋诗','song-poetry','','[]','晚日晴還暖，人閒見物機。',48,'全唐诗/poet.song.14000.json','["晚日晴還暖，人閒見物機。", "葉枯蟲自裹，窗響蜜尋歸。", "林下見收柿，水邊聞擣衣。", "吾嗟久爲客，却愧寄荆扉。"]'),
('51e05ae6-d2fa-44ad-b570-ea88bed443db','寄酬發運許主客','梅堯臣','宋','宋诗','song-poetry','','[]','淮上秋來物意閑，又乘輕舸信帆還。',64,'全唐诗/poet.song.14000.json','["淮上秋來物意閑，又乘輕舸信帆還。", "一浮一沒水中鳥，更遠更昏天外山。", "斜幅纏踍兵吏至，濃金灑紙頷珠頒。", "欲酬已覺不能敵，盡日臨風思自慳。"]'),
('99073628-aabf-4223-997c-4c2f32e6b2c6','前日','梅堯臣','宋','宋诗','song-poetry','','[]','前日楊州去，酒熟美蟹蜊。',48,'全唐诗/poet.song.14000.json','["前日楊州去，酒熟美蟹蜊。", "秋風淮陰來，沙暖拾蚌螄。", "不言爾貧富，只繫其鄙夷。", "漢重二千石，後世何忽之。"]'),
('20e274de-c407-49d2-b848-4ba87c8f9d05','淮陰','梅堯臣','宋','宋诗','song-poetry','','[]','青環瘦鐵纜，繫在淮陰城。',48,'全唐诗/poet.song.14000.json','["青環瘦鐵纜，繫在淮陰城。", "水脛多長短，林枝有直橫。", "山夔一足走，妖鳥九頭鳴。", "韓信祠堂古，誰將胯下平。"]'),
('a06fac4c-5c39-4527-8598-920b69f539a5','哀王孫','梅堯臣','宋','宋诗','song-poetry','','[]','泗水赤龍將欲飛，瘦蛟在泥雲未歸。',64,'全唐诗/poet.song.14000.json','["泗水赤龍將欲飛，瘦蛟在泥雲未歸。", "冰繭煮灰寒水擊，長大王孫抱饑色。", "誰知適自下鄉來，日昃可哀猶未食。", "菰飯白漿持與君，王孫王孫何復云。"]'),
('2a17092e-ddca-4fc7-b7cc-3c5a23417d23','沛公歌','梅堯臣','宋','宋诗','song-poetry','','[]','赤帝醉提龍劍行，徑草沒人壯士驚。',80,'全唐诗/poet.song.14000.json','["赤帝醉提龍劍行，徑草沒人壯士驚。", "白蛇斷裂不可續，神嫗哀哀夜深哭。", "酒醒自負氣生虹，從者日畏天下雄。", "秦皇玉輿來向東，安知隠在芒碭中。", "婦人自識雲氣從，王命艱哉豐沛公。"]'),
('b79c4fc1-b3c5-4dab-8eca-c2a23e35a2e6','使風','梅堯臣','宋','宋诗','song-poetry','','[]','胯下橋南逆水風，十幅蒲帆彎若弓。',48,'全唐诗/poet.song.14000.json','["胯下橋南逆水風，十幅蒲帆彎若弓。", "淮波带日魚鱗紅，岌岌飛上北斗中。", "龜山始撞人定鐘，岸草澀澀鳴秋蟲。"]'),
('a7ff04d5-3234-471f-9714-3403f022b8bf','田家屋上壺','梅堯臣','宋','宋诗','song-poetry','','[]','脩蔓屋頭綴，大壺簷外垂。',48,'全唐诗/poet.song.14000.json','["脩蔓屋頭綴，大壺簷外垂。", "霜乾葉猶苦，風斷根未移。", "收挂煙突近，開充酒具遲。", "賤生無所用，會有千金時。"]'),
('675a6139-caeb-492b-9848-c5903d5f2f85','九月二日夢後寄裴如晦','梅堯臣','宋','宋诗','song-poetry','','[]','裴生安健否，試問雁經過。',48,'全唐诗/poet.song.14000.json','["裴生安健否，試問雁經過。", "處士賦鸚鵡，將軍養駱駝。", "食魚今飽未，索米奈貧何。", "昨夜分明夢，持書認篆窠。"]'),
('405f05c2-9654-483f-a062-5703a0967c26','昭信淮上','梅堯臣','宋','宋诗','song-poetry','','[]','清淮渺然去，白浪勢如奔。',48,'全唐诗/poet.song.14000.json','["清淮渺然去，白浪勢如奔。", "同發已先遠，獨行將向昏。", "洲長寧辨路，夜泊偶依村。", "燈火稍覺亂，應聞人語喧。"]'),
('927b33e3-9330-48bd-ba7e-41a112d85b85','小村','梅堯臣','宋','宋诗','song-poetry','','[]','淮闊州多忽有村，棘籬疎敗謾爲門。',64,'全唐诗/poet.song.14000.json','["淮闊州多忽有村，棘籬疎敗謾爲門。", "寒雞得食自呼伴，老叟無衣猶抱孫。", "野艇鳥翹唯斷纜，枯桑水齧只危根。", "嗟哉生計一如此，謬入王民版籍論。"]'),
('82b83f17-485b-4f9b-b297-d3938944eccd','難知','梅堯臣','宋','宋诗','song-poetry','','[]','自古難知不遇人，朝爲蛇鼠暮龍麟。',64,'全唐诗/poet.song.14000.json','["自古難知不遇人，朝爲蛇鼠暮龍麟。", "魏齊客溺簀中死，亭長妻輕胯下貧。", "白石夜歌誰與進，黄金懷印自能伸。", "丈夫只患無才業，何恨區區逐路塵。"]'),
('38151c49-2346-4ccc-b028-f4ec62968010','九山','梅堯臣','宋','宋诗','song-poetry','','[]','我經九山問野叟，崔嵬一無安曰九。',56,'全唐诗/poet.song.14000.json','["我經九山問野叟，崔嵬一無安曰九。", "且恐斷岸積瓊玖，復意陂原多産韭。", "又疑堆壟若柱灸。", "四者未悟叟不言，使我臨流獨搔首。"]'),
('7d99ad67-deda-4340-948d-ac0487fa6d91','淮岸','梅堯臣','宋','宋诗','song-poetry','','[]','秋水刷土骨，峭瘦如老石。',48,'全唐诗/poet.song.14000.json','["秋水刷土骨，峭瘦如老石。", "虛沙歸島嶼，寒浪潄竅隙。", "下過白魚尾，上有蒼獺跡。", "平崗自相連，野籜鳴風櫟。"]'),
('cf87858b-3cf6-4c3f-aafc-c13142cb91a0','原有禽倏鳴升遽默下','梅堯臣','宋','宋诗','song-poetry','','[]','小禽不盈握，羽翮自輕捷。',48,'全唐诗/poet.song.14000.json','["小禽不盈握，羽翮自輕捷。", "裊裊上雲鳴，聲窮如隕葉。", "雀懷啄粟娛，鷃有棲蒿愜。", "嗟嗟力甚微，枉與鷹鸇接。"]'),
('4b8b47a5-7bee-4044-9ada-540cdd3a177c','浮來山','梅堯臣','宋','宋诗','song-poetry','','[]','秦鬼驅卯沙，聚結無蒼翠。',48,'全唐诗/poet.song.14000.json','["秦鬼驅卯沙，聚結無蒼翠。", "誰云海上移，能與潮浮至。", "洞噓蛟鼉腥，廟畫風雷異。", "雲母今有無，庶爲仙藥餌。"]'),
('97c16d1a-85b2-4f9c-88e6-f6b7f7b55df2','泊下黄溪','梅堯臣','宋','宋诗','song-poetry','','[]','黄溪晚來泊，得見田家微。',48,'全唐诗/poet.song.14000.json','["黄溪晚來泊，得見田家微。", "刺艇斜陽下，耕洲載耒歸。", "牛鳴向窂犢，犬喜入人衣。", "復有返樵者，檐枯翹雉肥。"]'),
('098597cb-7cb5-434f-ab71-aee9e581e25d','濠梁感懷','梅堯臣','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','天子昔封禪，吾叔從金輿。',48,'全唐诗/poet.song.14000.json','["天子昔封禪，吾叔從金輿。", "迴首泰山下，出建雙隼旟。", "來尋觀魚臺，遂遠承明廬。", "當時十五詠，螢照墨石書。"]'),
('8c6d580c-9715-4f01-8eb4-ef32f89924ad','渦口','梅堯臣','宋','宋诗','song-poetry','','[]','秋水見灘底，淺沙交浪痕。',48,'全唐诗/poet.song.14000.json','["秋水見灘底，淺沙交浪痕。", "白魚跳處急，宿雁下時昏。", "带月入渦尾，落帆防石根。", "清淮行未盡，明日又前村。"]'),
('5e0ff932-2720-41a4-a581-fa83afce620f','夢同諸公餞仲文夢中坐上作','梅堯臣','宋','宋诗','song-poetry','','[]','已許郊間陳祖席，少停車馬莫催行。',32,'全唐诗/poet.song.14000.json','["已許郊間陳祖席，少停車馬莫催行。", "劉郎休恨三千里，樽酒十分聽我傾。"]'),
('97479b18-0cd6-4031-b25d-7a916ac14be4','過塗荆二山遇暗石','梅堯臣','宋','宋诗','song-poetry','','[]','淮流兩山間，勢束秋漲急。',60,'全唐诗/poet.song.14000.json','["淮流兩山間，勢束秋漲急。", "聚石如伏兵，斂斂波下立。", "輕舟不可防，而况昧所習。", "暗值柂已毀，後者戒前及。", "同發去漸遥，更愁寒灘澀。"]'),
('5a0f4d81-7f19-4f63-a9a9-130931bb8bb0','舟上采菊','梅堯臣','宋','宋诗','song-poetry','','[]','泯泯平慢流，行當季秋月。',48,'全唐诗/poet.song.14000.json','["泯泯平慢流，行當季秋月。", "演漾過汀洲，汀洲芳杜歇。", "白露夜正霏，黄菊寒更發。", "采以泛酒巵，不獨映華髮。"]'),
('abc66733-d67e-4d6d-9576-183193e0d703','朝暮','梅堯臣','宋','宋诗','song-poetry','','[]','氣候輒未定，寒暄朝暮間。',48,'全唐诗/poet.song.14000.json','["氣候輒未定，寒暄朝暮間。", "挾纊水風生，衣綌川陽還。", "綠草藏邃岸，枯櫟植高山。", "且非天時異，順理心自閑。"]'),
('93adf807-902f-4d95-bae7-12444aa9ee84','荆山','梅堯臣','宋','宋诗','song-poetry','','[]','和楚人，茲楚地。',40,'全唐诗/poet.song.14000.json','["和楚人，茲楚地。", "泣玉山，無所記。", "但見楚人誇産玉，古廟幽幽無鬼哭。", "儻有鬼，定無足。"]'),
('11895415-b43d-4bdd-8368-7b584e4905e7','塗山','梅堯臣','宋','宋诗','song-poetry','','[]','古傳神禹迹，今向舊山阿。',48,'全唐诗/poet.song.14000.json','["古傳神禹迹，今向舊山阿。", "莫問辛壬娶，從來甲子多。", "夜淮低激射，朝江上嵯峨。", "荒廟立泥骨，巖頭風雨過。"]'),
('aa2ff2d0-d54a-4e0d-bb0d-e0ae43642687','曉日','梅堯臣','宋','宋诗','song-poetry','','[]','出舟曉日升曈矓，波上爛爛黄金鎔。',48,'全唐诗/poet.song.14000.json','["出舟曉日升曈矓，波上爛爛黄金鎔。", "羃歷紫煙生鏡中，釣船似畫分橫縱。", "風莫從虎雲從龍，變作霏霞重復重。"]'),
('446ea070-cc4e-46f7-9181-212839dba5b5','雞聲','梅堯臣','宋','宋诗','song-poetry','','[]','雞聲踏曉呼，呼起扶桑烏。',48,'全唐诗/poet.song.14000.json','["雞聲踏曉呼，呼起扶桑烏。", "含光如車輪，碾雲蹤跡無。", "誰教夸父逐，遠向鄧林趨。", "復從海底轉，循環似轆轤。"]'),
('ab8eacf4-8784-4cd9-ab68-02ec616b5d22','采杞','梅堯臣','宋','宋诗','song-poetry','','[]','誰謂岸無杞，條其長矣。',62,'全唐诗/poet.song.14000.json','["誰謂岸無杞，條其長矣。", "誰謂杞無實，爛其皇矣。", "掇彼征矣，檐既盈矣。", "捨棘與蠹，造此宜酒。", "維此宜酒，我挹我注。", "我飲我助，以養我籲。"]'),
('1f244dd2-9e5d-4b69-a27d-87092efd6566','泊橛澗觀渡','梅堯臣','宋','宋诗','song-poetry','','[]','隔岸呼舟檝，臨河立馬牛。',48,'全唐诗/poet.song.14000.json','["隔岸呼舟檝，臨河立馬牛。", "解鞍沙上憩，沉網渚間收。", "殘日銜沙尾，孤帆落戍頭。", "莫愁暄作雨，晚水白煙浮。"]'),
('a0d7c201-1ba9-43e1-8258-58ed255d03a0','看山寄宋中道','梅堯臣','宋','宋诗','song-poetry','','[]','前山不礙遠，斷處吐尖碧。',60,'全唐诗/poet.song.14000.json','["前山不礙遠，斷處吐尖碧。", "研青點無光，淡墨近有跡。", "前林橫白雲，復與後嶺隔。", "孤舟川上人，引望不知夕。", "安得老畫師，寫寄幽懷客。"]'),
('6617de5b-60f6-4809-b231-f54585980c09','暮雨','梅堯臣','宋','宋诗','song-poetry','','[]','水上魚，吹白露。',48,'全唐诗/poet.song.14000.json','["水上魚，吹白露。", "山頭雲，與龍附。", "潭中水作潭中雨，朱鼈飛過吳洲去。", "鯉魚相隨不知數，老蛤銜泥在深處。"]'),
('97d08bdd-4250-474a-82d9-f192041485fe','細雨樵行','梅堯臣','宋','宋诗','song-poetry','','[]','蛟人困卧寒潭底，怗波濛濛垂白綃。',64,'全唐诗/poet.song.14000.json','["蛟人困卧寒潭底，怗波濛濛垂白綃。", "波上女兒飛輕橈，逆流自與郎去樵。", "風吹鬢髮不及撩，鴉翅卷起蠆尾翹。", "濃纈羅带長繞腰，日暮下來吹短簫。"]'),
('57d03706-e8b4-405c-bdb4-09b7ed981f1f','晨鴉','梅堯臣','宋','宋诗','song-poetry','','[]','雲昏月黑鴉不知，皷聲鼕鼕雞報啼。',56,'全唐诗/poet.song.14000.json','["雲昏月黑鴉不知，皷聲鼕鼕雞報啼。", "睥睨未辨天東西，癡雛噪舞羣翅低。", "野桑葉卷風淒淒，濃霧不起寒雨迷，晨鴉却歸巢上棲。"]'),
('6ff18841-75c1-41cd-9fa7-34ac6da2be83','會稽婦','梅堯臣','宋','宋诗','song-poetry','','[]','食藕莫問濁水泥，嫁婿莫問寒家兒。',128,'全唐诗/poet.song.14000.json','["食藕莫問濁水泥，嫁婿莫問寒家兒。", "寒兒黧黑面無脂，驥子縱瘦骨骼奇。", "買臣貧賤妻生離，行歌負薪何媿之。", "高車來駕建朱旗，銅牙文弩擐犀皮。", "官迎吏走馬萬蹄，江潮晝起橫白霓。", "舊妻呼載後乘歸，悔淚夜落無聲啼。", "吳酒雖美吳魚肥，儂今豢養慚豬雞。", "園中高樹多曲枝，一日挂與桑蟲齊。"]'),
('779f38aa-2a51-4123-9a3a-74f82f6d264a','九日次壽州','梅堯臣','宋','宋诗','song-poetry','','[]','昔人把菊望青榼，今我持酒無黄花。',64,'全唐诗/poet.song.14000.json','["昔人把菊望青榼，今我持酒無黄花。", "自催屋裏紅鱗膾，不彈牆頭白項鴉。", "壽春城高枕淮水，綠蒲疎疎暮帆起。", "登臨不學孟參軍，帽墜山風費嘲紙。"]'),
('39e7cc5a-c91f-48c4-a487-c71ffc381423','泊壽春龍潭上夜半黑風破一舟','梅堯臣','宋','宋诗','song-poetry','','[]','盲風吼空來，不識前山遮。',120,'全唐诗/poet.song.14000.json','["盲風吼空來，不識前山遮。", "迴激入灣口，暗浪騰水涯。", "喧聞破我船，沉沒驚一家。", "晦昧若塗漆，心緒如亂麻。", "燈光不出戶，鬼火空照沙。", "百物任漂蕩，薄命誰怨嗟。", "但存此空舟，坐類鳥寄槎。", "妻孥皆失色，一夕鬢欲華。", "詹惶俟天明，頃刻抵歲遐。", "雨寒雞唱遲，况乃城上鴉。"]'),
('a6215b13-9583-410c-ac48-3dba33195881','潁上得鯉魚爲膾懷餘姚謝師厚','梅堯臣','宋','宋诗','song-poetry','','[]','青蓑潭上老，赬尾網中魚。',48,'全唐诗/poet.song.14000.json','["青蓑潭上老，赬尾網中魚。", "買作秋盤膾，還思遠客書。", "越齏橙熟久，楚飯稻舂初。", "雖去故鄉遠，不嫌爲饌疎。"]'),
('0542fe42-21ac-4eab-9cc0-8038da51f042','丘家渡早發','梅堯臣','宋','宋诗','song-poetry','','[]','曲潁若秋蛇，屈盤鱗甲活。',48,'全唐诗/poet.song.14000.json','["曲潁若秋蛇，屈盤鱗甲活。", "問戍得耕人，拾魚逢祭獺。", "草窠殘野燒，樹挂經流沫。", "百里相對看，頻行媿迂闊。"]'),
('1af4b999-d6a8-4dfa-a41b-e1873c188e5e','水次蘚花','梅堯臣','宋','宋诗','song-poetry','','[]','秋雨日霏霏，碧花生疊疊。',48,'全唐诗/poet.song.14000.json','["秋雨日霏霏，碧花生疊疊。", "水邊有神女，粧去遺翠靨。", "岸側小家婦，不知所宜愜。", "未得未還人，自將渾面帖。"]'),
('ffb1518d-b539-4bc4-b3bb-065fcf63cbd6','夜行憶山中','梅堯臣','宋','宋诗','song-poetry','','[]','青熒鬼火動，不悟前山雨。',48,'全唐诗/poet.song.14000.json','["青熒鬼火動，不悟前山雨。", "昏徑梟鳥鳴，獨行毛髮聚。", "桷葉枯綴林，風動疑有虎。", "低迷薄雲開，心喜淡月吐。"]'),
('1e707cee-0c3a-4c26-b8b1-a06724b594ea','村醪','梅堯臣','宋','宋诗','song-poetry','','[]','雨濕破荆籬，風摇樹亞旗。',48,'全唐诗/poet.song.14000.json','["雨濕破荆籬，風摇樹亞旗。", "小槽聲不急，挈榼問沽遲。", "摘果野棠熟，望人船火隨。", "燈前相對飲，還似昔過時。"]'),
('b4de9747-fe41-4795-9f4d-bd4a96af296f','川上田家','梅堯臣','宋','宋诗','song-poetry','','[]','斜光隔河明，入照桑柘下。',48,'全唐诗/poet.song.14000.json','["斜光隔河明，入照桑柘下。", "臯壠生麥苗，青青尚堪把。", "遠見牛羊歸，相親童稚野。", "醉歌秋草間，頗與世家寡。"]'),
('26926288-a245-49c1-8586-5cf8bd6985ba','發勻陵','梅堯臣','宋','宋诗','song-poetry','','[]','秋雨密無迹，濛濛在一川。',48,'全唐诗/poet.song.14000.json','["秋雨密無迹，濛濛在一川。", "孤村望漸遠，去鳥飛已先。", "向晚雲漏日，微光人倚船。", "安知偶自適，落岸逢沙泉。"]'),
('bfc528dd-8f62-44b5-8633-597ed859d87d','聞雁','梅堯臣','宋','宋诗','song-poetry','','[]','濕雲夜不散，薄處微有星。',48,'全唐诗/poet.song.14000.json','["濕雲夜不散，薄處微有星。", "孤雁去何急，一聲愁更聽。", "心應失舊侶，翅已高青冥。", "幾日江海上，鳬鷗共滿汀。"]'),
('ecc05101-3d42-4691-b050-a9b799054717','牽船人','梅堯臣','宋','宋诗','song-poetry','','[]','沙洲折脚雁，疑人鋪翅行。',48,'全唐诗/poet.song.14000.json','["沙洲折脚雁，疑人鋪翅行。", "奈何暮雨來，復值寒風生。", "濕毛染泥滓，縮頸無鳴聲。", "爾輩正若此，猶勝被堅兵。"]'),
('3f589c9f-884c-47d9-96fa-32493b77a331','田人夜歸','梅堯臣','宋','宋诗','song-poetry','','[]','田收野更迥，墟里隔煙陂。',48,'全唐诗/poet.song.14000.json','["田收野更迥，墟里隔煙陂。", "荒徑已風急，獨行唯犬隨。", "荆扉候不掩，稚子望先知。", "自是一生樂，何須閭井爲。"]'),
('c43a5fd6-75b5-49d2-8598-a6afb024eb63','行次潁州聞張甥宗亮不捷鄉薦以詩唁而迎之','梅堯臣','宋','宋诗','song-poetry','','[]','風前汝陰道，雨冷江南書。',48,'全唐诗/poet.song.14000.json','["風前汝陰道，雨冷江南書。", "始歎與意異，何慚定鑑疎。", "但能存楚玉，切莫道黔馿。", "不負當時約，馳迎一乘車。"]'),
('55d5cee6-ef75-48a7-8d3b-69a89e2e50d5','聞櫓','梅堯臣','宋','宋诗','song-poetry','','[]','靜夜有舟下，中流聞櫓聲。',48,'全唐诗/poet.song.14000.json','["靜夜有舟下，中流聞櫓聲。", "隔窗燈已暗，卷幔月微明。", "漸向寒灣遠，遥應宿枕驚。", "客心何苦急，曾是不緣名。"]'),
('1dbc599f-e2ac-49bd-a159-f182316444fb','晚鷗','梅堯臣','宋','宋诗','song-poetry','','[]','晴川带微陽，鷗鳥雙飛去。',48,'全唐诗/poet.song.14000.json','["晴川带微陽，鷗鳥雙飛去。", "雙飛如有歸，並宿向何處。", "汀寒霧羃歷，永落沙沮洳。", "不避近行舟，應知心寡慮。"]'),
('27b1aed4-c61a-4b41-9aa4-694df153adee','新晴','梅堯臣','宋','宋诗','song-poetry','','[]','陰雲忽掃盡，朝日吐清光。',48,'全唐诗/poet.song.14000.json','["陰雲忽掃盡，朝日吐清光。", "萬里不礙日，衆鳥欣哢吭。", "草樹已摇落，山川尚鬰蒼。", "百事擇佳日，佳日唯晴陽。"]'),
('864451bf-6d76-4cf7-8ee6-d93973fd7c21','將次項城阻風舟不能進','梅堯臣','宋','宋诗','song-poetry','','[]','逆水寒風急，輕舟晚不前。',48,'全唐诗/poet.song.14000.json','["逆水寒風急，輕舟晚不前。", "因來泊古渡，聊且上平田。", "草軟行方穩，鶉驚去瞥然。", "却尋孤岸遠，吹幘亂華顛。"]'),
('8ca8473a-cde1-45a8-8ce2-594b69380d9c','斫膾懷永叔','梅堯臣','宋','宋诗','song-poetry','','[]','高河古穴深，下有蒼鱗鯽。',48,'全唐诗/poet.song.14000.json','["高河古穴深，下有蒼鱗鯽。", "出水獰將飛，落刀細可織。", "香粳炊正滑，白酒美少力。", "但欠平生歡，共此中路食。"]'),
('4050d0a7-0775-4105-8e1e-5ad45427d8ca','夜漁','梅堯臣','宋','宋诗','song-poetry','','[]','夜漁歸自速，短艇若飛雲。',48,'全唐诗/poet.song.14000.json','["夜漁歸自速，短艇若飛雲。", "水動月猶白，挐音人不聞。", "迴身明燭底，撫卷至宵分。", "我以此爲足，勞勞非爾羣。"]'),
('e74c901c-88aa-4cd5-91d7-19f653c4bfdb','驚鳧','梅堯臣','宋','宋诗','song-poetry','','[]','驚鳬雖避人，終戀舊所泊。',36,'全唐诗/poet.song.14000.json','["驚鳬雖避人，終戀舊所泊。", "盡背船頭去，却從船尾落。", "須知取勢高，不是初飛錯。"]'),
('b12c7f1d-5d37-4e4a-a2cb-9341a9199652','十月三日相公花下小飲賦四題 拒霜','梅堯臣','宋','宋诗','song-poetry','','[]','木杪芙蓉花，開非紅豔早。',24,'全唐诗/poet.song.14000.json','["木杪芙蓉花，開非紅豔早。", "常畏晚霜寒，朱華競衰草。"]'),
('7449ad14-a393-48f7-bb60-86505a08f52f','十月三日相公花下小飲賦四題 九月二十八日牡丹','梅堯臣','宋','宋诗','song-poetry','','[]','香包已向青春發，又見秋深特地開。',32,'全唐诗/poet.song.14000.json','["香包已向青春發，又見秋深特地開。", "應笑菊殘無意思，不能邀賦洛陽才。"]'),
('0fa561a0-346e-4521-808c-171763f20b92','十月三日相公花下小飲賦四題 殘菊','梅堯臣','宋','宋诗','song-poetry','','[]','零落黄金蕊，雖枯不改香。',24,'全唐诗/poet.song.14000.json','["零落黄金蕊，雖枯不改香。", "深叢隠孤秀，猶得奉清觴。"]'),
('c863744e-1802-41d8-9d63-252af5224a51','十月三日相公花下小飲賦四題 三日醼集','梅堯臣','宋','宋诗','song-poetry','','[]','蕭然寒圃有殘芳，吟遍朱欄向夕陽。',32,'全唐诗/poet.song.14000.json','["蕭然寒圃有殘芳，吟遍朱欄向夕陽。", "既許坐陪公衮貴，却慚蒿羽接鸞凰。"]'),
('830f4361-31c2-4858-b386-4146e2e0aeee','依韻許主客北樓夜會','梅堯臣','宋','宋诗','song-poetry','','[]','一日能逢幾笑歡，高樓紅蠟滴金盤。',64,'全唐诗/poet.song.14000.json','["一日能逢幾笑歡，高樓紅蠟滴金盤。", "吟餘隴首雲初散，唱盡陽關露已寒。", "不管星河漸西落，自將煙水去程寬。", "當時坐客各南北，誰憶重遊泛木蘭。"]'),
('56711ffa-74f3-4910-8a8a-83fb719865fc','謹和相國屋上菊叢','梅堯臣','宋','宋诗','song-poetry','','[]','屋上有叢菊，結根深瓦縫。',96,'全唐诗/poet.song.14000.json','["屋上有叢菊，結根深瓦縫。", "既無地勢美，又乏土力擁。", "乃因塗明生，不由人所種。", "亦能應節開，焉取入公用。", "公來步廣庭，聞雁目始縱。", "忽見粲然英，降植合常從。", "賓僚席其傍，詠玩意已重。", "物莫厭僻遠，會遇良可頌。"]'),
('047d0c22-435b-4a50-8019-c7174e7ffedf','寒菜','梅堯臣','宋','宋诗','song-poetry','','[]','畦蔬收莫晚，圃吏已能供。',48,'全唐诗/poet.song.14000.json','["畦蔬收莫晚，圃吏已能供。", "根脆土將凍，葉萎霜漸濃。", "不應虛匕筯，還得間庖饔。", "旨蓄詩人詠，從來用禦冬。"]'),
('5181f5db-f16b-424b-adeb-14c58e357a97','送裴節推歸京','梅堯臣','宋','宋诗','song-poetry','','[]','遠水未生凍，輕舟歸大梁。',48,'全唐诗/poet.song.14000.json','["遠水未生凍，輕舟歸大梁。", "岸迴初向月，篙滑始霑霜。", "清世豈淹俊，上公存薦章。", "行應重對策，莫愧漢賢良。"]'),
('0ae2b9dc-3e9e-4af4-ae64-efbe03ab27ba','十月菊上蜂','梅堯臣','宋','宋诗','song-poetry','','[]','黄蜂得晴日，不道菊開稀。',48,'全唐诗/poet.song.14000.json','["黄蜂得晴日，不道菊開稀。", "向蕊晚寒起，落叢無力飛。", "輕輕難自舉，怗怗一何微。", "莫問巢房處，斜陽奈欲歸。"]'),
('255f1694-be27-449e-bed6-4854e0fcad22','送江學士睦州通判','梅堯臣','宋','宋诗','song-poetry','','[]','涉淮淮水淺，泝溪溪水遲。',36,'全唐诗/poet.song.14000.json','["涉淮淮水淺，泝溪溪水遲。", "君到桐廬日，正值采茶時。", "試問嚴陵跡，今復有誰知。"]'),
('3cfb056c-93a3-4b12-b78a-e1333303b228','和民樂','梅堯臣','宋','宋诗','song-poetry','','[]','歲晚場功畢，野老相經過。',96,'全唐诗/poet.song.14000.json','["歲晚場功畢，野老相經過。", "有酒自斟酌，適意同笑歌。", "大兒緝牛衣，小兒護雞窠。", "囷廩見餘積，息戍靡負戈。", "林間落熟果，屋裏鳴寒梭。", "會待朔雪時，狐兔生罝羅。", "飫鮮持作腊，贈乏不言他。", "是非了莫問，此理當何如。"]'),
('889809c0-573d-423e-8114-fd7391272d88','和晚花','梅堯臣','宋','宋诗','song-poetry','','[]','春花莫厭早，秋草莫厭遲。',84,'全唐诗/poet.song.14000.json','["春花莫厭早，秋草莫厭遲。", "各不相羨慕，榮枯乃繫時。", "芙蓉東籬英，雖晚亦自宜。", "霜前給給開，霜後差差萎。", "深處有孤萼，寒月尚見披。", "野蜂徒愛香，凍翼不能支。", "抱枝無力去，憫然見恩私。"]'),
('42077776-17d2-4d74-8970-54e4dea79815','擬李益竹窗聞風寄苗發司空曙','梅堯臣','宋','宋诗','song-poetry','','[]','窗前風動竹，聲碎影仍繁。',48,'全唐诗/poet.song.14000.json','["窗前風動竹，聲碎影仍繁。", "衝扉忽自啟，出候初迎門。", "驚雀枝未定，乳蜂窠暫翻。", "飄飄一舉袂，聊更遲來轅。"]'),
('a9fb161a-c4bd-46c5-8255-3b719a3f2da2','擬宋之問春日翦綵花應制','梅堯臣','宋','宋诗','song-poetry','','[]','上林花未有，中禁綵先成。',48,'全唐诗/poet.song.14000.json','["上林花未有，中禁綵先成。", "葉逐翦刀出，蕊從粧粉生。", "紅繁內人手，香染侍臣纓。", "不是將春競，天心重發榮。"]'),
('198c2bf0-e533-4e3e-95d1-aa825a91bca7','郡閣閱書投壺和呈相國晏公','梅堯臣','宋','宋诗','song-poetry','','[]','較量人世無窮樂，羅列平生未見書。',64,'全唐诗/poet.song.14000.json','["較量人世無窮樂，羅列平生未見書。", "聊奉投壺祭征虜，休言繫劍馬相如。", "畫樓晚去聞寒角，縹帙看來落蠹魚。", "日獲誨言皆舊學，不慚貧賤带經鋤。"]'),
('9dd31301-0093-40c5-b1bc-b3002d294388','梅花','梅堯臣','宋','宋诗','song-poetry','','[]','江南臘月前溪上，照水野梅多少株。',64,'全唐诗/poet.song.14000.json','["江南臘月前溪上，照水野梅多少株。", "豔薄自將同鵠羽，粉寒曾不逐蜂鬚。", "桃根有妹猶含凍，杏樹爲鄰尚带枯。", "楚客且休吹玉笛，清香飄盡更應無。"]'),
('aeefadd3-7577-40ea-9336-ccb825f4681d','擬張九齡詠燕','梅堯臣','宋','宋诗','song-poetry','','[]','眇眇雙來燕，長年與社違。',48,'全唐诗/poet.song.14000.json','["眇眇雙來燕，長年與社違。", "任從新曆改，只向舊巢歸。", "永日當人語，輕寒逆雨飛。", "自親梁棟慣，不識海鷗機。"]'),
('10bf8361-e1b3-431b-ad4c-c66656b2a54f','遲雪','梅堯臣','宋','宋诗','song-poetry','','[]','風嚎大澤晚，雲覆女牆低。',48,'全唐诗/poet.song.14000.json','["風嚎大澤晚，雲覆女牆低。", "驚霰夜將集，廣庭朝復迷。", "鶑鳴寒蔽日，鴈泊凍生谿。", "會待飄花密，開軒意外題。"]'),
('abc5a08c-1747-472c-aab4-10b4adc802b1','欲雪復晴','梅堯臣','宋','宋诗','song-poetry','','[]','陰雲不成雪，碧瓦有繁霜。',48,'全唐诗/poet.song.14000.json','["陰雲不成雪，碧瓦有繁霜。", "日氣生簾額，冰條結井牀。", "飛烏鳴自樂，古木晝仍殭。", "誰意斗晴後，苦寒勝北方。"]'),
('fdd76a84-f2ab-4173-a33e-cc2899f1dcf2','送蒙寺丞赴郢州','梅堯臣','宋','宋诗','song-poetry','','[]','郢國當時唱，猶傳白雪真。',48,'全唐诗/poet.song.14000.json','["郢國當時唱，猶傳白雪真。", "問今非昔日，和者幾何人。", "客自射飛雁，漁能供躍鱗。", "芳洲墮馬處，吾祖漢名臣。"]'),
('4310bdcc-cbda-45ee-b351-505b923e662e','聞角','梅堯臣','宋','宋诗','song-poetry','','[]','一聲催客夢，星斗轉西簷。',48,'全唐诗/poet.song.14000.json','["一聲催客夢，星斗轉西簷。", "風卷梅花去，愁從柳塞添。", "馬鳴霜滿鬣，龍泣凍生髯。", "高樹朝光動，城頭落海蟾。"]'),
('6da097e0-eebb-469c-a39d-5f0c76631d39','和人雪意','梅堯臣','宋','宋诗','song-poetry','','[]','凍雲低垂野，遠樹昏未分。',120,'全唐诗/poet.song.14000.json','["凍雲低垂野，遠樹昏未分。", "朝來庭竹上，摵摵霰已聞。", "扣門有兵吏，嘉命傳相君。", "趨閤展熊席，卷幔飄爐熏。", "桂漿貯榼美，馬乳薦實蕡。", "賓屬兩三人，從容奉評文。", "遠稽先儒言，風賦可以羣。", "密置筆與硯，唯待雪雰雰。", "雪既不可待，日暮人半醺。", "明朝獲方楮，健思欲凌雲。"]'),
('e0756eb2-47c2-441e-9282-cd5a856303ac','和楊高品馬廄猢猻','梅堯臣','宋','宋诗','song-poetry','','[]','嘗聞養騏驥，辟惡繫獼猴。',48,'全唐诗/poet.song.14000.json','["嘗聞養騏驥，辟惡繫獼猴。", "供奉新教藝，將軍舊病偷。", "聊看緣柱杪，尚想傍崖頭。", "更祝南州使，如拳試爲求。"]'),
('47b895d3-ae3d-41d6-bfd1-7a86d5178ab3','和欲雪二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','貂裘著不暖，牙帳曉初開。',48,'全唐诗/poet.song.14000.json','["貂裘著不暖，牙帳曉初開。", "朔氣還先及，流風亦屢催。", "擬聞人詠絮，將見使傳梅。", "公復憂民畝，龍沙幾日來。"]'),
('2dfb6933-c859-46f6-9397-b36aa4b92d0e','和欲雪二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','雪欲漫天落，雲初著地垂。',48,'全唐诗/poet.song.14000.json','["雪欲漫天落，雲初著地垂。", "臂鷹過野健，走馬上冰遲。", "公子多論酒，騷人自詠詩。", "都無少年意，只卧竹窗宜。"]'),
('a28ad3e8-c39e-49dd-a2a4-aeb70c90e705','梅花','梅堯臣','宋','宋诗','song-poetry','','[]','已先羣木得春色，不與杏花爲比紅。',64,'全唐诗/poet.song.14000.json','["已先羣木得春色，不與杏花爲比紅。", "薄薄遠香來澗谷，疎疎寒影近房櫳。", "全枝惡折憎鄰女，短笛橫吹怨楚童。", "墜萼誰將呵在鬢，蕊殘金粟上眉蟲。"]'),
('8da793a3-1151-4b1d-b7dd-e1bfbcc210b3','和十一月八日圃人獻小桃花二絕  其一','梅堯臣','宋','宋诗','song-poetry','','[]','當時開向杏花後，今日綻當梅萼前。',32,'全唐诗/poet.song.14000.json','["當時開向杏花後，今日綻當梅萼前。", "不畏雪霜何太甚，繁英如火滿枝燃。"]'),
('0030b17d-fa99-41dc-b8b9-ab6be4e85d3b','和十一月八日圃人獻小桃花二絕  其二','梅堯臣','宋','宋诗','song-poetry','','[]','前占寒食一百六，算到其時未合開。',32,'全唐诗/poet.song.14000.json','["前占寒食一百六，算到其時未合開。", "丹豔已先灰管動，不由人力與栽培。"]'),
('badc1f37-6453-4e6f-81fc-1e5bfab4eeb9','和梅花','梅堯臣','宋','宋诗','song-poetry','','[]','時時不甘春著力，年年能占臘前芳。',64,'全唐诗/poet.song.14000.json','["時時不甘春著力，年年能占臘前芳。", "水邊攀折此中女，馬上嗅尋何處郎。", "山舍更清栽作援，鳳樓偏巧學成粧。", "團枝密密都如雪，野雀飛來翅合香。"]'),
('459f555d-8d6e-48a9-bbae-4ab7581fce1e','再送蒙寺丞赴郢州','梅堯臣','宋','宋诗','song-poetry','','[]','彎弓落飛鳥，少也向幽州。',48,'全唐诗/poet.song.14000.json','["彎弓落飛鳥，少也向幽州。", "來作漢官屬，恥爲戎國留。", "身輕拋馬轡，地暖厭狐裘。", "慣見顔如玉，江邊問莫愁。"]'),
('b8221845-cbdf-45d2-8085-481268ab16a3','擬王維觀獵','梅堯臣','宋','宋诗','song-poetry','','[]','白草南山獵，調弓發指鳴。',48,'全唐诗/poet.song.14000.json','["白草南山獵，調弓發指鳴。", "原邊黄犬去，雲外皁雕迎。", "近出長陵道，還看小苑城。", "聊從向來騎，回望夕陽平。"]'),
('e77875ff-e661-4b3c-9d00-579388b4bd16','擬陶潛止酒','梅堯臣','宋','宋诗','song-poetry','','[]','多病願止酒，不止病不已。',120,'全唐诗/poet.song.14000.json','["多病願止酒，不止病不已。", "止之懼無歡，雖病未宜止。", "且欲止人事，事止不經耳。", "次誦止足言，行當止田里。", "田里止誰親，止樂山水美。", "既止何所助，唯酒與止喜。", "以言止不止，未必止爲是。", "止酒儻不瘳，枉止徒可恥。", "止亦隨化遷，不止等亦死。", "慎勿道止酒，止酒乃君子。"]'),
('ee825747-222a-4e06-835f-9d47b6549b03','擬杜甫玉華宮','梅堯臣','宋','宋诗','song-poetry','','[]','松深溪色古，中有鼯鼠鳴。',96,'全唐诗/poet.song.14000.json','["松深溪色古，中有鼯鼠鳴。", "廢殿不知年，但與蒼崖平。", "鬼火出空屋，未繼華燭明。", "暗泉發虛竇，似作哀絃鳴。", "黄金不變土，玉質空令名。", "當時從輿輦，石馬埋棘荆。", "獨來感舊物，煎懷如沸羹。", "區區人世間，誰免此虧盈。"]'),
('95fb56ea-27ef-4a3b-971d-46b029f67c83','擬韋應物殘燈','梅堯臣','宋','宋诗','song-poetry','','[]','照此寒夜中，欲殘紅燼尾。',24,'全唐诗/poet.song.14000.json','["照此寒夜中，欲殘紅燼尾。", "空堂滅復明，獨宿擬山鬼。"]'),
('3ad37b29-4533-4c45-a774-63a4a8c0d17e','和十一月十二日與諸君登西園亭榭懷舊書事  其一','梅堯臣','宋','宋诗','song-poetry','','[]','冬日蕭條公府清，獨將諸吏上高城。',32,'全唐诗/poet.song.14000.json','["冬日蕭條公府清，獨將諸吏上高城。", "而今何處異疇昔，鐵墓下聞狐夜鳴。"]'),
('84ebc47e-2264-4395-8d33-c7988a514e3e','和十一月十二日與諸君登西園亭榭懷舊書事  其二','梅堯臣','宋','宋诗','song-poetry','','[]','莎徑依然見莎葉，蓮塘無復有蓮花。',32,'全唐诗/poet.song.14000.json','["莎徑依然見莎葉，蓮塘無復有蓮花。", "更看白水滿城下，說著當時龍骨車。"]'),
('e3d5f8ef-b25b-4e9e-950b-3851733eafce','和小雨','梅堯臣','宋','宋诗','song-poetry','','[]','蛟龍潠白霧，天外細濛濛。',48,'全唐诗/poet.song.14000.json','["蛟龍潠白霧，天外細濛濛。", "霑土曾無跡，昏林似有風。", "卷旗妨酒舍，濕翅下洲鴻。", "稍見斜陽透，西雲一半紅。"]'),
('4b1a65f6-1091-4338-9ce4-b8618cea2964','擬韓吏部射訓狐','梅堯臣','宋','宋诗','song-poetry','','[]','黄昏月暗妖鳥鳴，尨然鈍質麤豪聲。',160,'全唐诗/poet.song.14000.json','["黄昏月暗妖鳥鳴，尨然鈍質麤豪聲。", "憑凶自異立屋角，潛事觜吻欲我驚。", "豈知慣聞此醜狡，呼集鬼物夸陰獰。", "夕盜雞雛無畏避，曾遭彈射沉泥坑。", "汝今病翼未甚愈，還作舊態侵平明。", "陽烏曈曈出東海，照汝宜喪膽與精。", "何爲世人苦憎汝，汝常盜物資已榮。", "儻有弓矢勿污辱，殺此非得去惡名。", "養雛四三已相似，眼腦實異鸞皇生。", "一朝車輪翅墮地，狐鼠入穴梟黨烹。"]'),
('8021b0fb-43e6-4ac8-aba0-ca872d41c799','得韓持國書報新作茅廬','梅堯臣','宋','宋诗','song-poetry','','[]','聞君作茅廬，正在西軒西。',48,'全唐诗/poet.song.14000.json','["聞君作茅廬，正在西軒西。", "定移舊蔬圃，稍改新藥畦。", "其高如伯鸞，况亦有隠妻。", "今方漢德盛，不必之會稽。"]'),
('18140b3f-966b-4432-a720-e7776729c768','和新晴','梅堯臣','宋','宋诗','song-poetry','','[]','雲開日照戟衣寒，浄掃平沙路已乾。',64,'全唐诗/poet.song.14000.json','["雲開日照戟衣寒，浄掃平沙路已乾。", "吏散庭除少公事，畦挑芽甲足春盤。", "要聽林上鳴鳩變，試步塘陰綠水寬。", "誰詠陳根有微綠，烏蟾易失似跳丸。"]'),
('0458ebc5-717c-4010-bcbb-a85de2e96c38','責躬詩','梅堯臣','宋','宋诗','song-poetry','','[]','所稟介且拙，嘗恥朋比爲。',72,'全唐诗/poet.song.14000.json','["所稟介且拙，嘗恥朋比爲。", "皎皎三十年，半語曾未欺。", "身微德不著，尚使人見疑。", "省己當自責，實負聖相知。", "聖相雖明察，不假束藴辭。", "扣言已可罪，引去豈非宜。"]'),
('d3722bad-28be-4f9b-a48a-bc29d0d54b2e','嘗惠山泉','梅堯臣','宋','宋诗','song-poetry','','[]','吳楚千萬山，山泉莫知數。',108,'全唐诗/poet.song.14000.json','["吳楚千萬山，山泉莫知數。", "其以甘味傳，幾何若飴露。", "大禹書不載，陸生品嘗著。", "昔唯廬谷亞，久與茶經附。", "相襲好事人，砂缾和月注。", "持參萬錢鼎，豈足調羹助。", "彼哉一勺微，唐突爲霖澍。", "疏濃既不同，物用誠有處。", "空林癯面僧，安比侯王趣。"]'),
('2062c9d0-37de-4bad-94eb-b43803845338','糟淮鮊','梅堯臣','宋','宋诗','song-poetry','','[]','寒潭縮淺瀨，空潭多鮊魚。',60,'全唐诗/poet.song.14000.json','["寒潭縮淺瀨，空潭多鮊魚。", "網登肥且美，糟漬奉庖厨。", "昔聞漁父賢，嘗勉楚人餔。", "楚人懷沙死，葬腹千歲餘。", "今茲有遺意，敢共盃盤疎。"]'),
('27d0612a-fad0-4721-a5fd-46cf54860981','和臘前','梅堯臣','宋','宋诗','song-poetry','','[]','漢家戍日看看近，雲景蒼茫已歲昏。',64,'全唐诗/poet.song.14000.json','["漢家戍日看看近，雲景蒼茫已歲昏。", "欲驗方書治百藥，預調飛走獵平原。", "土人熏肉經春美，宮女藏鈎舊戲存。", "獨把凍醪驚節物，草芽微動見庭萱。"]'),
('64e480f1-e185-45be-b0f3-1a50aa2982db','題臘藥','梅堯臣','宋','宋诗','song-poetry','','[]','頹顔早覺衰，乃藉藥扶持。',48,'全唐诗/poet.song.14000.json','["頹顔早覺衰，乃藉藥扶持。", "及此季冬日，預脩來歲宜。", "鼎成無犬見，蜜煉有蜂知。", "借問月中兔，長年何所爲。"]'),
('fc4d4b2a-6e26-444e-a329-2252783f4762','臘酒','梅堯臣','宋','宋诗','song-poetry','','[]','汲井轆轤鳴，寒泉碧甕盛。',48,'全唐诗/poet.song.14000.json','["汲井轆轤鳴，寒泉碧甕盛。", "欲爲三伏美，方俟十旬清。", "夢憶黄公舍，徒聞韋氏名。", "熟時梅杏小，獨飲效淵明。"]'),
('79f331a7-3860-4285-a61d-61997841d34b','臘脯','梅堯臣','宋','宋诗','song-poetry','','[]','畋獵得封獸，割鮮爲腶脩。',48,'全唐诗/poet.song.14000.json','["畋獵得封獸，割鮮爲腶脩。", "易甘非愛日，不敗任經秋。", "可用資賓豆，何妨鄙薦䐹。", "考之新月錄，美脆勝庖牛。"]'),
('76d791bc-a51d-4b77-b2e3-59a11ca867dd','臘笋','梅堯臣','宋','宋诗','song-poetry','','[]','南岡深竹養，下有鷓鴣鳴。',48,'全唐诗/poet.song.14000.json','["南岡深竹養，下有鷓鴣鳴。", "破臘初挑箘，誇新欲比瓊。", "薦盤香更美，案酒味偏清。", "馬援當時見，曾將禹貢評。"]'),
('adb938e7-3f8f-46c6-95c3-d1ca1f2c0e4f','和挑菜','梅堯臣','宋','宋诗','song-poetry','','[]','中圃本膏壤，始覺氣候偏。',60,'全唐诗/poet.song.14000.json','["中圃本膏壤，始覺氣候偏。", "出土蓼甲紅，近水芹芽鮮。", "挑以寶環刀，登之饌玉筵。", "僻遠尚含凍，安占春陽前。", "造物非有意，地勢使之然。"]'),
('9c18f0f4-0ef8-40cd-87cf-3f7f2e353c65','和臘日','梅堯臣','宋','宋诗','song-poetry','','[]','獵鼓逢逢奏，寒冰齾齾消。',48,'全唐诗/poet.song.14000.json','["獵鼓逢逢奏，寒冰齾齾消。", "正憐風日暖，不似雪霜朝。", "敢問祠黄石，休從擊皁雕。", "楚郊梅萼未，壠麥已多苗。"]'),
('90abd4af-9a5a-4819-aa1e-e594bf753eed','啄木二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','城頭啄枯楊，城下啄枯桑。',48,'全唐诗/poet.song.14000.json','["城頭啄枯楊，城下啄枯桑。", "朝啄不停咮，暮啄不充腸。", "寒風正洌洌，蠹穴蟲且殭。", "况茲園林迥，剝剝響何長。"]'),
('4aa89be0-0f93-4a28-84aa-a2858e201e8c','啄木二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','食蠹非嫌蠹，聲來古木高。',24,'全唐诗/poet.song.14000.json','["食蠹非嫌蠹，聲來古木高。", "誰將琵琶弄，寫入相思槽。"]'),
('f789ca82-e746-4f2a-83b7-65756daec14a','語鴆','梅堯臣','宋','宋诗','song-poetry','','[]','客語南方鴆，啄蛇掀巨石。',36,'全唐诗/poet.song.14000.json','["客語南方鴆，啄蛇掀巨石。", "遂令山中人，多竊禹步跡。", "誰云不可轉，鳥啄猶能擲。"]'),
('91466e5d-856d-4098-8753-a1435cc96371','和淮陽燕秀才','梅堯臣','宋','宋诗','song-poetry','','[]','我官忝博士，曾昧通經術。',240,'全唐诗/poet.song.14000.json','["我官忝博士，曾昧通經術。", "前因辟書來，亦不習文律。", "循舊臨學宮，虎革被羊質。", "倚席未能講，占牘聊置日。", "朴鈍既若茲，愧彼噉棗栗。", "今者登俊賢，充詔冠庭實。", "邦伯乃宗公，惟帝舊良弼。", "置醴餞以行，行行季冬月。", "騏驥入羈駕，千里終不蹶。", "慚予延蔭人，安得結子韈。", "心雖羨名場，才命甘汨沒。", "祿仕二十年，屢遘龍牓揭。", "在昔見麻衣，于今盡超越。", "是以對杯觴，謹嚴微敢忽。", "寧唯畏後生，自恨疎節骨。", "肴羞羅食案，包核備時物。", "里婦或窺觀，戶下紅裙出。", "歸應願生男，生男付紙筆。", "乃信讀書榮，况即服縕韠。", "長歌食苹詩，聲淡異鳴瑟。"]'),
('5dce118f-f95c-4fd5-8502-757e43ff076e','和石昌言求牡丹栽','梅堯臣','宋','宋诗','song-poetry','','[]','昔年藥欄下，已多香草名。',72,'全唐诗/poet.song.14000.json','["昔年藥欄下，已多香草名。", "更移花本去，聊助日邊榮。", "莫問西都品，存吾舊友評。", "會應包萼吐，可與魏姚並。", "带土歸金谷，封根近玉京。", "謫僊方醉詠，不倚錦官城。"]'),
('16762e0c-56dc-4970-83a9-4d8dd8cc98ba','和十二月十七日雪','梅堯臣','宋','宋诗','song-poetry','','[]','窮冬勁臘已過半，曉雪先春何處來。',64,'全唐诗/poet.song.14000.json','["窮冬勁臘已過半，曉雪先春何處來。", "豈應全資南畝麥，多應不分北枝梅。", "庭中未許野童掃，林下唯愁狂吹摧。", "莫問兔園同賦客，相如居右最爲才。"]'),
('b5127e88-9789-472a-a35c-04ab9d7dcfd8','建溪新茗','梅堯臣','宋','宋诗','song-poetry','','[]','南國溪陰暖，先春發茗芽。',48,'全唐诗/poet.song.14000.json','["南國溪陰暖，先春發茗芽。", "采從青竹籠，蒸自白雲家。", "粟粒烹甌起，龍文御餠加。", "過茲安得比，顧渚不須誇。"]'),
('2fb77f81-0c5e-469a-8804-2e657a9f4145','送詹彥迪秘校之越','梅堯臣','宋','宋诗','song-poetry','','[]','夙懷山水心，夢寐向東越。',48,'全唐诗/poet.song.14000.json','["夙懷山水心，夢寐向東越。", "聞爲會稽行，獨此羨明發。", "渡江信春潮，泊館食野蕨。", "平時異梁鴻，但泛鏡湖月。"]'),
('6c35b017-5ef3-4a87-8be5-08724a7ca69c','謝人惠茶','梅堯臣','宋','宋诗','song-poetry','','[]','山色已驚溪上雷，火前那及兩旗開。',64,'全唐诗/poet.song.14000.json','["山色已驚溪上雷，火前那及兩旗開。", "采芽幾日始能就，碾月一罌初寄來。", "以酪爲奴名價重，將雲比脚味甘迴。", "更勞誰致中𤃩水，况復顔生不解杯。"]'),
('05e100a3-2fe5-4284-a806-9b238b64347d','和立春','梅堯臣','宋','宋诗','song-poetry','','[]','茲日何所喜，所喜物向榮。',48,'全唐诗/poet.song.14000.json','["茲日何所喜，所喜物向榮。", "㡜縷作翠柳，意先新陽生。", "塗金鏤爲勝，義不首時輕。", "增年已歎老，斗酒聊自傾。"]'),
('9a6c7f6b-9fb7-4a52-9969-a661492ff54a','和謝仲弓廷評新理北園','梅堯臣','宋','宋诗','song-poetry','','[]','園吏乘冬和，荷鋤去宿莽。',84,'全唐诗/poet.song.14000.json','["園吏乘冬和，荷鋤去宿莽。", "主人因其勤，築土截荒壤。", "移枯復窊缺，剗徑就平廣。", "東北倚高城，巇險不可上。", "愛彼林木深，便爲丘壑想。", "更待春風歸，日探花卉長。", "但願多置酒，應得時一往。"]'),
('958d6d54-4e8c-4478-ab6a-e37314073fd9','和謝仲弓廷評栽竹','梅堯臣','宋','宋诗','song-poetry','','[]','移得溪邊翠，來爲庭下陰。',48,'全唐诗/poet.song.14000.json','["移得溪邊翠，來爲庭下陰。", "惜根存舊土，带筍助新林。", "暗換蕭蕭葉，知虛寸寸心。", "東風莫摇撼，培壅未應深。"]'),
('6af146df-1b87-45de-8bab-717bd4af8a87','和歲除日','梅堯臣','宋','宋诗','song-poetry','','[]','一年三萬六千刻，玉漏唯餘十二時。',64,'全唐诗/poet.song.14000.json','["一年三萬六千刻，玉漏唯餘十二時。", "去日苦多誰會惜，殘陰全少頗能知。", "已驚顔貌徐徐改，不奈烏蟾冉冉馳。", "萬國明朝賀新歲，東風依舊入春旗。"]'),
('c4f0f014-0b24-4e3c-bb03-00d6f713e7fd','明井','梅堯臣','宋','宋诗','song-poetry','','[]','顯晦有難必，孰云幽不明。',60,'全唐诗/poet.song.14000.json','["顯晦有難必，孰云幽不明。", "深井發寒泉，光若月色盈。", "陰陽信奇變，曷用究厥情。", "譬彼出炎火，投薪丹焰成。", "吾人勿驚異，但自汲缾罌。"]'),
('991b22d3-6957-47bd-8674-284f0fb8ed51','楊公懿得潁人惠糟鮊分餉并遺楊叔恬','梅堯臣','宋','宋诗','song-poetry','','[]','頭尾接清淮，淮魚日登網。',48,'全唐诗/poet.song.14000.json','["頭尾接清淮，淮魚日登網。", "吳蒓芼羹美，楚糟增味爽。", "云誰得嘉貺，曾靡獨爲享。", "乃知不忘義，分遺及吾黨。"]'),
('c7d4bca5-bd3a-4544-9b92-d86844851416','和楊秘校得糟鮊','梅堯臣','宋','宋诗','song-poetry','','[]','食魚何必食河魴，自有詩人比興長。',32,'全唐诗/poet.song.14000.json','["食魚何必食河魴，自有詩人比興長。", "淮浦霜鱗更腴美，誰憐按酒敵庖羊。"]'),
('a32bb959-3901-487d-b4f7-d12ff8d0e75d','春雪','梅堯臣','宋','宋诗','song-poetry','','[]','臘前望盈尺，姦縮不應乞。',132,'全唐诗/poet.song.14000.json','["臘前望盈尺，姦縮不應乞。", "萬物及向榮，而反事凝凓。", "與雨暗爭能，不念傷彼茁。", "雖然便消釋，終是乖氣律。", "新陽豈憚沮，暴柳未爲屈。", "隨風勢更巧，著樹媚且密。", "誰將背時棄，乃欲逞果必。", "摧花自作花，旋積旋已失。", "上天施命令，冬春不相匹。", "生物與死物，其道安可壹。", "嗚呼此飛雪，何爲在今日。"]'),
('159e9a37-2827-401b-903a-d63e88606f76','和謝公儀學士正月十七日雨後復雪','梅堯臣','宋','宋诗','song-poetry','','[]','本祈春雨成春雪，應誤小桃先次開。',64,'全唐诗/poet.song.14000.json','["本祈春雨成春雪，應誤小桃先次開。", "西漢枚生誰復召，南朝何遜自多才。", "潑除燈火上元去，挫却勾萌六出來。", "前此解衣爭貰酒，不知爲瑞與爲災。"]'),
('1efba9b7-2a7d-4cf5-b9dc-860a6f74b0e2','伐桑','梅堯臣','宋','宋诗','song-poetry','','[]','二月起蠶事，伐桑人阻饑。',48,'全唐诗/poet.song.14000.json','["二月起蠶事，伐桑人阻饑。", "已傷持斧缺，不作負薪非。", "聊給終朝食，寧虞卒歲衣。", "月光無隔礙，直照破荆扉。"]'),
('1a44ccc8-0514-4c7b-9073-6ec620971e41','夢登天壇','梅堯臣','宋','宋诗','song-poetry','','[]','夜夢登天壇，壇上兩仙人。',36,'全唐诗/poet.song.14000.json','["夜夢登天壇，壇上兩仙人。", "來時乘白鳳，去時乘白麟。", "我問不我語，颯颯山中雨。"]'),
('4812ccaa-7d20-46c7-a70c-a898b6b1f338','寒食日過荆山','梅堯臣','宋','宋诗','song-poetry','','[]','山郵雖禁火，嶺樹自生煙。',48,'全唐诗/poet.song.14000.json','["山郵雖禁火，嶺樹自生煙。", "嗚咽同歸櫓，悲哀欲問天。", "泣親非泣玉，流淚劇流泉。", "春鮆橫刀膾，何心更食鮮。"]'),
('264faef6-f625-4613-95b8-eeb35eff6d06','濄口得雙鱖魚懷永叔','梅堯臣','宋','宋诗','song-poetry','','[]','春風午橋上，始迎歐陽公。',156,'全唐诗/poet.song.14000.json','["春風午橋上，始迎歐陽公。", "我僕跪雙鱖，言得石瀨中。", "持歸奉慈媼，欣詠殊未工。", "是時四三友，推尚以爲雄。", "于茲十九載，存沒復西東。", "我今淮上去，沙嶼逢釣翁。", "因之獲二尾，其色與昔同。", "錢將青絲繩，羹芼春畦菘。", "公乎廣陵來，值我號蒼穹。", "何爲號蒼穹，失怙哀無窮。", "烹煎不暇餉，泣血語孤衷。", "生平四海內，有始鮮能終。", "唯公一榮悴，不媿古人風。"]'),
('a4212f9e-6250-43b2-9681-c6b4bbf90a8b','歲寒亭','梅堯臣','宋','宋诗','song-poetry','','[]','種花邀青春，種柏要晏歲。',48,'全唐诗/poet.song.14000.json','["種花邀青春，種柏要晏歲。", "乃知風露前，已辨雪霜勢。", "時俗愛芳菲，不妨鳴鶗䳏。", "他年都門歸，寧昧始終計。"]'),
('1ecf65ae-3726-4ddc-871f-3f88030c9a5a','澄虛閣','梅堯臣','宋','宋诗','song-poetry','','[]','箘圃隔囂紛，閑來衣練裙。',48,'全唐诗/poet.song.14000.json','["箘圃隔囂紛，閑來衣練裙。", "檻邊生靜意，水底見微雲。", "斜照迴晴景，幽芳襲薄薰。", "主人多賦詠，不減沈休文。"]'),
('8d1a36f8-8f13-492b-8001-ae5f38d850ae','舟次泗上逢黄令因以詩送','梅堯臣','宋','宋诗','song-poetry','','[]','向曉入汴尾，隔河聞人聲。',84,'全唐诗/poet.song.14000.json','["向曉入汴尾，隔河聞人聲。", "得聲不得貌，問識舊時名。", "泊舟忽來及，袖詩多賢英。", "言除丹徒宰，暫作七閩行。", "東南幾千里，日夕挂帆輕。", "渡江蒓已老，未足助杯羹。", "最知便道出，先見縣人迎。"]'),
('585d8704-5cca-4c01-8824-f72b49652b34','依韻和許發運游泗州草堂寺之什','梅堯臣','宋','宋诗','song-poetry','','[]','入寺豈緣齋，阮公方詠懷。',96,'全唐诗/poet.song.14000.json','["入寺豈緣齋，阮公方詠懷。", "心將超紫府，手欲拍洪崖。", "雲霧波初浄，塵埃鑑已揩。", "但能傾玉醑，不假列金釵。", "遠客歸空速，千檣密自挨。", "醒論時事正，醉戴野巾喎。", "風俗通吳楚，清渾見汴淮。", "遥知香剎外，獨與賞心諧。"]'),
('60d08da4-463b-42d3-b634-f3f33a565e08','依韻和許發運真州東園新成','梅堯臣','宋','宋诗','song-poetry','','[]','疏鑿近東城，蕭森萬物榮。',96,'全唐诗/poet.song.14000.json','["疏鑿近東城，蕭森萬物榮。", "美花移舊本，黄鳥發新聲。", "曲閣池傍起，長橋柳外橫。", "河渾遠波漲，雨急斷虹明。", "雲與危臺接，風當廣厦清。", "朱鬐看自躍，翠柏種初生。", "香草猶能識，山苗未得名。", "南峯及西嶺，常共酒杯平。"]'),
('d43a91bf-818c-49f5-8f23-3d93d001c547','行路難','梅堯臣','宋','宋诗','song-poetry','','[]','途路無不通，行貧足如縛。',48,'全唐诗/poet.song.14000.json','["途路無不通，行貧足如縛。", "輕裘誰家子，百金負六博。", "蜀道不爲難，太行不爲惡。", "平地乏一錢，寸步鄰溝壑。"]'),
('2c5d824e-2414-43c1-8c46-a9bbe9001b8a','題姑蘇豹隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','青山崔巍藏古基，文豹不見空斷碑。',96,'全唐诗/poet.song.14000.json','["青山崔巍藏古基，文豹不見空斷碑。", "華堂重構猶隠霧，地今易主還好奇。", "欲邀明月一去飲，常娥將悔出海遲。", "谿邊少年意氣在，來往只借白鹿騎。", "自稱山人具肴酒，酒酣請我留此辭。", "謫仙墳近何可問，當日無詠亦所疑。"]'),
('68bb1892-5829-43d0-96e0-641c7bf5080a','雨還','梅堯臣','宋','宋诗','song-poetry','','[]','雨濛濛兮欲暮，路險絕兮深泥。',56,'全唐诗/poet.song.14000.json','["雨濛濛兮欲暮，路險絕兮深泥。", "嗟予僕兮甚餒，畏予馬兮顛蹄。", "關已度兮心緩，家將至兮涉溪。", "喜膝前兮童稚，餉燈下兮女妻。"]'),
('79602fbd-d22e-449b-95d1-e9d23363361b','哭笑鳥','梅堯臣','宋','宋诗','song-poetry','','[]','日月轉入地，星辰蔽重雲。',72,'全唐诗/poet.song.14000.json','["日月轉入地，星辰蔽重雲。", "夜色晦若漆，怪禽巢未焚。", "其音哭且笑，哀樂詎能分。", "方哭且笑時，曾莫有以羣。", "哭爲何所悲，笑爲何所聞。", "了不預人事，吉凶誰復云。"]'),
('f7858902-4606-49e5-b061-344d0f1fe035','山行冒雨至村家','梅堯臣','宋','宋诗','song-poetry','','[]','雨急芹泥滑，禽鳴苦竹秋。',48,'全唐诗/poet.song.14000.json','["雨急芹泥滑，禽鳴苦竹秋。", "野香生草木，雲潤上衣裘。", "入石纔通馬，穿林忽隠牛。", "山家多淺井，下照碧峯頭。"]'),
('11db0ea8-1e2c-49bc-af64-e22844f67a8b','八月九日晨興如厠有鴉啄蛆','梅堯臣','宋','宋诗','song-poetry','','[]','飛烏先日出，誰知彼雌雄。',60,'全唐诗/poet.song.14000.json','["飛烏先日出，誰知彼雌雄。", "豈無腐鼠食，來啄穢厠蟲。", "飽腹上高樹，跋觜噪西風。", "吉凶非予聞，臭惡在爾躬。", "物靈必自絜，可以推始終。"]'),
('6ebe3230-7b66-4f09-a454-663b84ac6000','夜坐','梅堯臣','宋','宋诗','song-poetry','','[]','夜久方慮寂，空堂燈燭明。',48,'全唐诗/poet.song.14000.json','["夜久方慮寂，空堂燈燭明。", "落葉有暫響，暗蟲無停聲。", "力學不爲己，甘貧且徇名。", "聊爲詠懷篇，還想阮步兵。"]'),
('094ba1ae-dcf9-42e2-8e2d-40d6413c0ad8','八月十五夜有懷','梅堯臣','宋','宋诗','song-poetry','','[]','天爲水蒼玉，月拕潭面冰。',144,'全唐诗/poet.song.14000.json','["天爲水蒼玉，月拕潭面冰。", "萬里絕瑕玷，百文已澄凝。", "山河了然在，星斗光莫增。", "借問九州內，豈無陰雲興。", "緬懷去年秋，是夜客廣陵。", "太守歐陽公，預邀三四朋。", "乃值連連雨，共飲陳華燈。", "既醉公有詠，屬和予未能。", "强賦石屏物，固慙無所稱。", "今來宛溪上，聊以故歲徵。", "晶明正若此，霢霂且何曾。", "美景信難并，康樂語足憑。"]'),
('5e06fbe0-4810-4807-bf00-3d1c835fbe30','題吏隠堂','梅堯臣','宋','宋诗','song-poetry','','[]','新堂生虛明，未悟追隠吏。',48,'全唐诗/poet.song.14000.json','["新堂生虛明，未悟追隠吏。", "無乃隠非時，唯應喧可避。", "移花莫傷根，種竹不改翠。", "牀中置素琴，亦見陶潛意。"]'),
('cc7c79a4-56be-4a11-a46b-be7014844161','詠嚴子陵','梅堯臣','宋','宋诗','song-poetry','','[]','不顧萬乘主，不屈千戶侯。',84,'全唐诗/poet.song.14000.json','["不顧萬乘主，不屈千戶侯。", "手澄百金魚，身被一羊裘。", "借問此何耳，心遠忘九州。", "青山束寒灘，濺浪驚素鷗。", "以之爲朋親，安慕乘華輈。", "老氏輕璧馬，莊生惡犧牛。", "終爲藴石玉，夐古輝巖陬。"]'),
('355cc287-af50-4ec8-bc66-0bf96ea351af','與潯陽舍弟別','梅堯臣','宋','宋诗','song-poetry','','[]','昭亭潭上水，下與九江通。',48,'全唐诗/poet.song.14000.json','["昭亭潭上水，下與九江通。", "去客解輕舸，落潮乘順風。", "迴頭迷遠樹，沒背見飛鴻。", "寂寞還蓬巷，桓彝宅近東。"]'),
('0ab2a968-c283-428c-82fb-4081913099cf','九月十八日山中見杜鵑花復開','梅堯臣','宋','宋诗','song-poetry','','[]','山中泉壑暖，幽木寒更華。',48,'全唐诗/poet.song.14000.json','["山中泉壑暖，幽木寒更華。", "春鳥各噤口，游子未還家。", "云誰未及還，對此重興嗟。", "何必因啼血，顔色勝曙霞。"]'),
('8aaca72c-b248-4c05-b441-0aa501702943','記歲','梅堯臣','宋','宋诗','song-poetry','','[]','買臣四十八，猶苦行負薪。',48,'全唐诗/poet.song.14000.json','["買臣四十八，猶苦行負薪。", "我免以樵給，貧居年與均。", "道上不謳歌，妻亦無恚嗔。", "三者固異彼，異同雙朱輪。"]'),
('9d9f7172-9245-4f10-aaaf-d423ea1ae7ed','種胡麻','梅堯臣','宋','宋诗','song-poetry','','[]','悲哀易衰老，鬢忽見二毛。',84,'全唐诗/poet.song.14000.json','["悲哀易衰老，鬢忽見二毛。", "苟生亦何樂，慈母年且高。", "勉力向藥物，曲畦聊自薅。", "胡麻養氣血，種以督兒曹。", "傍枝延扶疎，脩筴繁橐韜。", "霜前未堅好，霜後可炮熬。", "誠非騰雲術，顧此實以勞。"]'),
('9eff9d5a-bdec-4909-a9cc-ff46c4b5e8a8','達觀禪師曇穎住隠靜蘭若或言自此獼猴散走不來穎嘗哂曰吾知是山枇杷爲多始至也未實故其去將實也必羣集後果然穎惡乎俗之好異恐傳以爲人惑欲予詠而播之','梅堯臣','宋','宋诗','song-poetry','','[]','隠靜山中寺，獼猴往往過。',48,'全唐诗/poet.song.14000.json','["隠靜山中寺，獼猴往往過。", "導師歸以去，盧橘熟還多。", "禪地寧求悕，居人切莫訛。", "未嘗嫌此物，任挂古松柯。"]'),
('3cca521b-ec2e-472b-b881-7a5a61223fe8','穎公遺碧霄峯茗','梅堯臣','宋','宋诗','song-poetry','','[]','到山春已晚，何更有新茶。',48,'全唐诗/poet.song.14000.json','["到山春已晚，何更有新茶。", "峯頂應多雨，天寒始發芽。", "採時林狖靜，蒸處石泉嘉。", "持作衣囊秘，分來五柳家。"]'),
('3aad4d41-9ff3-4ade-ba6e-653b87bdf190','送達觀禪師歸隠靜寺古律二首  其一','梅堯臣','宋','宋诗','song-poetry','','[]','初逢洛陽陌，再見南徐州。',72,'全唐诗/poet.song.14000.json','["初逢洛陽陌，再見南徐州。", "所歷幾何時，倏去二十秋。", "今復振霜屨，還山遠莫留。", "我詠阮公詩，物靡必沈浮。", "誰云西海魚，夜飛東海頭。", "世人嗟識昧，豈是滯林丘。"]'),
('725ae02f-f11e-46f4-b77d-95867e7e42eb','送達觀禪師歸隠靜寺古律二首  其二','梅堯臣','宋','宋诗','song-poetry','','[]','栗林霜下熟，歸摘禦窮冬。',48,'全唐诗/poet.song.14000.json','["栗林霜下熟，歸摘禦窮冬。", "带月涉溪水，過山聞寺鐘。", "未嫌雲衲溼，已喜野人逢。", "且莫似杯渡，滄波無去蹤。"]'),
('26d408f6-fcad-4c4d-befc-a50d379f6a90','冬至感懷','梅堯臣','宋','宋诗','song-poetry','','[]','銜泣想慈顔，感物哀不平。',48,'全唐诗/poet.song.14000.json','["銜泣想慈顔，感物哀不平。", "自古九泉死，靡隨新陽生。", "稟命異草木，彼將羨勾萌。", "人實嗣其世，一衰復一榮。"]'),
('77f4fa48-e7c9-41f9-a93f-961c26a1666c','冬至日得師厚宋次道中道書','梅堯臣','宋','宋诗','song-poetry','','[]','水國欲爲雪，野冰將合河。',48,'全唐诗/poet.song.14000.json','["水國欲爲雪，野冰將合河。", "人同一陽至，淚向八行多。", "朋意今猶在，年華悵似過。", "看看四十九，應笑此蹉跎。"]');
